-- Poems batch 151
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('493ca7b3-8252-4b87-b492-c19d827c1fb2','漢老弟寄和花發多風雨人生足別離韻十絕因和之  其三','虞儔','宋','宋诗','song-poetry','','[]','春盡園林鶑懶喚，日長官舍雀堪羅。',32,'全唐诗/poet.song.154000.json','["春盡園林鶑懶喚，日長官舍雀堪羅。", "二毛老去渾無用，一掬愁來不奈多。"]'),
('d1d74172-027d-4fd5-8742-82f257cb7d83','漢老弟寄和花發多風雨人生足別離韻十絕因和之  其四','虞儔','宋','宋诗','song-poetry','','[]','幾多白白與紅紅，爭似淮山小桂叢。',32,'全唐诗/poet.song.154000.json','["幾多白白與紅紅，爭似淮山小桂叢。", "簿領沈迷春又過，枉教二十四番風。"]'),
('ac3b5022-335f-4843-ba31-119ba9414d42','漢老弟寄和花發多風雨人生足別離韻十絕因和之  其五','虞儔','宋','宋诗','song-poetry','','[]','有酒不澆墳上土，浮花浪蕊何須數。',32,'全唐诗/poet.song.154000.json','["有酒不澆墳上土，浮花浪蕊何須數。", "營巢燕子恰迎風，逐婦鵓鴣還喚雨。"]'),
('7efc8ca0-8654-4e02-bf92-ce75ac626ead','漢老弟寄和花發多風雨人生足別離韻十絕因和之  其六','虞儔','宋','宋诗','song-poetry','','[]','割雞自歎非初意，有底徘徊絆此身。',32,'全唐诗/poet.song.154000.json','["割雞自歎非初意，有底徘徊絆此身。", "官事未知何日了，溪邊誰識望雲人。"]'),
('5d417660-58e5-400a-ad0d-3b8cb1281d38','漢老弟寄和花發多風雨人生足別離韻十絕因和之  其七','虞儔','宋','宋诗','song-poetry','','[]','三春已過二春了，十日那無一日晴。',32,'全唐诗/poet.song.154000.json','["三春已過二春了，十日那無一日晴。", "已是飄零成老醜，更憐行樂負平生。"]'),
('21592f64-6ec7-4092-b6a9-580e449fd6be','漢老弟寄和花發多風雨人生足別離韻十絕因和之  其八','虞儔','宋','宋诗','song-poetry','','[]','照坐彫盤花一簇，滿甕葡萄酒新綠。',32,'全唐诗/poet.song.154000.json','["照坐彫盤花一簇，滿甕葡萄酒新綠。", "那知身後更浮名，若論眼前不翅足。"]'),
('3d5a1407-873e-4af2-955d-075e8dd964bc','漢老弟寄和花發多風雨人生足別離韻十絕因和之  其九','虞儔','宋','宋诗','song-poetry','','[]','莫將楊柳輕攀折，人生會少多離別。',32,'全唐诗/poet.song.154000.json','["莫將楊柳輕攀折，人生會少多離別。", "芍藥留殘十日春，杜鵑啼破千山月。"]'),
('3b01b2d4-ee4f-4ef7-82ba-19093243f707','漢老弟寄和花發多風雨人生足別離韻十絕因和之  其一○','虞儔','宋','宋诗','song-poetry','','[]','十首新詩逼黄絹，數行妙墨寫烏絲。',32,'全唐诗/poet.song.154000.json','["十首新詩逼黄絹，數行妙墨寫烏絲。", "摩挲老眼還驚顧，文采珊瑚鬭陸離。"]'),
('63cbf283-3621-44aa-a2c5-2fd184e4dc0c','和人二絕  其一','虞儔','宋','宋诗','song-poetry','','[]','眼底羣山入望來，攙天蒼弁獨崔嵬。',32,'全唐诗/poet.song.154000.json','["眼底羣山入望來，攙天蒼弁獨崔嵬。", "年來懷抱誰關鎖，祇傍登臨醉裏開。"]'),
('b777f3c4-baa9-420a-aa28-a530f1f992e9','和人二絕  其二','虞儔','宋','宋诗','song-poetry','','[]','廣文官冷復誰堪，心事無人可共談。',32,'全唐诗/poet.song.154000.json','["廣文官冷復誰堪，心事無人可共談。", "好雨忽來詩興動，苦無才調却懷慚。"]'),
('ec1446d1-c9ef-4f34-a3c1-980b3e67c8f4','蚊蟲  其一','虞儔','宋','宋诗','song-poetry','','[]','嗟予意廣與才疎，天下何當貯一幮。',32,'全唐诗/poet.song.154000.json','["嗟予意廣與才疎，天下何當貯一幮。", "盡把饑蚊羈海外，却驅一世入華胥。"]'),
('c5c318c0-d882-4053-9bc0-de59a9ab1d80','蚊蟲  其二','虞儔','宋','宋诗','song-poetry','','[]','賦形微細在汙渠，終日營營爲腹虛。',32,'全唐诗/poet.song.154000.json','["賦形微細在汙渠，終日營營爲腹虛。", "貪吏貪民膏血盡，不知何計與驅除。"]'),
('3c2d96f0-2a23-4a0f-8cc0-345aa80482ad','過南京','虞儔','宋','宋诗','song-poetry','','[]','三蘇當日振英華，下榻相看意已佳。',32,'全唐诗/poet.song.154000.json','["三蘇當日振英華，下榻相看意已佳。", "太息樂全無復見，舊廬聞屬女真家。"]'),
('aea65f1a-e170-4ca1-80f8-ac9d3e566fb2','迴至南京聞杜鵑','虞儔','宋','宋诗','song-poetry','','[]','夏木陰陰四月天，傷心滿目舊山川。',32,'全唐诗/poet.song.154000.json','["夏木陰陰四月天，傷心滿目舊山川。", "還轅已落春歸後，始到南京聞杜鵑。"]'),
('8df2deab-a034-4314-b09e-3b57fe7746f1','將至泗州聞杜鵑聲甚急','虞儔','宋','宋诗','song-poetry','','[]','長淮準擬濯塵埃，漢節何妨一往回。',32,'全唐诗/poet.song.154000.json','["長淮準擬濯塵埃，漢節何妨一往回。", "杜宇不知歸路近，樹頭聲急更相催。"]'),
('9cd6cd77-df18-4b5d-ad28-c5426e461257','謝楊仲才惠芍藥  其一','虞儔','宋','宋诗','song-poetry','','[]','何人金印漫垂腰，赤脚憐濃不解嬌。',32,'全唐诗/poet.song.154000.json','["何人金印漫垂腰，赤脚憐濃不解嬌。", "老去不因花妄想，沾泥柳絮似參寥。"]'),
('579b501f-4136-4c36-afee-c715a0176533','謝楊仲才惠芍藥  其二','虞儔','宋','宋诗','song-poetry','','[]','白玉盤盂自一家，春工雕琢蚤萌芽。',32,'全唐诗/poet.song.154000.json','["白玉盤盂自一家，春工雕琢蚤萌芽。", "品題况有坡翁句，除却姚黄說此花。"]'),
('96d9414a-04c5-4661-b888-a340f45eb6c4','謝楊仲才惠芍藥  其三','虞儔','宋','宋诗','song-poetry','','[]','回首龍山憶孟嘉，詩成醉墨带烟霞。',32,'全唐诗/poet.song.154000.json','["回首龍山憶孟嘉，詩成醉墨带烟霞。", "風流多謝佳公子，遣贈揚州幾度花。"]'),
('c532a103-3d85-4116-a030-87549a3f2a33','南坡種芍藥  其一','虞儔','宋','宋诗','song-poetry','','[]','錯盤根墢似苞桑，細細分來巧作行。',32,'全唐诗/poet.song.154000.json','["錯盤根墢似苞桑，細細分來巧作行。", "且趁秋灰浮季琯，更教冬線受微陽。"]'),
('18ef26fa-8c19-41d2-a0fb-7860ab8585e0','南坡種芍藥  其二','虞儔','宋','宋诗','song-poetry','','[]','卵石周圍也自佳，茅亭穩著不須奢。',32,'全唐诗/poet.song.154000.json','["卵石周圍也自佳，茅亭穩著不須奢。", "何心更作揚州夢，十里春風萬本花。"]'),
('44b7d1fe-0ab2-4831-ac17-7c7be0b0c68e','南坡種芍藥  其三','虞儔','宋','宋诗','song-poetry','','[]','南坡地脈生來瘦，根墢移栽却要肥。',32,'全唐诗/poet.song.154000.json','["南坡地脈生來瘦，根墢移栽却要肥。", "說與園翁須早計，莫教春事與心違。"]'),
('ba69dd60-cc37-4c32-95af-0a1d40cee57e','圖南學長有詠梅十五詩各指名其處所且書以見寄因賦二絕句謝之  其一','虞儔','宋','宋诗','song-poetry','','[]','詠梅誰復擅詩名，梅與詩人自有情。',32,'全唐诗/poet.song.154000.json','["詠梅誰復擅詩名，梅與詩人自有情。", "說盡梅花隨處好，喜君詩句似梅清。"]'),
('abb88b3d-7a4b-4e41-abde-f7f370d4b6de','圖南學長有詠梅十五詩各指名其處所且書以見寄因賦二絕句謝之  其二','虞儔','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅格孤高不待誇，暗香浮動影橫斜。',32,'全唐诗/poet.song.154000.json','["梅格孤高不待誇，暗香浮動影橫斜。", "箇中風味誰相稱，只有西湖處士家。"]'),
('6b167748-36ea-45b6-919b-dffb89a81bf5','和廣文俞同年賀太守  其一','虞儔','宋','宋诗','song-poetry','','[]','休詠詩人大小東，豐年雨意十分濃。',32,'全唐诗/poet.song.154000.json','["休詠詩人大小東，豐年雨意十分濃。", "使君自是爲霖手，不遣昌黎苦訟風。"]'),
('141a5b16-4dc2-47bd-a25a-4c08d1aae317','和廣文俞同年賀太守  其二','虞儔','宋','宋诗','song-poetry','','[]','三登從此數淳熙，一雨炎官遂霽威。',32,'全唐诗/poet.song.154000.json','["三登從此數淳熙，一雨炎官遂霽威。", "綠潤田疇今已遍，凉生殿閣故應微。"]'),
('0b231bd6-3eb9-461f-9b49-a509b0d03ee4','和廣文俞同年賀太守  其三','虞儔','宋','宋诗','song-poetry','','[]','人言歲稔催科易，我念民貧積欠多。',32,'全唐诗/poet.song.154000.json','["人言歲稔催科易，我念民貧積欠多。", "政拙不歸嗟已老，空餘一飯愧廉頗。"]'),
('0c553c02-03f5-4f46-8a7c-e5bbe2d50605','和廣文俞同年賀太守  其四','虞儔','宋','宋诗','song-poetry','','[]','絳帳才華溢彩牋，誰嘲晝寢腹便便。',32,'全唐诗/poet.song.154000.json','["絳帳才華溢彩牋，誰嘲晝寢腹便便。", "側聞已上中和頌，試請重歌相府蓮。"]'),
('58e23e6b-0e58-45b3-8758-61a80c8cbc52','余帥淮西下車纔十日移東漕二絕  其一','虞儔','宋','宋诗','song-poetry','','[]','安得絲毫補吏民，下車纔度十朝曛。',32,'全唐诗/poet.song.154000.json','["安得絲毫補吏民，下車纔度十朝曛。", "却慚父老相留戀，巵酒爭持壽使君。"]'),
('ff1a9881-c699-43e2-857e-82c3ac1b4f12','余帥淮西下車纔十日移東漕二絕  其二','虞儔','宋','宋诗','song-poetry','','[]','多少邦人意慘悽，出郊雲淡楚天低。',32,'全唐诗/poet.song.154000.json','["多少邦人意慘悽，出郊雲淡楚天低。", "馬頭漸指淮東去，回望孤城落照西。"]'),
('bcded238-586c-4582-bc6d-3c0197d04b63','和萬舍人分惠鱟魚  其一','虞儔','宋','宋诗','song-poetry','','[]','昌黎集裏知名久，山海經中取喻何。',32,'全唐诗/poet.song.154000.json','["昌黎集裏知名久，山海經中取喻何。", "柱後惠文渠勿恃，只今散地亦投戈。"]'),
('d6910c0d-78df-4670-8aa1-ae168c3cfa1b','和萬舍人分惠鱟魚  其二','虞儔','宋','宋诗','song-poetry','','[]','怪形未免遭支解，香甲還應即鼎烹。',32,'全唐诗/poet.song.154000.json','["怪形未免遭支解，香甲還應即鼎烹。", "便與庚桑登俎豆，何如郭索自泥行。"]'),
('add54def-5461-459a-a154-6e8d79f717d4','舒州清明二首  其一','虞儔','宋','宋诗','song-poetry','','[]','架竹編茅數百家，柴門隨分映桃花。',32,'全唐诗/poet.song.154000.json','["架竹編茅數百家，柴門隨分映桃花。", "春風不辦舒州杓，習慣淮鄉木杵茶。"]'),
('f2941bff-7267-488e-a09a-888459f4e6c1','舒州清明二首  其二','虞儔','宋','宋诗','song-poetry','','[]','試著輕衫問曉晴，野棠花下有清明。',32,'全唐诗/poet.song.154000.json','["試著輕衫問曉晴，野棠花下有清明。", "不如獨上江樓去，坐聽春潮送艣聲。"]'),
('e3fe1971-ecb8-4c52-83af-721e0e658220','以雙梅二枝送郁簿小詩見意','虞儔','宋','宋诗','song-poetry','','[]','連枝並蒂更同根，結實雙雙向小園。',32,'全唐诗/poet.song.154000.json','["連枝並蒂更同根，結實雙雙向小園。", "調鼎異時知有伴，相期携手上天門。"]'),
('7faef49f-2493-481c-8ebf-36ac0dc81bde','六月二十一日戊寅率同寮詣登源祖廟中迎英濟禱雨是日也雨隨車至越翼日己卯繼之至中宵方霽自辛巳至于乙酉遂沛然霑足丙戌敬送神因書二小詩以紀靈異  其一','虞儔','宋','宋诗','song-poetry','','[]','蓱號起雨風頭好，禾稼如雲水面肥。',32,'全唐诗/poet.song.154000.json','["蓱號起雨風頭好，禾稼如雲水面肥。", "從此豐年無一事，前歌後舞送神歸。"]'),
('78f1845e-e9ce-4e33-9fa9-fa06069ee459','六月二十一日戊寅率同寮詣登源祖廟中迎英濟禱雨是日也雨隨車至越翼日己卯繼之至中宵方霽自辛巳至于乙酉遂沛然霑足丙戌敬送神因書二小詩以紀靈異  其二','虞儔','宋','宋诗','song-poetry','','[]','催科太拙愧無功，撫字徒勞技已窮。',32,'全唐诗/poet.song.154000.json','["催科太拙愧無功，撫字徒勞技已窮。", "正直却應神誤聽，祇憑香火報年豐。"]'),
('626778d2-a8aa-4323-8c20-518b427dba59','端午日被旨禱雨天目山次日至臨安縣道中  其一','虞儔','宋','宋诗','song-poetry','','[]','伊軋籃輿度翠微，蕭疎甲隊小紅旂。',32,'全唐诗/poet.song.154000.json','["伊軋籃輿度翠微，蕭疎甲隊小紅旂。", "杜鵑强欲知人事，苦苦聲聲勸我歸。"]'),
('61da0718-5d23-4416-ae9e-a0fe8775ed00','端午日被旨禱雨天目山次日至臨安縣道中  其二','虞儔','宋','宋诗','song-poetry','','[]','綠林深處囀黄鸝，光景渾如初夏時。',32,'全唐诗/poet.song.154000.json','["綠林深處囀黄鸝，光景渾如初夏時。", "尚覺風頭能瑟瑟，却憂雨脚反遲遲。"]'),
('eda9cea6-8517-4357-bd0d-3fa6c6bb39f8','偕簿尉過石照山禱雨  其一','虞儔','宋','宋诗','song-poetry','','[]','紫金岩電間閃爍，寶網香雲時吐吞。',32,'全唐诗/poet.song.154000.json','["紫金岩電間閃爍，寶網香雲時吐吞。", "况有降魔大圓鏡，豈因旱魃更遊魂。"]'),
('f23c33e2-a403-45a0-9423-5f6b05be157e','偕簿尉過石照山禱雨  其二','虞儔','宋','宋诗','song-poetry','','[]','怪生斗水蓄風雷，喚取龍神睡覺來。',32,'全唐诗/poet.song.154000.json','["怪生斗水蓄風雷，喚取龍神睡覺來。", "火急共爲詩準備，却愁頭上雨相催。"]'),
('ad6e9961-3b9f-4746-8b5e-f197662725c2','偕簿尉過石照山禱雨  其三','虞儔','宋','宋诗','song-poetry','','[]','野火燒渠經幾秋，却將光彩閟深幽。',32,'全唐诗/poet.song.154000.json','["野火燒渠經幾秋，却將光彩閟深幽。", "塵中縱有人磨鏡，俗狀年來我亦羞。"]'),
('4c897859-77a1-44af-8163-e5d446529126','偕簿尉過石照山禱雨  其四','虞儔','宋','宋诗','song-poetry','','[]','向來赤地增愁歎，更遣蜚蝗恣噬吞。',32,'全唐诗/poet.song.154000.json','["向來赤地增愁歎，更遣蜚蝗恣噬吞。", "稽首願天憐一雨，只今未定有驚魂。"]'),
('60d090de-81f5-46b4-8ec3-274ad8d048b6','偕簿尉過石照山禱雨  其五','虞儔','宋','宋诗','song-poetry','','[]','一聲破柱走驚雷，割得乖龍左耳來。',32,'全唐诗/poet.song.154000.json','["一聲破柱走驚雷，割得乖龍左耳來。", "海水蕩雲疑欲立，電光摇幟更煩催。"]'),
