('f6aa5b8a-d42f-4a86-807d-fc7fca253d32','句  其二','黄仲本','宋','宋诗','song-poetry','','[]','好把丹衷爲上傾。',8,'全唐诗/poet.song.154000.json','["好把丹衷爲上傾。"]'),
('2f37e562-cf06-4b37-9ebe-9e67c6799bbf','賀雨','傅大詢','宋','宋诗','song-poetry','','[]','獅子關前半篆烟，二龍飛下卓篙泉。',64,'全唐诗/poet.song.154000.json','["獅子關前半篆烟，二龍飛下卓篙泉。", "銀河掣電連宵雨，綠野翻雲四月天。", "便覺春生花一縣，會看秋熟米三錢。", "何時卓魯登黄閣，都與寰區作有年。"]'),
('107aebf9-3aff-48ee-9689-5a0403e17837','賀生子索盃','傅大詢','宋','宋诗','song-poetry','','[]','喚婦推窗索錦牋，山翁要賦弄璋篇。',64,'全唐诗/poet.song.154000.json','["喚婦推窗索錦牋，山翁要賦弄璋篇。", "一年江上春將暮，三日人間月又圓。", "母舅故家應有持，郎官餘慶豈無傳。", "不妨小小爲湯餠，紫竹林邊風月天。"]'),
('202865c9-204b-4f99-a7e9-2e8f19f6535e','賀生次子','傅大詢','宋','宋诗','song-poetry','','[]','老子瞿曇魯仲尼，新來抱送一麟兒。',64,'全唐诗/poet.song.154000.json','["老子瞿曇魯仲尼，新來抱送一麟兒。", "已吞賈氏三英時，不數徐卿二子奇。", "昨夜光連奎昴宿，他年身在鳳凰池。", "相門有相非虛語，細聽啼聲自可知。"]'),
('31fc4b06-9cf5-49cb-8fd8-e288ac3bff00','賀生第五子','傅大詢','宋','宋诗','song-poetry','','[]','春風有客到門牆，院落猶聞天上香。',64,'全唐诗/poet.song.154000.json','["春風有客到門牆，院落猶聞天上香。", "曲水尚遲三日宴，燕山要足五枝芳。", "偶逢賀夏隨飛燕，不誤題書作弄璋。", "從此葛山壇下路，要成父子錦衣鄉。"]'),
('cb457ddc-90aa-430c-8797-2fc497818e3d','賀晚生子','傅大詢','宋','宋诗','song-poetry','','[]','□□森森天下奇，靈椿猶自長新枝。',64,'全唐诗/poet.song.154000.json','["□□森森天下奇，靈椿猶自長新枝。", "從來老蚌珠生時，豈是長庚夢到遲。", "標格銀蟾光皎潔，精神秋水碧漣漪。", "玉皇案吏家聲近，佇看追蹤入鳳池。"]'),
('e88ea099-1d42-4a3e-b7da-6b7106f5a5b4','挽嫂','傅大詢','宋','宋诗','song-poetry','','[]','閨門六十四年春，回首平生可痛情。',64,'全唐诗/poet.song.154000.json','["閨門六十四年春，回首平生可痛情。", "不肯轑羹驚好客，直能炊扊奉難兄。", "莫思秀水初來塈，豈料蕭州竟逝傾。", "一望松楸三百里，年年遥爲哭清明。"]'),
('789c1ba7-d1ab-4e8b-be86-2f9d9eee1629','哭夫','傅大詢','宋','宋诗','song-poetry','','[]','三十功名四十亡，有才無壽兩堪傷。',64,'全唐诗/poet.song.154000.json','["三十功名四十亡，有才無壽兩堪傷。", "夫妻鏡裏鸞分影，兄弟群中鴈失行。", "數尺紅羅書姓字，一堆黄壤蓋文章。", "我來不敢高聲哭，只恐猿聞也斷腸。"]'),
('a621667b-bd69-4532-be76-4043de07a104','贈山人黎君寶','傅大詢','宋','宋诗','song-poetry','','[]','白雲深處鬰孤臺，一卷青囊一酒杯。',64,'全唐诗/poet.song.154000.json','["白雲深處鬰孤臺，一卷青囊一酒杯。", "天在掌中旋日月，龍從足下起風雷。", "自知有分三公貴，未必何時萬乘來。", "經過鈴岡肯相訪，柴門認取竹新栽。"]'),
('fd1964ec-fdcb-42b0-b2a5-b832f617c9f4','飲月','傅大詢','宋','宋诗','song-poetry','','[]','酒滿金樽月滿輪，月沈輪影在金樽。',32,'全唐诗/poet.song.154000.json','["酒滿金樽月滿輪，月沈輪影在金樽。", "更深坐久詩喉渴，一舉金樽和月吞。"]'),
('30adc3d4-bf8c-405f-88fd-06f542e5154e','新霜','傅大詢','宋','宋诗','song-poetry','','[]','瓊宮青女妝初試，錦幄佳人睡未知。',32,'全唐诗/poet.song.154000.json','["瓊宮青女妝初試，錦幄佳人睡未知。", "但見玉童呵手道，破寒唯有酒相宜。"]'),
('2a80f862-3cf4-4c9b-ac76-9b117a2fe24f','題寒巖寺','丁可','宋','宋诗','song-poetry','','[]','大塊中間一竅開，佛龕僧榻遍巖隈。',64,'全唐诗/poet.song.154000.json','["大塊中間一竅開，佛龕僧榻遍巖隈。", "羣峰爭汎玄雲出，絕磴祇容幽鳥來。", "蝠穴巧藏人世界，鼇山驚現蜃樓臺。", "重來又與山僧別，鐘鼓無情鶴自哀。"]'),
('831a5837-9898-48ab-8605-3c4133758fd0','夜對巾山題客樓','丁可','宋','宋诗','song-poetry','','[]','兩峰高並玉瓏鬆，絕頂浮圖插暮空。',32,'全唐诗/poet.song.154000.json','["兩峰高並玉瓏鬆，絕頂浮圖插暮空。", "飛雨入簾烟樹暝，半天燈火幻疏紅。"]'),
('b746d7b4-ee65-47c6-adc0-c98514fe73bb','飛步亭','霍箎','宋','宋诗','song-poetry','','[]','杏花巖左斸東巖，驅使淮山指顧間。',64,'全唐诗/poet.song.154000.json','["杏花巖左斸東巖，驅使淮山指顧間。", "招信□□總□赴，僧伽孤塔正灣環。", "今來古往皆陳迹，衰草斜陽祇慘顔。", "走馬看山真懡□，□□拾得片時閒。"]'),
('4c38d223-0e13-48dc-a403-2babbdd02c3d','挽呂東萊二首  其一','邵浩','宋','宋诗','song-poetry','','[]','三相流風遠，諸孫氣貌舒。',48,'全唐诗/poet.song.154000.json','["三相流風遠，諸孫氣貌舒。", "有文皆錦繡，不琢自璠璵。", "樂育心無類，何言意已攄。", "摳衣多戶履，四海讀公書。"]'),
('e06c2f72-dcf4-4b67-a4e2-1ed3ece70d74','挽呂東萊二首  其二','邵浩','宋','宋诗','song-poetry','','[]','道統傳千載，儒風振一時。',48,'全唐诗/poet.song.154000.json','["道統傳千載，儒風振一時。", "心誠師孔孟，業廣慕皋夔。", "感鳳方興歎，書麟尚措辭。", "一朝梁木壞，吾黨可勝悲。"]'),
('b128b708-6a37-49ad-a850-cdde5d72afdf','耕樂軒','任允迪','宋','宋诗','song-poetry','','[]','安分丘園百不憂，生涯滿目足優游。',64,'全唐诗/poet.song.154000.json','["安分丘園百不憂，生涯滿目足優游。", "春深甘雨桑麻長，秋霽西疇黍稻收。", "教子倚闌看邃說，飲牛挂策俯池流。", "高情更喜親朋至，白酒黄雞醉即休。"]'),
('6903e424-0d9c-40e9-b2d5-59dc2f355dca','題錢塘','吳會','宋','宋诗','song-poetry','','[]','荆江南下越，渺渺幾長亭。',48,'全唐诗/poet.song.154000.json','["荆江南下越，渺渺幾長亭。", "一水三千里，孤帆十二程。", "潮來江渚白，山在海門青。", "昔日錢吳地，如今作帝京。"]'),
('9a3d511d-e804-4726-aec5-83ca92a20121','訪別嚴儀卿寄郭招甫','吳會','宋','宋诗','song-poetry','','[]','言將遠行邁，來宿故人家。',48,'全唐诗/poet.song.154000.json','["言將遠行邁，來宿故人家。", "愛爾時相顧，回舟日欲斜。", "論心付杯酒，別路正梅花。", "不待江湖去，今朝鬢已華。"]'),
('f701c7d2-6506-448d-af31-698c597931c0','句','胡持','宋','宋诗','song-poetry','','[]','藏雲八世五登科。',8,'全唐诗/poet.song.154000.json','["藏雲八世五登科。"]'),
('f8205f75-57d3-48f8-b126-6413d7c18d84','自題眄怡齋  其一','程迥','宋','宋诗','song-poetry','','[]','乞得膠膠擾擾身，霜筠露菊便相親。',32,'全唐诗/poet.song.154000.json','["乞得膠膠擾擾身，霜筠露菊便相親。", "勸君莫厭羹藜藿，違己由來更病人。"]'),
('e26f5032-0124-4be9-9d90-3eff6e86f581','自題眄怡齋  其二','程迥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','六月松風萬籟寒，笙竽頻到枕屏間。',32,'全唐诗/poet.song.154000.json','["六月松風萬籟寒，笙竽頻到枕屏間。", "夜深夢繞匡廬阜，瀑布濺珠過藥闌。"]'),
('b9d1b014-a436-408b-afe4-4e4e67f0e4af','自題眄怡齋  其三','程迥','宋','宋诗','song-poetry','','[]','葵花已過菊花開，萬里西風拂面來。',32,'全唐诗/poet.song.154000.json','["葵花已過菊花開，萬里西風拂面來。", "問字今朝幾人至，細看屐齒破蒼苔。"]'),
('858b5d74-9491-4cb5-8813-5706a2d9b02d','尤美軒','程迥','宋','宋诗','song-poetry','','[]','儒賢不自居，遠慕六一翁。',168,'全唐诗/poet.song.154000.json','["儒賢不自居，遠慕六一翁。", "洞巖天下奇，超出滁山峰。", "鬰積秀和氣，鍾我蓋世公。", "冰玉相輝映，盛事古無同。", "公今忽乘箕，而我來自東。", "列炬照幽遠，捫蘿扣玲瓏。", "陽崖能奪景，陰岫自藏風。", "巉絕異狀至，淙激洑流通。", "須臾鍾磬發，乃得梵王宮。", "亭製亦云舊，遠日增憑空。", "禪老霜顛毛，歷歷記前蹤。", "名儒天一涯，悵仰無歡悰。", "諸友命之賦，萬象驕莫從。", "異時憐湛輩，名託峴山崇。"]'),
('3d944931-b788-4159-9b67-0ddd4ee8139f','題玉真書院','程迥','宋','宋诗','song-poetry','','[]','吳侯所築居，密近玉真麓。',120,'全唐诗/poet.song.154000.json','["吳侯所築居，密近玉真麓。", "翳葳祕幽奇，千載空喬木。", "一朝敞虛境，劃見神仙躅。", "拄杖步危磴，遠寄千里目。", "鶴憑子晉笙，鳬舉王喬足。", "信是隠君子，名入丹青錄。", "冥搜得佳句，隠然可騷僕。", "早聞雲錦溪，鳴榔到巖谷。", "寄我輞川圖，居然媚幽獨。", "何當櫂輕舠，飛鳥送遐矚。"]'),
('88964eea-a9f0-45cf-a434-22ceacc8ac4c','游石橋二絕  其一','宋之瑞','宋','宋诗','song-poetry','','[]','石梁橫亙不知春，閲盡憧憧幾許人。',32,'全唐诗/poet.song.154000.json','["石梁橫亙不知春，閲盡憧憧幾許人。", "正使更無蒸餠礙，可能前路絕荆榛。"]'),
('e9525512-f44a-48dc-8fa5-3b9a6c74af28','游石橋二絕  其二','宋之瑞','宋','宋诗','song-poetry','','[]','應緣心在已心空，方廣那知只此中。',32,'全唐诗/poet.song.154000.json','["應緣心在已心空，方廣那知只此中。", "金爵茗花時現滅，不妨遊戲小神通。"]'),
('8884cad4-c9ce-4a5f-8086-6d6a4756fdf1','洪陽洞','宋之瑞','宋','宋诗','song-poetry','','[]','天台自是神仙窟，常恨平生游未足。',224,'全唐诗/poet.song.154000.json','["天台自是神仙窟，常恨平生游未足。", "朅來訪古得洪陽，不憚攀躋冒炎酷。", "當年事往雖渺茫，至今峭壁摩空蒼。", "豁從洞口見穿穴，始信靈蹟由天藏。", "細泉滴乳散瓔珞，亂石排衙互拏攫。", "上施牀几看燒丹，旁布塍畦閒種藥。", "虛舟聊具仍馭風，靈源暗與江流通。", "欲携束縕恣幽討，却疑深處藏蛟龍。", "惜哉此境真奇絕，地偏往往成湮沒。", "僅存野廟傍山阿，儻非好事誰留轍。", "吾衰重到定無期，肯辭繭足陵丹梯。", "共言荆榛無路入，徒羨翠羽穿林飛。", "安知咫尺蓬萊隔，邂逅仙人還不識。", "謾書所歷記吾曹，歸向天台詫泉石。"]'),
('771191c9-20f8-460b-aea6-a9b956cc374e','寶雲院','游少游','宋','宋诗','song-poetry','','[]','石徑緣雲艱復艱，不知蕭寺駐林間。',64,'全唐诗/poet.song.154000.json','["石徑緣雲艱復艱，不知蕭寺駐林間。", "餘香滿袖花驚眼，空翠沾襟雨暝山。", "早晚報衙蜂擾擾，友朋相和鳥關關。", "我來亦被浮名縛，那得高僧一樣閒。"]'),
('56df0a2f-3d2c-4168-8e41-78772c822d22','禪寂院三首  其一','游少游','宋','宋诗','song-poetry','','[]','簿書叢裏匆匆過，小白長紅總自芳。',32,'全唐诗/poet.song.154000.json','["簿書叢裏匆匆過，小白長紅總自芳。", "獨到遠村渾不惡，綠陰深處野花香。"]'),
('d9933af9-85b9-4a7c-b351-7fc6d1e6e911','禪寂院三首  其二','游少游','宋','宋诗','song-poetry','','[]','黄雲翻盡水平田，時有農耕破曉烟。',32,'全唐诗/poet.song.154000.json','["黄雲翻盡水平田，時有農耕破曉烟。", "熱氣漸深牛易喘，不須辛苦更加鞭。"]'),
('c4d49c7f-ce8c-4bcd-bf14-ed048dc86d1a','禪寂院三首  其三','游少游','宋','宋诗','song-poetry','','[]','柳絲風颺馬蹄輕，又作長亭十里行。',32,'全唐诗/poet.song.154000.json','["柳絲風颺馬蹄輕，又作長亭十里行。", "爭似老僧無一事，白雲欹枕聽鶑聲。"]'),
('b0ce8d88-972e-415a-8d10-0d3e37440331','田南寺','游少游','宋','宋诗','song-poetry','','[]','我本無心似白雲，應緣未見宰官身。',32,'全唐诗/poet.song.154000.json','["我本無心似白雲，應緣未見宰官身。", "何時鐵笛千山首，吹起梅花一點春。"]'),
('ec51fb6f-e396-42f4-8657-8494ead2b80c','香山院','游少游','宋','宋诗','song-poetry','','[]','誰將萬斛旃檀子，撒向千春古道場。',32,'全唐诗/poet.song.154000.json','["誰將萬斛旃檀子，撒向千春古道場。", "萬壑曉風吹不斷，至今猶自滿山香。"]'),
('b51ffa4f-b276-4aec-9436-bef5b2ba274b','題石仙洞','游少游','宋','宋诗','song-poetry','','[]','石巖嶔巇跨龍虎，有客巖前避風雨。',96,'全唐诗/poet.song.154000.json','["石巖嶔巇跨龍虎，有客巖前避風雨。", "篆文委蛇蟠玉書，流鈴擲火煩守護。", "冷翁蛻骨黄金容，千年古木何嵌空。", "無人喚起玉霄夢，閒却碧桃丹杏風。", "令威白鶴去不歸，麻姑丹砂疑是非。", "長松滴翠挹北斗，流水泛花迷舊溪。"]'),
('713039dc-5802-4931-b3ea-2308a2c4a4de','飛魚港','李唐卿','宋','宋诗','song-poetry','','[]','嘗聞一鯉魚，飛騰作清質。',24,'全唐诗/poet.song.154000.json','["嘗聞一鯉魚，飛騰作清質。", "至今涵青霄，尚且浴白日。"]'),
('fb90435f-f325-4f7d-9602-cc4865f7dac8','句','李宗思','宋','宋诗','song-poetry','','[]','邪色哇聲方漫漫，是中正氣愈駸駸。',16,'全唐诗/poet.song.154000.json','["邪色哇聲方漫漫，是中正氣愈駸駸。"]'),
('bac3fa5b-f7ba-4900-aecd-7f25706b5a8f','寓居全吳江上  其一','姚申之','宋','宋诗','song-poetry','','[]','夜來得酒氣增華，興入丹梯月姊家。',32,'全唐诗/poet.song.154000.json','["夜來得酒氣增華，興入丹梯月姊家。", "兩首新詩一篇賦，今年不負木犀花。"]'),
('672f6a48-8897-4e81-b6b5-4c1793f6b58b','寓居全吳江上  其二','姚申之','宋','宋诗','song-poetry','','[]','一雨通宵翦菜畦，波稜生甲晚菘齊。',32,'全唐诗/poet.song.154000.json','["一雨通宵翦菜畦，波稜生甲晚菘齊。", "朝來赤脚語言好，醒酒杯羹有宿虀。"]'),
('a2a55736-c14c-4262-a641-949b3bcb6b99','寓居全吳江上  其三','姚申之','宋','宋诗','song-poetry','','[]','幅巾蕭散一枝筇，身在水雲千頃中。',32,'全唐诗/poet.song.154000.json','["幅巾蕭散一枝筇，身在水雲千頃中。", "抹野亂山隨意碧，裊林霜葉可憐紅。"]'),
('ed47740c-bea0-45ed-a9da-810800aacc29','寓居全吳江上  其四','姚申之','宋','宋诗','song-poetry','','[]','築成芋塹那憂餓，爨到扊扅真箇窮。',32,'全唐诗/poet.song.154000.json','["築成芋塹那憂餓，爨到扊扅真箇窮。", "飽坐西軒觀物變，一甌濃茗一林風。"]'),
('7570110e-c6a8-4e20-897f-21cd8aa7f6dd','家西小亭名水雲千頃','姚申之','宋','宋诗','song-poetry','','[]','雲影翻隨宿鳥迴，斜暉猶带晚潮來。',32,'全唐诗/poet.song.154000.json','["雲影翻隨宿鳥迴，斜暉猶带晚潮來。", "小橋低處通船過，一隊鵝兒兩道開。"]'),
('ed7c2542-78ad-4bcc-8600-b041f17afa20','將至崑山舟中作','姚申之','宋','宋诗','song-poetry','','[]','崑嶺煙斂後，虞浦風定時。',156,'全唐诗/poet.song.154000.json','["崑嶺煙斂後，虞浦風定時。", "一舸飛兩艣，百媚生漣漪。", "霜清寒中人，天宇雲陸離。", "朝曦忽漏光，野光明荒陂。", "潛魚時一躍，宿鳥意遲遲。", "却望西津橋，千尺天投霓。", "豪家貴公子，香衾擁屏幃。", "安知蒼莽中，有境如此奇。", "我以饑驅出，氣軒復開眉。", "褚侯真懿親，襆被相追隨。", "長嘯開船篷，襟袖風披披。", "平生崔嵬胸，軒昂對天池。", "有景無句道，徑須酒澆之。"]'),
('f6c3bcf7-b5da-485a-a591-69f59103233a','送歐陽令之任粵中','薛敏思','宋','宋诗','song-poetry','','[]','大隄二月柳初舒，秣馬飄然別故廬。',64,'全唐诗/poet.song.154000.json','["大隄二月柳初舒，秣馬飄然別故廬。", "自取通才分劇邑，誰憐修路奉除書。", "綠蕉丹荔千山度，瘴雨蠻煙百粵居。", "此去縣中花事好，早將佳績報雙魚。"]'),
('8fcb0020-7fa5-4458-a7bf-713b48152730','風光閣','林淳','宋','宋诗','song-poetry','','[]','萬箇琅玕照碧溪，翠蘿蒼木與雲齊。',32,'全唐诗/poet.song.154000.json','["萬箇琅玕照碧溪，翠蘿蒼木與雲齊。", "山南山北皆春色，豈特風光在水西。"]'),
('e00809bc-9fa6-493d-806a-7b4dc55d3dfd','秋霜閣吟','林淳','宋','宋诗','song-poetry','','[]','煙霞鬰林巒，天地橫機軸。',108,'全唐诗/poet.song.154000.json','["煙霞鬰林巒，天地橫機軸。", "天巧出經緯，織來雲錦簇。", "木杪見浮屠，突兀隠渠屋。", "夕照含幽微，曛紅間深綠。", "可望不可親，白鳥時往復。", "飛閣凌秋霜，危檻倚修竹。", "崖陰分白晝，颯爽變幽谷。", "隙地清絕處，他年猶可卜。", "山水固依然，爲我留蒼木。"]'),
('9d54dc25-6a29-4877-9914-4a9dcfb8c817','清心堂','林淳','宋','宋诗','song-poetry','','[]','好山佳水照晴簷，時鼓瑶琴頌雅南。',32,'全唐诗/poet.song.154000.json','["好山佳水照晴簷，時鼓瑶琴頌雅南。", "吏散庭空無箇事，一輪明月印寒潭。"]'),
('d5a2cec7-dfc3-4c68-b42d-ce17bdbb9fb2','錦照堂','林淳','宋','宋诗','song-poetry','','[]','溪西受日雲山麗，乞與溪東作錦屏。',32,'全唐诗/poet.song.154000.json','["溪西受日雲山麗，乞與溪東作錦屏。", "好把生絹寫歸去，光華清晝爛門庭。"]'),
('62168964-41c9-46ea-884e-9f61e27c2645','蒸霞亭','林淳','宋','宋诗','song-poetry','','[]','種桃人去歲華更，依舊紅霞照月明。',32,'全唐诗/poet.song.154000.json','["種桃人去歲華更，依舊紅霞照月明。", "但見濃雲環百里，誰知春色滿寰瀛。"]'),
('4addcae3-ce23-41cc-a4b0-a4a253410af5','旵山','林淳','宋','宋诗','song-poetry','','[]','昔來因檮雨，祝旱却重遊。',48,'全唐诗/poet.song.154000.json','["昔來因檮雨，祝旱却重遊。", "洞裏龍何在，山前水自流。", "黄楊厄閏歲，白菊殿殘秋。", "正好看雲起，朱簾莫下鈎。"]'),
('5a0978cf-f7f7-4993-a2d9-f92353e014bc','琴溪','林淳','宋','宋诗','song-poetry','','[]','湛湛長溪水，飛橋遠近通。',48,'全唐诗/poet.song.154000.json','["湛湛長溪水，飛橋遠近通。", "客喧墟市合，仙去釣臺空。", "欲辨磨崖字，忽聞遵渚鴻。", "僧無贊公趣，誰與論崖中。"]'),
('3e3a6b5c-a43c-4364-b0b9-92882fe1262e','梅花','趙伯泌','宋','宋诗','song-poetry','','[]','綽約冰姿傍短牆，天香應不讓花王。',64,'全唐诗/poet.song.154000.json','["綽約冰姿傍短牆，天香應不讓花王。", "雪光相映精神爽，月色深籠意味長。", "惟契竹松敦晚節，不隨桃李競春芳。", "漫將玉笛風前弄，留取宮人學漢妝。"]'),
('5ce85b5e-f88f-4a49-aef2-1e0f2a549142','淳熙辛丑自武寧丞攝靖安作  其一','楊方','宋','宋诗','song-poetry','','[]','毛竹山頭雲雨昏，靖安橋下小谿渾。',32,'全唐诗/poet.song.154000.json','["毛竹山頭雲雨昏，靖安橋下小谿渾。", "高陂約水歸田急，不管湍聲入縣門。"]'),
('9bf78a03-0c93-49ad-a89d-c3e2bd4cc4c5','淳熙辛丑自武寧丞攝靖安作  其二','楊方','宋','宋诗','song-poetry','','[]','堂上官人似野人，村甿相見可相親。',32,'全唐诗/poet.song.154000.json','["堂上官人似野人，村甿相見可相親。", "開門坐對臨溪樹，故是水邊林下身。"]'),
('b67c3090-78fd-4062-9f67-4717348e49dd','淳熙辛丑自武寧丞攝靖安作  其三','楊方','宋','宋诗','song-poetry','','[]','對縣誰家數畝園，竹亭茅宇雜花繁。',32,'全唐诗/poet.song.154000.json','["對縣誰家數畝園，竹亭茅宇雜花繁。", "同官不可無兼局，通管溪南水竹村。"]'),
('f752f394-1e99-4071-80a8-ad34958bb47f','題武寧丞廳','楊方','宋','宋诗','song-poetry','','[]','暮年叢薄寄鷦鷯，搔首巡簷歲月銷。',32,'全唐诗/poet.song.154000.json','["暮年叢薄寄鷦鷯，搔首巡簷歲月銷。", "留與後人還要否，一軒松竹冷蕭蕭。"]'),
('c397f245-5cce-481d-9aaa-63112467617c','館中簡張約齋  其一','楊方','宋','宋诗','song-poetry','','[]','書生賦分合窮愁，官與休辰不肯休。',32,'全唐诗/poet.song.154000.json','["書生賦分合窮愁，官與休辰不肯休。", "清曉犯寒開省戶，誰家見雪似瀛洲。"]'),
('5b72933a-c8d7-4553-a697-36085051614a','館中簡張約齋  其二','楊方','宋','宋诗','song-poetry','','[]','爛銀宮闕雲端見，素柰園林月下遊。',32,'全唐诗/poet.song.154000.json','["爛銀宮闕雲端見，素柰園林月下遊。", "說與南湖張祕閣，速來同直道山頭。"]'),
('5ad49646-cfca-47ef-98ef-2176ea1e8cce','合歡詩','楊方','宋','宋诗','song-poetry','','[]','爾根深且固，余根淺且洿。',24,'全唐诗/poet.song.154000.json','["爾根深且固，余根淺且洿。", "移植艮無期，嘆息將何如。"]'),
('850a50c6-3e71-4b5b-9a5e-92799b8e4795','古梅','楊方','宋','宋诗','song-poetry','','[]','尚有黄梅一樹斜，幾年叉柱惜繁花。',32,'全唐诗/poet.song.154000.json','["尚有黄梅一樹斜，幾年叉柱惜繁花。", "新詩連壁皆惆悵，想見當時北客家。"]'),
('84acef6b-1d82-4639-a2b8-70cf2f9c7813','送張振古二首  其一','楊方','宋','宋诗','song-poetry','','[]','積剛自許挾浮雲，拂拭平生欲佩君。',32,'全唐诗/poet.song.154000.json','["積剛自許挾浮雲，拂拭平生欲佩君。", "匣古年侵春暈澀，忍隨人課割鉛勳。"]'),
('81da73ef-bb89-4ba9-9c47-0edd24b06f95','送張振古二首  其二','楊方','宋','宋诗','song-poetry','','[]','張公不是病參軍，晚出猶將一事君。',32,'全唐诗/poet.song.154000.json','["張公不是病參軍，晚出猶將一事君。", "耿介只今無伴處，秋光詩好與誰聞。"]'),
('9c94eb63-c6e1-4a67-83b2-52911f053957','江郊亭新成賦詩二十三韻','楊咸亨','宋','宋诗','song-poetry','','[]','蜀江千里東南傾，峽門橫鎖千丈鯨。',368,'全唐诗/poet.song.154000.json','["蜀江千里東南傾，峽門橫鎖千丈鯨。", "吳帆蜀楫過如織，府主四海皆弟兄。", "城西門前二十里，客去當送來當迎。", "藤梢橘刺密無路，短亭四壁荒榛荆。", "春風淡沱酌客處，我陪後乘同郊行。", "碧油紅旆駐沙尾，連宵急雨鼓不鳴。", "元戎玉皇香案吏，俯仰茆屋無乃輕。", "擘山鞭石相原隰，釘頭瓦縫粟縷盈。", "偉哉幻書此奇觀，丹楹畫棟光崢嶸。", "山長波迥目力短，空濛宜雨高宜晴。", "危嵐滴翠染窗戶，空江倒影翻檐甍。", "天藏地設久相待，更爲佳處得佳名。", "梁間橫陳大手筆，龍蛇飛動鬼神驚。", "高齋百篇子美唱，峴山千載羊公情。", "試呼小隊訪新館，壯遊始與盛概并。", "披雲喚月星斗動，放舟聞鶴天水明。", "練光渺渺風力壯，疊鼓西上帆東征。", "舳艫冠蓋兩嘆息，歡謠晝亂漁樵聲。", "元戎故是活國手，山河指顧風塵清。", "淒涼三峽小遊戲，樸斲丹黝安足程。", "明堂梁棟要杞梓，天關一柱須公擎。", "紛紛故吏萬里外，燕雀行慶大厦成。", "賦詩抵掌者誰子，夜郎野老楊咸亨。"]'),
('cb7798b3-075a-45aa-8c9b-365fa348e25a','南山','陳讜','宋','宋诗','song-poetry','','[]','天造其山，在貴之陽。',200,'全唐诗/poet.song.154000.json','["天造其山，在貴之陽。", "二十四峰，拔地峭剛。", "其山維何，如彼玉蒼。", "宅位於離，火德之祥。", "南山何有，有方其巖。", "若堂甚夷，若門者三。", "穹者圓蓋，植者羽參。", "石像天成，匪鑿匪劖。", "陟彼山巔，有洞益奇。", "南北戶通，千里頫闚。", "伊晉之洪，采榮于斯。", "丹飛井霤，木潤草滋。", "昔我太宗，雲章下賁。", "於皇仁廟，奎文狎至。", "巖處有輝，神護孔閟。", "丕昭聖朝，聲化遠暨。", "南山不騫，天子萬年。", "南山不朽，天子萬壽。", "無量惟壽，與天齊久。", "小臣作詩，永颺於後。"]'),
('7ee4766e-c11a-4a67-8804-5189fe0f35fb','彈丸山','陳讜','宋','宋诗','song-poetry','','[]','地迥山奇怪，神仙喜穴居。',48,'全唐诗/poet.song.154000.json','["地迥山奇怪，神仙喜穴居。", "百雲剜洞巧，五石補天餘。", "商野幽人夢，周南太史書。", "心乎愛丘壑，勝概一躊躇。"]'),
('2fbfb32f-a570-4a97-b8cf-8344753ec196','過溪南韓氏宅','陳讜','宋','宋诗','song-poetry','','[]','曾覽溪南勝，重來四十年。',48,'全唐诗/poet.song.154000.json','["曾覽溪南勝，重來四十年。", "樹如人老矣，山共水依然。", "香玉紛堆案，晴虹對跨川。", "吾廬今咫尺，乘興且盤旋。"]'),
('c23a1c96-53f8-4539-aac4-4828de487f63','尊賢堂','陳讜','宋','宋诗','song-poetry','','[]','聞道騎鯨碧眼仙，黄柑手植尚依然。',64,'全唐诗/poet.song.154000.json','["聞道騎鯨碧眼仙，黄柑手植尚依然。", "人間俯仰更成古，天下聲名不計年。", "繭紙誰能收妙墨，鷄林何用續遺編。", "使君爲創新堂事，若解尊賢則是賢。"]'),
('597811df-d380-4547-8514-307b2b5d3c5c','潯陽白牡丹  其一','陳讜','宋','宋诗','song-poetry','','[]','玉色天然賽渥丹，亭亭並立倚朱欄。',32,'全唐诗/poet.song.154000.json','["玉色天然賽渥丹，亭亭並立倚朱欄。", "正緣不語偏含思，若使能行却厭看。"]'),
('71fa5def-992e-493b-a7e1-7cf5665776ae','潯陽白牡丹  其二','陳讜','宋','宋诗','song-poetry','','[]','曉來玉露浥香腮，雪態雲裳妙剪裁。',32,'全唐诗/poet.song.154000.json','["曉來玉露浥香腮，雪態雲裳妙剪裁。", "不比世情隨冷暖，此花端爲老人開。"]'),
('2b71a9fd-db01-41fe-82b6-6cc5de06af95','十洲亭','陳讜','宋','宋诗','song-poetry','','[]','東塘昔號神仙景，亭以洲名世亦稀。',64,'全唐诗/poet.song.154000.json','["東塘昔號神仙景，亭以洲名世亦稀。", "山擁髻鬟臨水鑑，花鋪雲錦出天機。", "好風入座清如濯，古木分行翠欲圍。", "每到馮欄會心處，不知香氣襲人衣。"]'),
('189cf35d-d98f-497b-8754-45c53c32c7d1','句  其一','陳讜','宋','宋诗','song-poetry','','[]','淵源師老杜，體制陋西崑。',12,'全唐诗/poet.song.154000.json','["淵源師老杜，體制陋西崑。"]'),
('3585135b-07bf-4119-831f-0a62ef3465ea','句  其二','陳讜','宋','宋诗','song-poetry','','[]','竹密不知雲欲雨，山高盡見水朝宗。',16,'全唐诗/poet.song.154000.json','["竹密不知雲欲雨，山高盡見水朝宗。"]'),
('b25a2669-6fa1-4cbf-95b6-734ba49c8abd','懷歔歈','周去非','宋','宋诗','song-poetry','','[]','白雲近空山，清風動修竹。',72,'全唐诗/poet.song.154000.json','["白雲近空山，清風動修竹。", "竹間何所有，曲澗聲谷谷。", "山迥何可窮，萬里來懸瀑。", "昔有君子廬，清標謝王屋。", "北山茲正高，邦君見良燭。", "吾黨詎敢忘，封植此佳木。"]'),
('cab13d65-2b30-453a-abb5-26bc085648f1','凈相院','張抑','宋','宋诗','song-poetry','','[]','雲山爛漫本難名，收拾閒情付此生。',64,'全唐诗/poet.song.154000.json','["雲山爛漫本難名，收拾閒情付此生。", "出處自知無上策，往來聊欲試同盟。", "門多賢轍人便靜，琴鎖師堂歲幾更。", "六月岸巾來借扇，頻遊應不禁船行。"]'),
('1adfd31e-810b-488b-b780-900bc25127fd','縣廳書事','袁采','宋','宋诗','song-poetry','','[]','庭下幽花照眼醒，綠陰成幄晚風清。',32,'全唐诗/poet.song.154000.json','["庭下幽花照眼醒，綠陰成幄晚風清。", "何時拋擲銅章去，小艇煙波弄月明。"]'),
('fb6c3c35-c4d5-43be-823f-9a88c08d6171','誠臺春色','薛季宣','宋','宋诗','song-poetry','','[]','鳳闕西岡，郎亭東乳。',200,'全唐诗/poet.song.154000.json','["鳳闕西岡，郎亭東乳。", "惟竹猗猗，誠臺有楚。", "苔痕春綠，玉李晚風。", "屏山坐對，青葱數峰。", "頹牆色弄，文杏新紅。", "爭鮮競秀，芳隨意遠。", "各稱時宜，自成深淺。", "妙意誰傳，叵形罨畫。", "羲皇晚生，先天後卦。", "江湖漲綠，旋拍滄洲。", "晴嵐翠滴，烟瘴悠悠。", "篁鞭破蘚，柳带縈愁。", "亦有江梅，花殘未落。", "弄音好鳥，笙簧度曲。", "堆如瓦鼓，幽獨是稱。", "兀坐頹然，邑荒無政。", "新陽多感，雷鼓轟天。", "清淮咫尺，狼烽夕煙。", "暮四朝三，誰爲第一。", "不知其它，且以永日。"]'),
('e588ca4d-6191-4708-83dd-c2dcb93dcc18','春江夕泛二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','短棹春江裏，桃花流水生。',48,'全唐诗/poet.song.154000.json','["短棹春江裏，桃花流水生。", "天高裝鏡浄，岸遠筆山橫。", "落日無窮意，丹霞逐旋明。", "何時遂歸志，一葉任縱橫。"]'),
('db16ecac-756c-497c-a001-2f632003421c','春江夕泛二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','夕泛春江裏，扁舟萬里心。',108,'全唐诗/poet.song.154000.json','["夕泛春江裏，扁舟萬里心。", "仰頭竟空碧，疏樾成清陰。", "浩志曷可遂，歸懷詎能尋。", "波隨亂山急，意若□流深。", "日落洲上葦，霞生霧堆金。", "重淵狎已貫，飄風顧難禁。", "巖巒多李花，冰霜積梅林。", "爲何縱松舟，且以開吾襟。", "迎送未云已，浮雲逐行吟。"]'),
('b6356703-6621-487c-acc4-7dfffaf8cb2c','俞氏園林','薛季宣','宋','宋诗','song-poetry','','[]','茁茁桃與李，生花故城山。',108,'全唐诗/poet.song.154000.json','["茁茁桃與李，生花故城山。", "修竹共娟好，流水相往還。", "天遠峰可續，人來心已閑。", "殷紅間蒼白，晚吹催潺湲。", "吾邑在何許，滄波對重關。", "煙霞蔽落日，萑葦深前灣。", "送客時已到，遊人意長慳。", "高風怒濤作，卷雪食餉間。", "官禁不可脫，歸哉望斕斑。"]'),
('0e9792c8-5d6d-4fd9-a7ca-0c6e9355c903','石門漁舍','薛季宣','宋','宋诗','song-poetry','','[]','漁家在何許，踳駮巖下石。',96,'全唐诗/poet.song.154000.json','["漁家在何許，踳駮巖下石。", "花樹幾株芳，湖山數峰碧。", "窊樽亭遂古，雙闕天自闢。", "錦繡入茨舍，藤蘿封筀柵。", "吾爲江上遊，形苦世間役。", "心馳定沙步，舟行過簷隙。", "浪翁底鎸銘，太尉此居宅。", "豈若斯人徒，風雲相主客。"]'),
('aa5c68ac-9465-4da2-b6a7-c7f554a4ab53','元夕','薛季宣','宋','宋诗','song-poetry','','[]','元夕不作會，蓮燈相照明。',48,'全唐诗/poet.song.154000.json','["元夕不作會，蓮燈相照明。", "影光嚴鐵馬，讙譟合金城。", "發策悶如醉，中庭空自行。", "月娥雲鏡暗，樽酒爲誰傾。"]'),
('64b6f72d-0681-48e0-93bd-f883803e6a2a','月夜郊行','薛季宣','宋','宋诗','song-poetry','','[]','曠野久晴霽，月娥添夜明。',48,'全唐诗/poet.song.154000.json','["曠野久晴霽，月娥添夜明。", "光浮渰水白，寒徹纊衣清。", "頗復藍關意，端爲剡縣行。", "灝然天宇內，應不負平生。"]'),
('64852878-9887-49e6-ad17-b8deb5e72a8d','讀書三首寄景望 春秋','薛季宣','宋','宋诗','song-poetry','','[]','非復東都會，書王春又春。',48,'全唐诗/poet.song.154000.json','["非復東都會，書王春又春。", "退風飛宋鷁，遠狩獲西麟。", "孔志知安在，豳詩難重陳。", "焚香掩卷坐，歌詠忽臣鄰。"]'),
('981973ca-c309-4a59-b180-592f3153110d','讀書三首寄景望 山海經','薛季宣','宋','宋诗','song-poetry','','[]','帝江無目面，歌舞識成音。',48,'全唐诗/poet.song.154000.json','["帝江無目面，歌舞識成音。", "形天斷厥首，操干意岑崟。", "大化浩難量，懸解在明心。", "舒嘯東皋上，薰風五弦琴。"]'),
('bb957f6c-67f5-4baa-a310-4dc651f8aa01','讀書三首寄景望 韓文','薛季宣','宋','宋诗','song-poetry','','[]','退之强解事，剛不信神仙。',48,'全唐诗/poet.song.154000.json','["退之强解事，剛不信神仙。", "所作古意詩，甘心玉井蓮。", "沈疴痊不見，險絕慟虛傳。", "頼得華陰令，聱書言豈然。"]'),
('77d83b1e-13c5-43ce-8313-21ea54ea828d','遊竹陵善權洞二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','萬古英臺面，雲泉響珮環。',48,'全唐诗/poet.song.154000.json','["萬古英臺面，雲泉響珮環。", "練衣歸洞府，香雨落人間。", "蝶舞疑山魄，花開想玉顔。", "幾如禪觀適，遊魶戲澄灣。"]'),
('8aa8defe-9f27-4b86-8bfb-1f15b46f5f3e','遊竹陵善權洞二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','左右蝸蠻戰，晨昏燕蝠爭。',48,'全唐诗/poet.song.154000.json','["左右蝸蠻戰，晨昏燕蝠爭。", "九星寧曲照，三洞獨何營。", "世事嗟興喪，人情見死生。", "阿誰能種玉，還爾石田耕。"]'),
('246d699d-33b5-4191-89a7-8475dae48fdb','都場正月盡未見梅思雪中石門之遊作  其一','薛季宣','宋','宋诗','song-poetry','','[]','千里春何晚，三旬暖不回。',48,'全唐诗/poet.song.154000.json','["千里春何晚，三旬暖不回。", "眼青暝縣柳，粉白悶宮梅。", "麗水年時泛，桃花雪裏開。", "軒轅丘一夢，懷往意悠哉。"]'),
('b1fe1dd2-cecf-41a3-8263-e6e375b4d051','都場正月盡未見梅思雪中石門之遊作  其二','薛季宣','宋','宋诗','song-poetry','','[]','謝客窮幽處，仙宮隠薜蘿。',48,'全唐诗/poet.song.154000.json','["謝客窮幽處，仙宮隠薜蘿。", "二峰峨魏闕，雙瀑瀉天河。", "犺獚應難致，猿猴却患多。", "雪中山更好，淹歲定如何。"]'),
('b6a6d05f-ffa4-4e93-9c99-3a272baba061','梅花','薛季宣','宋','宋诗','song-poetry','','[]','花實望先進，英華標素王。',48,'全唐诗/poet.song.154000.json','["花實望先進，英華標素王。", "竹籬眠夜月，風雪傲寒塘。", "皎皎曾無對，凄凄忽有香。", "和羹須鼎味，盛服也霓裳。"]'),
('925cc7a3-182d-4a7b-8833-ef77a11b642e','吳江放船至楓橋灣','薛季宣','宋','宋诗','song-poetry','','[]','短篷負長虹，破䉬掛明月。',48,'全唐诗/poet.song.154000.json','["短篷負長虹，破䉬掛明月。", "風馬座中生，天幕波中出。", "高城多隠映，遠岫攙羅列。", "少小泛吳江，始識仙凡別。"]'),
('6f3e1f83-8b4f-4bc0-9015-2de1e5559229','讀春秋有感','薛季宣','宋','宋诗','song-poetry','','[]','巧辯雞三足，曾窺豹兩斑。',48,'全唐诗/poet.song.154000.json','["巧辯雞三足，曾窺豹兩斑。", "鳳衰歌已過，麟獲涕爲潸。", "妄作南柯郡，間爭左角蠻。", "夢回無箇事，風雨度前山。"]'),
('ef94912f-8210-44d8-96b1-8c9f4927248e','送士昭兄赴南外敦宗院二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','人道溫陵郡，山川似洛陽。',48,'全唐诗/poet.song.154000.json','["人道溫陵郡，山川似洛陽。", "懷兄尚淹滯，敦族蹔翱翔。", "會見親先漢，方期變有唐。", "萬安秋夜月，多稱古文章。"]'),
('3c192f9e-5897-4b8a-8b84-867448d287e3','送士昭兄赴南外敦宗院二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','憶昔南州去，松根眺邑廛。',48,'全唐诗/poet.song.154000.json','["憶昔南州去，松根眺邑廛。", "鳥啼雲裏樹，人入洞中天。", "載陟今時路，須航古渡船。", "地窮巇嶮盡，蚤晚濟平川。"]'),
('b45303fb-3f5b-4a74-96fa-70fb77f3ae73','觀天德圖像二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','函封傳遠邊，瞥見藁街懸。',48,'全唐诗/poet.song.154000.json','["函封傳遠邊，瞥見藁街懸。", "虎喙終爲噉，狼心約下賢。", "時無漢延壽，天奪晉苻堅。", "請決春秋事，陳侯訃豈然。"]'),
('cbc12b04-0c8f-4bb4-9cd4-25b3b73b8006','觀天德圖像二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','鳴鏑心何悖，投鞭計亦休。',48,'全唐诗/poet.song.154000.json','["鳴鏑心何悖，投鞭計亦休。", "傳聞廣陵散，因作畔牢愁。", "淝水真同道，黄池故不侔。", "見遺天授像，看是郅支頭。"]'),
('c40d6fe6-0864-4392-a1f7-e1e66f7b7e31','傷淮帥','薛季宣','宋','宋诗','song-poetry','','[]','淮浦天龍戰，居巢塞馬歸。',48,'全唐诗/poet.song.154000.json','["淮浦天龍戰，居巢塞馬歸。", "陣傷軍背水，機失寇踰淝。", "越石知何在，虞君恨曷依。", "都緣生過涉，誰爲斬何徽。"]'),
('bb716518-af6b-42de-8a2d-ee4f46aedf97','袁口回棹有感','薛季宣','宋','宋诗','song-poetry','','[]','放舟谷里口，乘流楚江干。',48,'全唐诗/poet.song.154000.json','["放舟谷里口，乘流楚江干。", "釣臺亦已墮，大舶寧長安。", "春度亂山綠，風回平水湍。", "何須問今古，劫劫難爲觀。"]'),
('19554a41-caf9-4d28-b966-d59e3f47029b','白髮','薛季宣','宋','宋诗','song-poetry','','[]','浮生寧久客，罷沐彈冠幘。',48,'全唐诗/poet.song.154000.json','["浮生寧久客，罷沐彈冠幘。", "芳樹幾時紅，童髮半莖白。", "千月浪翻濤，百齡駒過隙。", "多少少年人，烏頭問華簀。"]'),
('40367d31-8616-4916-9f4d-f2cfb858cdc7','樊口晨泛送程端卿','薛季宣','宋','宋诗','song-poetry','','[]','扁舟送歸客，萬籟寂無風。',48,'全唐诗/poet.song.154000.json','["扁舟送歸客，萬籟寂無風。", "宿霧青郊暗，卿雲碧嶺空。", "水清明去鷺，天遠入征鴻。", "日脚中流見，委蛇走白虹。"]'),
('a628dbe2-f593-4505-8260-834242a994de','寒溪堂有待','薛季宣','宋','宋诗','song-poetry','','[]','疏雨渡西關，寒溪亦厚顔。',48,'全唐诗/poet.song.154000.json','["疏雨渡西關，寒溪亦厚顔。", "風和沈白浪，雲斂出青山。", "浩蕩鷗偏適，翔飛鷺自閑。", "可堪泥染鞅，行客馬班班。"]'),
('387b41e5-3a48-4825-ba95-17296089c975','元夜齋居','薛季宣','宋','宋诗','song-poetry','','[]','漢家傳舊事，太一祀中庭。',48,'全唐诗/poet.song.154000.json','["漢家傳舊事，太一祀中庭。", "宮架崇喬嶽，銀釭耀列星。", "九階塵擾擾，萬室火熒熒。", "兀坐聞迂叟，無人尚典刑。"]'),
('5ddbdddb-8621-4bef-bec9-ed0fc93994ff','讀列女傳','薛季宣','宋','宋诗','song-poetry','','[]','一避先生席，鏗然鼓瑟希。',48,'全唐诗/poet.song.154000.json','["一避先生席，鏗然鼓瑟希。", "功名窗紙薄，聲色路塵微。", "大禮無通問，清談浪解圍。", "黨人狂斐甚，猶有詠雩歸。"]'),
('f6202a0e-8e71-45f7-a6e2-40bf4b1658ac','讀骨鯁集','薛季宣','宋','宋诗','song-poetry','','[]','幾許興亡事，全歸喜怒中。',48,'全唐诗/poet.song.154000.json','["幾許興亡事，全歸喜怒中。", "鸛鳴非雨候，花落任春風。", "龍馬符雖在，檀槐戰已空。", "未須悲麥秀，王道有車攻。"]'),
('f5bf0712-dd90-4ee5-8bb9-28158ded90c0','縣民訴事有以禪僧見況者','薛季宣','宋','宋诗','song-poetry','','[]','訟庭披訴者，道我似禪僧。',48,'全唐诗/poet.song.154000.json','["訟庭披訴者，道我似禪僧。", "不悟無生理，安知最上乘。", "修行心懶慢，溘睡日瞢騰。", "說法還知否，宰官非所能。"]'),
('012f5cb5-be0e-46a2-90d3-8bed61db8bec','士昭兄琴室','薛季宣','宋','宋诗','song-poetry','','[]','弄琴函丈者，無始到來今。',48,'全唐诗/poet.song.154000.json','["弄琴函丈者，無始到來今。", "韶濩五弦上，乾坤三古心。", "荷香流曲沼，烟雨抹寒林。", "閔子罷傾聽，何人知此音。"]'),
('96a1398f-8583-4238-bb49-6c49073adf3c','無眠','薛季宣','宋','宋诗','song-poetry','','[]','丙夜不成寐，可如心念家。',48,'全唐诗/poet.song.154000.json','["丙夜不成寐，可如心念家。", "人情風上草，身世眼中沙。", "宿鳥司更漏，黄蜂集晚衙。", "了忘官府事，高枕是生涯。"]'),
('720cbaa3-bd42-4147-90ef-9e3f4dc1c5ba','武昌射圃後山與江接走植柳竹方茂每爲民家羊羣所齕日有毆羊之事昔贊皇公以祝雞翁自況走亦可謂牧羊兒矣','薛季宣','宋','宋诗','song-poetry','','[]','有欲即有累，無營了無爲。',48,'全唐诗/poet.song.154000.json','["有欲即有累，無營了無爲。", "且非割雞宰，寧是牧羊兒。", "甲解木方遂，苞屯芽定萎。", "江山萬里道，好去莫遲疑。"]'),
('58e5e8d1-1a77-4794-a129-5283ba5b2666','乳鹿或得之近山既不可縱畜之更日而馴走命之曰山友','薛季宣','宋','宋诗','song-poetry','','[]','駒鹿何年致，它山小水濱。',48,'全唐诗/poet.song.154000.json','["駒鹿何年致，它山小水濱。", "呦呦興念母，麌麌熟依人。", "物性初無定，野心時亦馴。", "故林迷町疃，結友幸相親。"]'),
('de81b566-b33c-4b88-a1c9-26691cad7670','乳貓','薛季宣','宋','宋诗','song-poetry','','[]','乳貓毛比雪，卉服絮成衣。',48,'全唐诗/poet.song.154000.json','["乳貓毛比雪，卉服絮成衣。", "扼鼠氣方盛，食牛形但微。", "紛拏殊矍鑠，上下擬騰飛。", "幾許明眸子，虧盈望日暉。"]'),
('23977ba5-7c05-4474-a601-468dc27b9061','芍藥','薛季宣','宋','宋诗','song-poetry','','[]','萃拔秀羣芳，花間得素王。',48,'全唐诗/poet.song.154000.json','["萃拔秀羣芳，花間得素王。", "牡丹紅樹色，菡萏碧池香。", "融洩云何樂，熙怡日是常。", "問人伊謔事，士女熟相忘。"]'),
('3eca3ae8-d346-4e6a-b40b-84a5f7fbcf6f','殊亭','薛季宣','宋','宋诗','song-poetry','','[]','指掌視吳都，遊人望已殊。',48,'全唐诗/poet.song.154000.json','["指掌視吳都，遊人望已殊。", "清江浮晚岸，綠野漲春湖。", "我乏淵明事，誰爲漫叟徒。", "醉心尋古記，始信不虛誣。"]'),
('e173c9da-fd2f-433e-bb85-a7e79d2b969e','寒食雨  其一','薛季宣','宋','宋诗','song-poetry','','[]','風雨逢寒食，天公涕亦潸。',48,'全唐诗/poet.song.154000.json','["風雨逢寒食，天公涕亦潸。", "柳眉顰綠髮，花淚溼朱顔。", "貼嶠雲橫水，藏舟霧障灣。", "燒痕青已徧，若箇子推山。"]'),
('3300f64f-05c6-4158-9acd-1abff2398c83','寒食雨  其二','薛季宣','宋','宋诗','song-poetry','','[]','客裏換春衣，寒風带雨霏。',48,'全唐诗/poet.song.154000.json','["客裏換春衣，寒風带雨霏。", "漸班榆火禁，初感塞鴻歸。", "柳絮鶑啼亂，梨花蝶趁飛。", "丘原壇祭耳，悲念切更微。"]'),
('e23e0c75-86a1-4cd3-ae0c-cbcf36f9b6a7','袁口舟行值雨','薛季宣','宋','宋诗','song-poetry','','[]','樊楚勞形甚，將迎一遡流。',48,'全唐诗/poet.song.154000.json','["樊楚勞形甚，將迎一遡流。", "棹移驚立鳥，帆遠亂浮漚。", "落漠江皋樹，依稀荻岸舟。", "烏雲鳴雨急，還我舊神遊。"]'),
('761cbc29-2392-49ed-b739-e0a4237062dd','酴醿雨後  其一','薛季宣','宋','宋诗','song-poetry','','[]','晼晚春闌雨，酴醿花意秋。',48,'全唐诗/poet.song.154000.json','["晼晚春闌雨，酴醿花意秋。", "雪飛香霰集，龍鬭玉雲浮。", "外戶楊青眼，中唐浪白頭。", "夢回人不見，心醉兀悠悠。"]'),
('15eaceda-02ce-4ef8-ad57-3b71b6e746c0','酴醿雨後  其二','薛季宣','宋','宋诗','song-poetry','','[]','玩世無心子，成功不義侯。',48,'全唐诗/poet.song.154000.json','["玩世無心子，成功不義侯。", "升沈三躍浪，聚散一浮漚。", "守郡官槐木，王家夢髑髏。", "團團天上月，猶自曲如鉤。"]'),
('6ddff208-e10d-4753-a85e-61ae75ff4619','𣒅花唐玉蕊花介甫謂之瑒花魯直謂之山礬武昌山中多有之其葉可供染事土人用之釀酒','薛季宣','宋','宋诗','song-poetry','','[]','𣒅綠吐瑶琨，泠然郭外村。',48,'全唐诗/poet.song.154000.json','["𣒅綠吐瑶琨，泠然郭外村。", "仙人來玉蕊，文士立山礬。", "芳澤留絲素，風流付酒罇。", "莫言瑒酷似，香處不勝繁。"]'),
('88a73937-26a5-43c9-948b-f6882d624c34','春霖未霽澍雨大作','薛季宣','宋','宋诗','song-poetry','','[]','甚雨過清明，侵淫不肯晴。',48,'全唐诗/poet.song.154000.json','["甚雨過清明，侵淫不肯晴。", "天占符後甲，人意失先庚。", "陌路河魚上，階塘野草生。", "早來雲陡黑，流澍霫間成。"]'),
('ca226da2-be53-4429-a30b-e77e6fa543b1','書江表志','薛季宣','宋','宋诗','song-poetry','','[]','株守生財道，棋翻正國成。',48,'全唐诗/poet.song.154000.json','["株守生財道，棋翻正國成。", "周王方虎噬，唐后獨牛耕。", "軍罷心忘戰，民勞勢自傾。", "誰如內史鉉，求伴大夫平。"]'),
('a9495e1f-0b88-4639-8e10-7abf10c586ac','夏日晝寢','薛季宣','宋','宋诗','song-poetry','','[]','至樂歸靈囿，棲神得睡鄉。',48,'全唐诗/poet.song.154000.json','["至樂歸靈囿，棲神得睡鄉。", "青奴涼自愜，班友夢偏長。", "莫管黄粱熟，何須綠醑嘗。", "知他人世界，若處有虞唐。"]'),
('7f6e4a3a-4a10-4c53-9bf7-2378e5b5b431','夏口懷舊','薛季宣','宋','宋诗','song-poetry','','[]','夏口傷前事，毛精淚暗垂。',48,'全唐诗/poet.song.154000.json','["夏口傷前事，毛精淚暗垂。", "白龜生不報，黄鵠去無期。", "嶺雪炎雲熾，瓜田古岸移。", "戰塵愁滿眼，聊付一篇詩。"]'),
('756bdf34-2ed3-43e4-bf07-594b2d9a96c6','寒溪寺拈香時國喪罷宴錫已三歲二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','社舞莫㛹娟，當修晉白蓮。',108,'全唐诗/poet.song.154000.json','["社舞莫㛹娟，當修晉白蓮。", "林梢開遠嶂，花片落寒泉。", "鐘鼓鏗鏘甚，松篁影带妍。", "如來本無象，長老亦逃禪。", "昔者溪爲虎，如今突蹔煙。", "萬松晨逕滑，九曲夏雲連。", "畦町苗初實，池塘滴尚涓。", "潔齋朝五日，清浄樂三年。", "要祝南山壽，南山壽十千。"]'),
('cd76f9ae-7601-4bd9-abbb-c13cb5ebdf2d','寒溪寺拈香時國喪罷宴錫已三歲二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','朝衣結藍綬，古剎禮青蓮。',108,'全唐诗/poet.song.154000.json','["朝衣結藍綬，古剎禮青蓮。", "蒨絢林間樹，琤瑽竹下泉。", "晨曦方散彩，曉宿有餘妍。", "聚石應聞道，無人爲說禪。", "路回荒翳目，江遠望生煙。", "略彴溪源舊，孱顔嶺岫連。", "清神山歷歷，洗耳澗涓涓。", "菩薩行觀世，封人願祝年。", "更須東畝粟，長穗滿三千。"]'),
('9e9c2c25-4b96-4dab-a9ae-9a3c53963187','石榴花','薛季宣','宋','宋诗','song-poetry','','[]','國色宜炎夏，宮裝染絳紗。',48,'全唐诗/poet.song.154000.json','["國色宜炎夏，宮裝染絳紗。", "蒼崖陸渾火，朱景赤城霞。", "顔駐留瓊蕊，丹成嚥日華。", "東山舊遊處，遥憶武陵家。"]'),
('ab4c7265-9ae9-4c8f-bad0-2ba368781801','自訟','薛季宣','宋','宋诗','song-poetry','','[]','學問非干祿，宦遊端爲貧。',48,'全唐诗/poet.song.154000.json','["學問非干祿，宦遊端爲貧。", "生慙挽船令，羞殺采芝人。", "求牧知平陸，無漿賣棘津。", "讀書心愧否，何日是來春。"]'),
('ea27264d-fcd3-4257-93d7-56087c000dcc','讀李斯傳','薛季宣','宋','宋诗','song-poetry','','[]','上蔡游公子，真情本自愚。',48,'全唐诗/poet.song.154000.json','["上蔡游公子，真情本自愚。", "五刑身具論，七罪法當誅。", "逐兔蹤牽狗，亡秦效擊胡。", "明功與周召，爲問驪山徒。"]'),
('4388e2bb-285e-4cd2-870b-d7e794875796','宿低寨遇雨','薛季宣','宋','宋诗','song-poetry','','[]','酣睡忽驚覺，空牀秋氣清。',48,'全唐诗/poet.song.154000.json','["酣睡忽驚覺，空牀秋氣清。", "四垂來雨脚，萬壑漲灘聲。", "飛洒穿戎幕，凄涼悵旅情。", "緹幢高卧者，應更薄書生。"]'),
('a37480c4-c31a-401c-8270-0a709301614e','至信陽宿蕭安撫寨蕭虜蔡將去歲陷信陽者','薛季宣','宋','宋诗','song-poetry','','[]','左角語爭戰，南柯聞大奔。',48,'全唐诗/poet.song.154000.json','["左角語爭戰，南柯聞大奔。", "胡爲控弦去，猶有覆車存。", "行客應貪路，邊城不閉門。", "夜眠思往舊，空淚溼牀痕。"]'),
('31ff0e47-ced0-4a92-baa5-58cf0771d160','別元可元亨','薛季宣','宋','宋诗','song-poetry','','[]','去矣鴟夷子，片帆移夕陽。',48,'全唐诗/poet.song.154000.json','["去矣鴟夷子，片帆移夕陽。", "意深三折臂，情結九回腸。", "風雨思無晦，江湖道可忘。", "死生猶暫別，萬里未爲長。"]'),
('ed7e253f-fd8b-4b7a-b164-74a54e10e042','縣有父子訟者走以魯人之法聽之喜其改悔而作','薛季宣','宋','宋诗','song-poetry','','[]','父子本天性，情緣私愛暌。',48,'全唐诗/poet.song.154000.json','["父子本天性，情緣私愛暌。", "寧留今夕忍，無作望思悲。", "克己歸仁禮，回心即孝慈。", "同年千古意，聖相不吾欺。"]'),
('88d59c4c-4e60-43dd-abbf-d6b57b5f5d1b','樊岡雨後瀰望皆平蕪綠草無復花矣','薛季宣','宋','宋诗','song-poetry','','[]','候客樊岡道，新晴致日佳。',48,'全唐诗/poet.song.154000.json','["候客樊岡道，新晴致日佳。", "萬般詩外意，百種夢中花。", "蔓綠鋪平野，江流襲漲沙。", "無如石頭滑，龍首粲新芽。"]'),
('73dd1a74-15e1-4733-ae61-f58816978c54','漁父二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','蹤跡五湖浪，生涯千尺綸。',48,'全唐诗/poet.song.154000.json','["蹤跡五湖浪，生涯千尺綸。", "是非寧入耳，榮辱不關身。", "獵獵菰蒲暮，淒淒浦溆春。", "何時共蓑笠，和雨釣青蘋。"]'),
('551b57dd-8830-4c7f-8322-5e9e3e51735e','漁父二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','紅蓼白蘋岸，清風江月明。',48,'全唐诗/poet.song.154000.json','["紅蓼白蘋岸，清風江月明。", "萬波千尺動，四海一漚輕。", "濁酒醉獨酌，鮮魚饑旋烹。", "興來歌欵乃，煙雨過前汀。"]'),
('beba37fb-5608-4056-81d8-fe05c2315d84','筠鄉新筍','薛季宣','宋','宋诗','song-poetry','','[]','根節凌槐夏，風霜閲草春。',48,'全唐诗/poet.song.154000.json','["根節凌槐夏，風霜閲草春。", "此君椽筆健，稚子錦綳新。", "有待瞻淇奧，行將滿渭濱。", "狂鞭任奔迸，我不是饞人。"]'),
('0a68d2ec-7de9-4a7d-87d1-490bb4f0a416','白菊','薛季宣','宋','宋诗','song-poetry','','[]','不著金縷衣，寒窗弄明月。',48,'全唐诗/poet.song.154000.json','["不著金縷衣，寒窗弄明月。", "端宜裝淡泊，自是香蓬馞。", "臭味真可人，風流到華髮。", "試爲問東籬，定得淵明骨。"]'),
('99aae7f1-d271-4c12-86d5-83aad565acf4','丁香花','薛季宣','宋','宋诗','song-poetry','','[]','別是南州種，寒花七里香。',48,'全唐诗/poet.song.154000.json','["別是南州種，寒花七里香。", "玉笄駢寶髻，金粟綴銀璫。", "自得山林趣，不爲時世裝。", "紫霞休騁瑞，未及野梅芳。"]'),
('4ef81051-7662-4b9d-adf3-58fdf7e9eb0b','立春','薛季宣','宋','宋诗','song-poetry','','[]','誰得東君信，風生十萬家。',48,'全唐诗/poet.song.154000.json','["誰得東君信，風生十萬家。", "土牛占穀麥，灰律動蒹葭。", "嫩綠萌芳蕊，新紅茁綻芽。", "未能都免俗，春勝插春花。"]'),
('6c05ee82-b1f4-42bd-a977-c37e778eaca6','雪','薛季宣','宋','宋诗','song-poetry','','[]','怪得寒風瘦，窗明積漸加。',240,'全唐诗/poet.song.154000.json','["怪得寒風瘦，窗明積漸加。", "起來裘潑水，逆視竹生花。", "厚貌分羣品，新裝副六珈。", "飄零飛落葉，轉動絞回車。", "無定從高下，忘形變邇遐。", "郊坰鋪毳罽，階砌撒江沙。", "灑壁侵修飾，填坑旋不漥。", "屋頭昂怪獸，山脊走長蛇。", "萬木枝都亞，中庭石盡遮。", "獅符蹲陡踞，龍井噴增呀。", "撲面輕盈甚，裝衣點綴斜。", "礎閑開匣鏡，碑仆插梳牙。", "同色連千里，虛光合萬家。", "壓災時世重，爲瑞老農誇。", "勢極雲天際，威凌凍水涯。", "凹兜坡崿岝，條突樹牙槎。", "客子衣裳怯，王孫酒力奢。", "影浮垂繡幌，香带落梅花。", "籭簸知神女，門屯想夜叉。", "未能三十韻，旋瀹試烹茶。"]'),
('5d0c4def-eb11-4404-88b1-b83d545b39f9','郊迎趙漕','薛季宣','宋','宋诗','song-poetry','','[]','叱御逆軺車，愁先負弩驅。',48,'全唐诗/poet.song.154000.json','["叱御逆軺車，愁先負弩驅。", "虎頭晴在望，羊角淖盈途。", "草莽迷行跡，湖山出畫圖。", "傷今又懷古，坐睡覺吳歈。"]'),
('aefb6ab3-13e5-4acf-9947-52551b2b8d93','傳聞北虜請和','薛季宣','宋','宋诗','song-poetry','','[]','會稽吳功薄，夫椒越報深。',48,'全唐诗/poet.song.154000.json','["會稽吳功薄，夫椒越報深。", "漢驅胡遠遁，周任狄來侵。", "頼是佛狸死，何當頡利禽。", "請和君信否，無故莫容心。"]'),
('d209f89b-df8d-4450-91b6-e9636cdcff6c','梅雨','薛季宣','宋','宋诗','song-poetry','','[]','霢霂雨黄梅，凝雲綰不開。',48,'全唐诗/poet.song.154000.json','["霢霂雨黄梅，凝雲綰不開。", "心知養苗稼，眼見長莓苔。", "密篋幾如漬，崇墉勢欲隤。", "鬰蒸任炎熱，誰解酌金罍。"]'),
('e47d6f10-7ea5-4953-937c-d57c317a2c31','遊飛霞洞','薛季宣','宋','宋诗','song-poetry','','[]','橫塘富花柳，杳杳鏡中行。',48,'全唐诗/poet.song.154000.json','["橫塘富花柳，杳杳鏡中行。", "樓觀朱涵壁，洞天珉掩閎。", "林深暮雲合，地僻夏寒生。", "康樂屏巖靜，鳴榔時一聲。"]'),
('f89c7169-7f73-4adb-883d-a1a80206d8fa','龍翔寺','薛季宣','宋','宋诗','song-poetry','','[]','二江涵古寺，雙嶼聳平沙。',48,'全唐诗/poet.song.154000.json','["二江涵古寺，雙嶼聳平沙。", "翠浪環流浄，金城到眼奢。", "水光摇殿閣，塔景動龍蛇。", "不減蓬壺意，屯雲未許遮。"]'),
('7ff033ae-ff33-41b6-ad43-0be9a6113471','酬張縣尉','薛季宣','宋','宋诗','song-poetry','','[]','久客多塵滓，心懷爲子開。',48,'全唐诗/poet.song.154000.json','["久客多塵滓，心懷爲子開。", "文知龍有種，名苦雉爲媒。", "但得貧無累，何嗟去不來。", "吳門衆多士，待爾和羹梅。"]'),
('8e79209c-1daf-4ecd-bd6b-b1c46d76e528','元夕憶世母','薛季宣','宋','宋诗','song-poetry','','[]','蒼天毒我生，顧復自孩嬰。',48,'全唐诗/poet.song.154000.json','["蒼天毒我生，顧復自孩嬰。", "元夜維蛇夢，三山壽斝傾。", "星毬明烜赫，鼇島峻崢嶸。", "樂事都如夢，傷心母道情。"]'),
('888a4869-50ea-46f3-9df8-332deab0047e','拒霜花','薛季宣','宋','宋诗','song-poetry','','[]','蘸染木芙蓉，深紅間淺紅。',48,'全唐诗/poet.song.154000.json','["蘸染木芙蓉，深紅間淺紅。", "錦籠烘夕照，翠袖揖秋風。", "艷冶歸尤物，凄涼識化工。", "拒霜高節在，丹藥謾成業。"]'),
('6a75e6e8-cdf1-4f86-9d4f-29499cb8f296','早行','薛季宣','宋','宋诗','song-poetry','','[]','旅枕罷殘夢，明星懸屋椽。',48,'全唐诗/poet.song.154000.json','["旅枕罷殘夢，明星懸屋椽。", "不辭風露冷，欲了東西緣。", "雲馭方擎日，月輪猶印天。", "波波定何事，羞死地行仙。"]'),
('76d2fefa-1d90-45e1-b238-51a5db20984f','天陰','薛季宣','宋','宋诗','song-poetry','','[]','梅月乍開霽，油雲閒卷舒。',48,'全唐诗/poet.song.154000.json','["梅月乍開霽，油雲閒卷舒。", "溢光穿隙日，浮祲出清虛。", "鼓吹蛙聲亂，笙簧竹影疏。", "雨來三四點，靜覺打籧篨。"]'),
('5a6bbf4b-79d5-4065-b544-48492b8c26f6','告歸郡不得請倦于將迎之勞','薛季宣','宋','宋诗','song-poetry','','[]','閒居百不憂，何事武昌遊。',48,'全唐诗/poet.song.154000.json','["閒居百不憂，何事武昌遊。", "旦旦三江口，時時十里頭。", "箇中都是妄，此外竟何求。", "生被浮名累，將迎卒未休。"]'),
('d835ab64-e299-4280-93fd-f53547473942','昧爽寒溪送客','薛季宣','宋','宋诗','song-poetry','','[]','攀援長者車，昧爽踏汀沙。',48,'全唐诗/poet.song.154000.json','["攀援長者車，昧爽踏汀沙。", "片玉山銜水，堆金日蘸霞。", "風來雲外嶺，露重竹間花。", "好景看如客，心閒即是家。"]'),
('3bf05334-924e-44a1-815d-5a2c0d5405af','二十三日送客寒溪還視邑事食時過節推周文猶高卧未起愒然嗟羨以詩戲之','薛季宣','宋','宋诗','song-poetry','','[]','驚起周公夢，三竿日倍高。',48,'全唐诗/poet.song.154000.json','["驚起周公夢，三竿日倍高。", "被氈吟不用，州縣職徒勞。", "脂轄驅郵置，金車困賊曹。", "幾如陳處士，龍卧楚江皋。"]'),
('ab782264-f4ff-4f9b-827c-9466efb391ef','夏日江濱','薛季宣','宋','宋诗','song-poetry','','[]','鳥迹鋪天篆，金波漾日沙。',48,'全唐诗/poet.song.154000.json','["鳥迹鋪天篆，金波漾日沙。", "鷺拳巖積雪，風勺浪飛花。", "江斷客帆入，崖回山影斜。", "峰雲青入漢，略約二三家。"]'),
('02e0a270-8531-41e2-8b33-a906f54ded6b','聞黄仲益雲夢辟書報命','薛季宣','宋','宋诗','song-poetry','','[]','三府書交上，羣公座盡傾。',48,'全唐诗/poet.song.154000.json','["三府書交上，羣公座盡傾。", "量包雲夢嶺，名動洛陽城。", "雞肋刀焉用，牛腰軸定盈。", "江南望江北，無可贈梅英。"]'),
('bd262559-d816-40bd-bbd5-4e1b5d309d7d','讀蕭銑傳','薛季宣','宋','宋诗','song-poetry','','[]','不假成田勢，寧堪麥秀悲。',48,'全唐诗/poet.song.154000.json','["不假成田勢，寧堪麥秀悲。", "青氈梁舊物，赤幟漢威儀。", "剛被農家誤，俄推鼎祚移。", "江湖百郡地，只自黍離離。"]'),
('f9a5fe8b-5a47-488d-a1e9-643bf6761edc','讀九國志悶書','薛季宣','宋','宋诗','song-poetry','','[]','弔古因紬卷，傷神却皺眉。',48,'全唐诗/poet.song.154000.json','["弔古因紬卷，傷神却皺眉。", "蜂房開自牖，蟻穴潰成堤。", "不苦南風競，長懷北馬悲。", "陽曦曜星月，還有餞西時。"]'),
('d7d72744-d77f-4f39-982d-7ee462874627','被甲','薛季宣','宋','宋诗','song-poetry','','[]','儒服便章甫，戎裝乍鐵衣。',48,'全唐诗/poet.song.154000.json','["儒服便章甫，戎裝乍鐵衣。", "幾曾生共樂，猶有死同歸。", "著屨惟何甚，乘車未遽非。", "愧酬軍旅問，先見少知幾。"]'),
('08955618-711d-4f00-8dad-4dede12b022f','曾陽回棹','薛季宣','宋','宋诗','song-poetry','','[]','沔曲回晨棹，驚飛羨水禽。',48,'全唐诗/poet.song.154000.json','["沔曲回晨棹，驚飛羨水禽。", "波紋沙隠見，山影浪浮沈。", "色動蘆花雪，光摇日脚金。", "扁舟歸未得，惆悵五湖心。"]'),
('9522cd90-30f0-4038-b0ee-23475940b7e2','讀三國志','薛季宣','宋','宋诗','song-poetry','','[]','左角蠻攻觸，南柯檀伐槐。',48,'全唐诗/poet.song.154000.json','["左角蠻攻觸，南柯檀伐槐。", "徘諧記名字，人物委塵埃。", "錦里昔曾到，樊川今此來。", "遺風不可見，觀古意悠哉。"]'),
('062718bd-1073-4d92-a383-11de66dabec3','讀史','薛季宣','宋','宋诗','song-poetry','','[]','信乃噲等伍，宏與滔比肩。',48,'全唐诗/poet.song.154000.json','["信乃噲等伍，宏與滔比肩。", "饗士未爲過，出跨真能賢。", "物外體三極，環中無二天。", "傷哉千古恨，顰蹙翫陳編。"]'),
('e2692a84-dc95-4860-a829-3f505c0aef41','仵落回路得家書是夕有歸夢','薛季宣','宋','宋诗','song-poetry','','[]','夢入江南路，依然識舊廬。',48,'全唐诗/poet.song.154000.json','["夢入江南路，依然識舊廬。", "家人話生計，兒子督程書。", "繚繞俗緣在，纏綿習氣餘。", "金雞驚悞我，安問未爲疏。"]'),
('562b95d7-f1cb-42bf-8750-19eb4ea0d22d','三月七日按雲陂莊還宿舊州寺懷松楸作','薛季宣','宋','宋诗','song-poetry','','[]','不學老農稼，而爲田舍翁。',48,'全唐诗/poet.song.154000.json','["不學老農稼，而爲田舍翁。", "劬勞方軫慮，定集竟何功。", "心惻焄蒿氣，時寒疾甚風。", "年時尚壇祭，廢絕意奚窮。"]'),
('aef39075-c5dd-4250-9002-6b93edf08ceb','山舍三首  其一','薛季宣','宋','宋诗','song-poetry','','[]','髣髴依蠻室，林端鳥道縈。',48,'全唐诗/poet.song.154000.json','["髣髴依蠻室，林端鳥道縈。", "煙疑雲異色，松接澗同聲。", "樹古龍蛇蚴，巖嵬虎豹獰。", "野花舞狂蝶，栩栩夢莊生。"]'),
('7162d841-63ea-451f-ac4c-2d46f55b1fa9','山舍三首  其二','薛季宣','宋','宋诗','song-poetry','','[]','塢闊廜蘇小，奇峰疊翠屏。',48,'全唐诗/poet.song.154000.json','["塢闊廜蘇小，奇峰疊翠屏。", "巖頭通鳥跡，山脊走龍形。", "峽斷風偏勁，林幽天欲冥。", "流泉不知處，虛谷響泠泠。"]'),
('eb718de9-560e-44a1-bd92-2afbe49341d9','山舍三首  其三','薛季宣','宋','宋诗','song-poetry','','[]','寂寞無塵事，茅茨秀嶺連。',48,'全唐诗/poet.song.154000.json','["寂寞無塵事，茅茨秀嶺連。", "密蘿蒙灌木，亂石隠流泉。", "蟬噪雲間樹，鳥飛山外天。", "孤雲自明滅，應達主人玄。"]'),
('fd249ce8-e6f8-410d-88d7-ee608b077f04','觀棋','薛季宣','宋','宋诗','song-poetry','','[]','戰伐徒形似，死生俱妄爲。',48,'全唐诗/poet.song.154000.json','["戰伐徒形似，死生俱妄爲。", "爭先明有法，當局自成迷。", "多算非關劫，成功定出奇。", "兩情深海若，不比看人知。"]'),
('110394f4-14ec-4477-8d8d-b2a93d508774','昇仙寺','薛季宣','宋','宋诗','song-poetry','','[]','羽翼假真仙，飛來秀嶺巔。',48,'全唐诗/poet.song.154000.json','["羽翼假真仙，飛來秀嶺巔。", "道高還自正，境寂若爲禪。", "寓目山如礪，昂頭浪拍天。", "閩城多少地，羃歷带平煙。"]'),
('e6db57a0-fbca-4d5a-8a84-546f6aa86ea1','丙子歲春','薛季宣','宋','宋诗','song-poetry','','[]','物極雖云反，寒威何太衰。',48,'全唐诗/poet.song.154000.json','["物極雖云反，寒威何太衰。", "東風入簾幕，生意滿林畦。", "古木含新綠，仙葩吐舊枝。", "陰晴苦不定，中夜忍聞規。"]'),
('b78efb20-daf8-4faa-a250-668a058e01fd','江行即事','薛季宣','宋','宋诗','song-poetry','','[]','春信潮聲急，滔滔掩岸沙。',48,'全唐诗/poet.song.154000.json','["春信潮聲急，滔滔掩岸沙。", "客船離浦溆，漁笛起蒹葭。", "盪槳水光碎，轉山帆影斜。", "篙工指煙樹，依約有人家。"]'),
('416538d0-9429-4d59-9474-d45bd40492e5','雪銷','薛季宣','宋','宋诗','song-poetry','','[]','旬浹雨銀花，山林盡綺羅。',48,'全唐诗/poet.song.154000.json','["旬浹雨銀花，山林盡綺羅。", "東風雲氣減，南紀日光和。", "皓皓污應易，涓涓滴轉多。", "冰生又冰釋，天道竟如何。"]'),
('4988bdaf-9ea8-49d5-b150-8406112d0fee','讀大定書詔','薛季宣','宋','宋诗','song-poetry','','[]','竊國盜仁義，驚人新見聞。',48,'全唐诗/poet.song.154000.json','["竊國盜仁義，驚人新見聞。", "腥羶冠冕俗，穢雜犬羊羣。", "孟獲尚七縱，匈奴非五分。", "啟民身薙草，爲有鴈門軍。"]'),
('06102491-14ad-4f99-9c8c-e4203d2a7168','誠臺雪望懷子都五首  其一','薛季宣','宋','宋诗','song-poetry','','[]','不見子都子，誠臺一壯觀。',48,'全唐诗/poet.song.154000.json','["不見子都子，誠臺一壯觀。", "爛開梅骨峭，高聳玉峰寒。", "誰共雲霄目，詩亡錦繡肝。", "夢魂千里道，應更酒腸寬。"]'),
('d4fa900c-5431-4e9a-aaf1-b1eb15be54ef','誠臺雪望懷子都五首  其二','薛季宣','宋','宋诗','song-poetry','','[]','故人一相遇，七返霰瀌瀌。',48,'全唐诗/poet.song.154000.json','["故人一相遇，七返霰瀌瀌。", "辭采應奇甚，顛狂即在不。", "尋思落帽會，乘興錦官遊。", "皎皎誠臺暮，詩腸獨自搜。"]'),
('ab403697-2bc6-490e-b0b7-48e4b5109440','誠臺雪望懷子都五首  其三','薛季宣','宋','宋诗','song-poetry','','[]','白也今良嗣，千年璧一雙。',48,'全唐诗/poet.song.154000.json','["白也今良嗣，千年璧一雙。", "文思泉漱石，色照月明窗。", "樸樕空樊渚，飄零遠漢江。", "此情誰與度，木介響琤瑽。"]'),
('c5e5ba99-8a51-41db-9a8a-c023c86bb96a','誠臺雪望懷子都五首  其四','薛季宣','宋','宋诗','song-poetry','','[]','狂遊失可人，萍聚我和君。',48,'全唐诗/poet.song.154000.json','["狂遊失可人，萍聚我和君。", "千里共明月，幾山空白雲。", "擊鵰飛墮毳，嚼雪冷冰齦。", "百歲無多子，離居困索羣。"]'),
('3b261ed3-eb58-4ae1-ad45-1867323a50c9','誠臺雪望懷子都五首  其五','薛季宣','宋','宋诗','song-poetry','','[]','掩脛誠臺雪，吟頭祇自昂。',48,'全唐诗/poet.song.154000.json','["掩脛誠臺雪，吟頭祇自昂。", "梅花開嶺路，冰玉皺池塘。", "良馬日千里，美人天一方。", "尺書不可寄，道義兩相忘。"]'),
('3425f61f-b6f8-4a2e-a9b7-b10105be9d47','和賈簿','薛季宣','宋','宋诗','song-poetry','','[]','官冷君休歎，浮名陌路車。',48,'全唐诗/poet.song.154000.json','["官冷君休歎，浮名陌路車。", "冰山逢燠泮，豆粥併寒除。", "但酌樽中酒，從堆架上書。", "未酬題柱志，終不羨相如。"]'),
('be3d833b-dcd3-4c04-a778-e93ee8aa821e','忌日雪','薛季宣','宋','宋诗','song-poetry','','[]','荼毒惟何甚，同時失所天。',48,'全唐诗/poet.song.154000.json','["荼毒惟何甚，同時失所天。", "哀傷逢此日，懷抱憶初年。", "白雪明心素，青松黯墓埏。", "不堪陳几席，罪罟欲誰冤。"]'),
('7b3996a5-4316-4421-9449-ef1dd3f58098','大雪','薛季宣','宋','宋诗','song-poetry','','[]','江市彌旬雪，人行失舊蹤。',48,'全唐诗/poet.song.154000.json','["江市彌旬雪，人行失舊蹤。", "梅藏香骨瘦，冰結浪花重。", "髣髴門前柳，昏迷郭外峰。", "屋簷天漢在，一雁沒清空。"]'),
('1620a090-1eb9-46c7-98b2-784594d54801','喜雨','薛季宣','宋','宋诗','song-poetry','','[]','麥穗雖乾耳，秧苗未吐心。',48,'全唐诗/poet.song.154000.json','["麥穗雖乾耳，秧苗未吐心。", "正須雲潑墨，生怕日流金。", "氣鬰山堂潤，風回竹逕陰。", "稱人三四點，爭道即爲霖。"]'),
('de736eea-6c07-4130-91e1-b38a6aca2c80','春老寒雨酴醿竟爛','薛季宣','宋','宋诗','song-poetry','','[]','無定若遊絲，神人薦玉衣。',48,'全唐诗/poet.song.154000.json','["無定若遊絲，神人薦玉衣。", "飄摇思遠舉，婀娜怯空歸。", "晚色檀心重，春寒酒力微。", "牽腸無柳眼，香絮雪花飛。"]'),
('cf2f601b-bc96-4713-a09b-b13019a05461','讀史','薛季宣','宋','宋诗','song-poetry','','[]','閑是等閑非，沈迷不自知。',48,'全唐诗/poet.song.154000.json','["閑是等閑非，沈迷不自知。", "黄粱一夜夢，白雪數人詩。", "身後輸杯酒，生前對局棋。", "幾多亡國恨，窗几靜搘頤。"]'),
('b67ebb5f-efff-43ec-b711-8bd8620758a3','延陵感懷','薛季宣','宋','宋诗','song-poetry','','[]','延陵七春夢，悲切意更微。',48,'全唐诗/poet.song.154000.json','["延陵七春夢，悲切意更微。", "頗復吳牛喘，還多代馬依。", "去來紛混混，今昨是非非。", "況在遼東鶴，千年方始歸。"]'),
('f87e40ad-188f-4db9-ad42-18d6ff90994f','雪霽和智叔次諸郎曹韻二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','風洗朔雲靜，愁蠲淚眼晴。',48,'全唐诗/poet.song.154000.json','["風洗朔雲靜，愁蠲淚眼晴。", "夜闌灰亦冷，目眩室生明。", "客子遠鄉巷，天公偏世情。", "布衾寒潑水，墜葉也心驚。"]'),
('29c9c2cc-ac4d-4e9a-b1fa-d40ba1c46e78','雪霽和智叔次諸郎曹韻二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','同雲起飛絮，忽作無意晴。',48,'全唐诗/poet.song.154000.json','["同雲起飛絮，忽作無意晴。", "夢破客愁絕，魂銷天夜明。", "聞雞悲壯節，哀雁切鄉情。", "夜靜羣動息，空牀時自驚。"]'),
('1f34dad1-9532-4101-aefd-fecbe7205d90','元日','薛季宣','宋','宋诗','song-poetry','','[]','鳳曆回龍紀，羲和御物新。',48,'全唐诗/poet.song.154000.json','["鳳曆回龍紀，羲和御物新。", "崎嶇萬里道，牢落五年春。", "羈客聞哀雁，傷懷念昔人。", "米鹽能幾許，還自不由身。"]'),
('e8c6ca31-7df0-4f29-a737-a58dfa85c604','夢回二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','憶到梯雲巷，哀傷韡鄂叢。',48,'全唐诗/poet.song.154000.json','["憶到梯雲巷，哀傷韡鄂叢。", "舞鸞悲引鏡，傷雁落空弓。", "清夢回時雨，繁聲發夏蟲。", "情鍾正吾輩，匡坐泣薰風。"]'),
('4ac7588e-ce09-4c84-905d-4946f3d746d4','夢回二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','吾宗鮮兄弟，何事日飄零。',48,'全唐诗/poet.song.154000.json','["吾宗鮮兄弟，何事日飄零。", "凋落皆鵷鳳，相從謝鶺鴒。", "世緣那可了，魂夢也非寧。", "屈指傷心事，端如欲曙星。"]'),
('806dcd3e-8fc9-4eb4-9db1-132af4defa90','鄉思','薛季宣','宋','宋诗','song-poetry','','[]','達仕租千石，虛名酒五經。',48,'全唐诗/poet.song.154000.json','["達仕租千石，虛名酒五經。", "豈能千日醉，未勝九年耕。", "識取杯中趣，知從袋裏乘。", "讀書無一事，官宦汩平生。"]'),
('92963fdd-b477-4abc-b035-06734eb7bedd','寒食二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','異縣臨寒食，爲情覺大難。',48,'全唐诗/poet.song.154000.json','["異縣臨寒食，爲情覺大難。", "焄蒿五精氣，破散六祠壇。", "墮淚紛朝雨，回腸減夜餐。", "誰家簫鼓咽，懽舞欲媻跚。"]'),
('608e0940-6581-4aab-96e5-30004c341f8b','寒食二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','五歲懷歸夢，言歸已得歸。',48,'全唐诗/poet.song.154000.json','["五歲懷歸夢，言歸已得歸。", "未能逃俗累，旋復著征衣。", "子貢當何戰，燕人切自悲。", "無堪一百五，春雨作霏微。"]'),
('a1a3480d-c245-4878-b008-38751be47fc5','感事','薛季宣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','狐死正丘首，鳶飛翰戾天。',48,'全唐诗/poet.song.154000.json','["狐死正丘首，鳶飛翰戾天。", "乃知司馬晉，不若慕容燕。", "濟亂須人傑，投機赧世賢。", "長江千古恨，南北幾陳編。"]'),
('dfb5c509-681d-4254-92ff-8cd77162cbe5','鸂鶒','薛季宣','宋','宋诗','song-poetry','','[]','谿𪀸滄江外，雌雄萬里心。',48,'全唐诗/poet.song.154000.json','["谿𪀸滄江外，雌雄萬里心。", "浪花浮彩翠，煙雨弄清音。", "蓼岸無端艷，蓮塘底處尋。", "鴛鴦誰著色，知誤幾金針。"]'),
('a653dda4-87de-4dec-b2ca-aa982c2d940c','讀邸報二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','大漠煙塵靜，三公計畫奇。',48,'全唐诗/poet.song.154000.json','["大漠煙塵靜，三公計畫奇。", "定安唐廟貌，行復漢官儀。", "捷奏騰千里，除書滿四維。", "自然禽頡利，蚤晚贊無爲。"]'),
('4b329d43-f9b7-4523-9c5f-bb6f158f7811','讀邸報二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','世味刀頭蜜，人情屋上烏。',48,'全唐诗/poet.song.154000.json','["世味刀頭蜜，人情屋上烏。", "榮華葉子格，升黜選仙圖。", "豺祭知生獸，蛇銜欲報珠。", "不將魂夢到，反是憶蓴鱸。"]'),
('dafddcad-7c94-47e7-bfe0-9a2f014cbafb','九月十日菊','薛季宣','宋','宋诗','song-poetry','','[]','不改天香細，無端人意疏。',48,'全唐诗/poet.song.154000.json','["不改天香細，無端人意疏。", "重陽把杯者，今夕尚來與。", "白羽摇依舊，黄裳笑反初。", "知時自凡俗，冷暖欲焉如。"]'),
('327177b0-6188-403b-9c6d-283226cb9e3d','夜聞捷音','薛季宣','宋','宋诗','song-poetry','','[]','圓覺聲聞夜，蒙頭大比丘。',48,'全唐诗/poet.song.154000.json','["圓覺聲聞夜，蒙頭大比丘。", "上功來莫府，如用復東周。", "行即昇平舊，還從汗漫遊。", "憑誰問淮蔡，元濟莫擒不。"]'),
('735b6b11-1288-41c1-849d-c06cfb3cd1f1','悶成','薛季宣','宋','宋诗','song-poetry','','[]','春鳥弄輕微，凝陰滿院飛。',48,'全唐诗/poet.song.154000.json','["春鳥弄輕微，凝陰滿院飛。", "蠶姑云力作，杜宇不如歸。", "世變知音少，人亡解語希。", "汗顔多反仄，濺淚溼單衣。"]'),
('3f374eaa-1e79-4f6d-9def-af350993a6a5','春陰','薛季宣','宋','宋诗','song-poetry','','[]','春晝閣春愁，無情若隠憂。',48,'全唐诗/poet.song.154000.json','["春晝閣春愁，無情若隠憂。", "柔腸牽柳眼，困淚點花頭。", "不放春風度，從教暮雨休。", "哀憐無限意，小畜閔黄州。"]'),
('4764ee7f-26a9-4448-b600-e28d70adcbcf','燈花','薛季宣','宋','宋诗','song-poetry','','[]','自得天然艷，書窗氣吐虹。',48,'全唐诗/poet.song.154000.json','["自得天然艷，書窗氣吐虹。", "有心惟燭物，無種到施工。", "不管三春候，平分兩曜功。", "報人知喜事，誰辨悉歸空。"]'),
('39472e4e-22d4-4336-99f6-da1fc2ebbf2e','送鄭景望赴國子丞詩二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','風喜檣烏順，知難喚酒杯。',48,'全唐诗/poet.song.154000.json','["風喜檣烏順，知難喚酒杯。", "好溪寒已半，京洛暖應回。", "僧舍方飄雪，江籬欲放梅。", "不須愁國步，之子棟梁材。"]'),
('d24a3ddd-07a0-4417-b778-e259abb93239','送鄭景望赴國子丞詩二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','愾我論交晚，何堪又索居。',48,'全唐诗/poet.song.154000.json','["愾我論交晚，何堪又索居。", "朝陽鳴必鳳，清水察無魚。", "百惱愁成斛，羣疑鬼載車。", "否臧亡可道，贏得腹詩書。"]'),
('f7269fd1-9e21-44b6-9690-c371bbb760f0','送鄭景元赴秀州判官詩','薛季宣','宋','宋诗','song-poetry','','[]','恢炱煽炎毒，萬里無來風。',144,'全唐诗/poet.song.154000.json','["恢炱煽炎毒，萬里無來風。", "殿閣少微涼，況乃陌路中。", "紈扇可把揮，秋高網絲蟲。", "冰山豈足恃，見睍聿消融。", "進退信惟谷，黄塵奈匆匆。", "鄭君冰雪姿，干將依崆峒。", "竭蹶救頭然，巾車佐元戎。", "生人在熾炭，吾何憚爞隆。", "往聞開元帝，逃暑繡嶺宮。", "偪仄政浩歎，木陰見姚崇。", "煩溽頓以消，語識靜勝工。", "相期在此行，山泉養童蒙。"]'),
('2ec670be-505d-4bcc-87a7-adb66b8d651a','兄子象先罷公試歸知武林動靜成古風三首  其一','薛季宣','宋','宋诗','song-poetry','','[]','黄庭有真詣，魂升魄入淵。',48,'全唐诗/poet.song.154000.json','["黄庭有真詣，魂升魄入淵。", "知機動以食，還反道自然。", "嘗聞鍊色石，可用補蒼天。", "時哉復時哉，寧教悔在前。"]'),
('438fcd64-f194-45ce-9c26-6f7705d865ec','兄子象先罷公試歸知武林動靜成古風三首  其二','薛季宣','宋','宋诗','song-poetry','','[]','野鶴入雞羣，猨豈王孫輩。',48,'全唐诗/poet.song.154000.json','["野鶴入雞羣，猨豈王孫輩。", "之人定忘物，未足言身世。", "丹山兩鳳皇，爲誰來噦噦。", "靈龜發與肣，可以卜隆殺。"]'),
('379384ef-6873-4d19-aba4-82d6cbb77aed','兄子象先罷公試歸知武林動靜成古風三首  其三','薛季宣','宋','宋诗','song-poetry','','[]','明珠以彈雀，得雀亦亡珠。',48,'全唐诗/poet.song.154000.json','["明珠以彈雀，得雀亦亡珠。", "颺鶩以當鷹，夫豈獵之徒。", "黄金有定價，韞櫝盍藏諸。", "薰風扇餘涼，吾方愛吾廬。"]'),
('565f1b4a-1cb2-4896-a445-3d4c75283290','元夜齋居','薛季宣','宋','宋诗','song-poetry','','[]','元夜憶年時，忘情居灝灝。',144,'全唐诗/poet.song.154000.json','["元夜憶年時，忘情居灝灝。", "縣齋今夕居，曷謂傷懷抱。", "都緣人事非，不足年時好。", "世母舍我歸，屈指憂吾老。", "人亡不可見，此心爲草草。", "大人月云忌，棄我方兒褓。", "呱呱救嬰泣，安知請丘禱。", "諸父洎諸兄，下世吁何早。", "悲傷失所恃，涕淚流行潦。", "哀思動時節，不見蓮燈好。", "鄉居計日長，松楸倩誰埽。", "諸母侍何期，念舊呼穹昊。"]'),
('3785e284-7108-4873-ba7c-92ea3112f26a','春雨','薛季宣','宋','宋诗','song-poetry','','[]','春雨不知止，新晴旋復陰。',144,'全唐诗/poet.song.154000.json','["春雨不知止，新晴旋復陰。", "霏霺散秋毫，虛簷水鳴琴。", "琤瑽響疏窗，庭除有餘音。", "跬步莫可縱，蒼苔看侵淫。", "縣齋知幾秋，中堂漏相尋。", "涓涓濺人衣，黯黯乏勝襟。", "發策漫如漬，明眸暗沈吟。", "翛然薄雲開，風聲到園林。", "坐覺筠筀芽，羅鞭粲修森。", "巾車過坊市，溝渠漲江潯。", "言歸轉通渠，舉頭見西岑。", "峰青霧銜白，何堪送迎心。"]'),
('6627ab5c-e03d-44e0-8749-fbb5acad7534','春江小雨','薛季宣','宋','宋诗','song-poetry','','[]','小雨春風裏，澄江滿漲痕。',48,'全唐诗/poet.song.154000.json','["小雨春風裏，澄江滿漲痕。", "沙平波渺渺，山遠霧昏昏。", "短棹煙塵細，浮雲天地根。", "將迎倦無已，羞目舊杯尊。"]'),
('cc977945-1743-49a9-bc9a-d952f258d886','春雨','薛季宣','宋','宋诗','song-poetry','','[]','春光不滿百，霧雨六旬强。',96,'全唐诗/poet.song.154000.json','["春光不滿百，霧雨六旬强。", "眠蠶老脫殻，壠麥青已黄。", "愁雲密可厭，慘澹空滄茫。", "銅盤旦日出，障彼天一方。", "寒簇歎巧婦，麰蛾會飛虻。", "豐隆況忱祠，離畢占是常。", "庚午直及申，此意未遽央。", "使客困羈役，行留兩亡羊。"]'),
('c9c18658-4cea-48dc-8696-b38b1847ceb3','雨中鶴唳','薛季宣','宋','宋诗','song-poetry','','[]','陰靄結愁思，秋霖政霪澍。',96,'全唐诗/poet.song.154000.json','["陰靄結愁思，秋霖政霪澍。", "何天唳鳴鶴，嘹喨烏雲路。", "九皋聲甚遠，底處披冥霧。", "定知君子化，不作乘軒汙。", "介蟣六王師，櫛沐方暴露。", "芻輓苦不繼，曷保金湯固。", "塗泥困淪沒，無計開樊笯。", "傷古聽華亭，吾心向誰布。"]'),
('f0e1e4e9-e505-440f-b288-2c65beff9d98','種蘭','薛季宣','宋','宋诗','song-poetry','','[]','蘭生林樾間，清芬倍幽遠。',120,'全唐诗/poet.song.154000.json','["蘭生林樾間，清芬倍幽遠。", "野人坐官曹，茲意極不淺。", "西窗蔽斜日，松釵架春晚。", "牆陰蒔花木，憔悴根日損。", "植此山谷香，坐與前事反。", "扶疏可紉佩，心緒端有本。", "芽生僅盈壇，高風成九畹。", "羣芳顔色好，祇自誇園苑。", "何如淡嚼蠟，草莽曾誰混。", "對我靜無言，忘形如苯䔿。"]'),
('a2d91447-6243-4350-b38f-ac99a86b1b5b','讀東坡和靖節詩','薛季宣','宋','宋诗','song-poetry','','[]','我讀淵明詩，頗識詩外意。',144,'全唐诗/poet.song.154000.json','["我讀淵明詩，頗識詩外意。", "坡公繼逸響，箇中有佳思。", "取友百世上，古來獨二士。", "陶固泉石人，蘇則廊廟器。", "出處了無同，聲名都自異。", "往來不可作，矧復通姓字。", "神交定忘形，飲食尚知味。", "蕤賓中聲律，片鐵猶應類。", "茲文在尼父，爲復昌旦事。", "今時道古語，莫作今世視。", "以我思惟心，充彼剛大氣。", "芥子納須彌，誰信略相似。"]'),
('77e47455-1339-43fe-863b-9aec7d4048eb','欣木亭詩','薛季宣','宋','宋诗','song-poetry','','[]','寒威折青陽，雲雨作朝暮。',72,'全唐诗/poet.song.154000.json','["寒威折青陽，雲雨作朝暮。", "槎牙粲新綠，寂歷晴川樹。", "時至物皆春，豈在雲間露。", "之人止亭上，笑歌誰與晤。", "睠此榮與華，我亦知嘉孺。", "來游對溪山，識取亭中趣。"]'),
('59c3132e-8c88-417d-a472-99d1e9bc263d','早起次叔瞻韻','薛季宣','宋','宋诗','song-poetry','','[]','日高政好眠，披衣意何已。',96,'全唐诗/poet.song.154000.json','["日高政好眠，披衣意何已。", "不得戀黄紬，弩頭非所喜。", "厭浥行露多，忘却佳山水。", "有客愛閒居，被髮吟早起。", "神清到天元，靜極照物始。", "公乎尚何其，我亦偶然耳。", "此事叵立談，剝剝自鳴指。", "動息無端環，生人定一理。"]'),
('5bbdacc2-f65b-42a3-86ad-79a2a131a3bc','聞競渡聲','薛季宣','宋','宋诗','song-poetry','','[]','江頭閙金鉦，競渡記時序。',96,'全唐诗/poet.song.154000.json','["江頭閙金鉦，競渡記時序。", "欲弔大夫魂，正則知何許。", "情緣古今隔，況是都無楚。", "悲歌永爲戲，拯溺憑誰語。", "曰我舊家鄉，湖上人如堵。", "船戰習成風，迎神尚投黍。", "家居內忘物，廢聽何城阻。", "風聞不貳事，借問爲情緒。"]'),
('aa67f2d6-afe9-4c54-b304-20811a1a28d2','冬至和燠酴醿有華','薛季宣','宋','宋诗','song-poetry','','[]','我愛酴醿花，爛漫春歸後。',132,'全唐诗/poet.song.154000.json','["我愛酴醿花，爛漫春歸後。", "熏爲美人佩，韻勝青州酒。", "溰漼落霜霰，摇曳欹風柳。", "別來能幾時，夢寐依三后。", "一綫長新陽，萬木新凋朽。", "佳期尚云遠，盛意胡偏厚。", "秀色笑江梅，遊絲入窗牖。", "遥知此粲者，爲瑞朝中否。", "銀蟾待交映，天上彤雲久。", "金樽但高酌，身外閑愁剖。", "休言桃李華，常暘又何咎。"]'),
('e69191b5-8145-4820-90d3-3ea1e4fdb35a','刈蘭','薛季宣','宋','宋诗','song-poetry','','[]','東畹刈真香，靜院簪瓶水。',48,'全唐诗/poet.song.154000.json','["東畹刈真香，靜院簪瓶水。", "高遠不勝情，時逐微風起。", "和雨剪閑庭，誰作騷人語。", "記得舊家山，香來無覓處。"]'),
('d0ff02ff-7452-4ca2-83c1-a94d7041d7ba','石盆','薛季宣','宋','宋诗','song-poetry','','[]','髯翁久埋沒，歲月來成奔。',168,'全唐诗/poet.song.154000.json','["髯翁久埋沒，歲月來成奔。", "當年膾魚處，齏臼徒形存。", "想方高會時，猛士侔雲屯。", "連鰲覬一釣，欲以大口吞。", "尺鯽剉紅雪，烹葵植蘭蓀。", "王餘棄玉食，銀刀亂洄沄。", "墮臺不禁醉，網漏如鯨鯤。", "座中盡羣彥，人亡失叢墦。", "吾遊懷此都，重到郭外村。", "聊興廣武歎，徘徊受辛盆。", "頹然鳳凰臺，路走臨津門。", "催歸趁人馬，誰念古帝魂。", "愁無有力者，窊樽負雲根。", "斯焉共杯飲，垂綸具盤飧。"]'),
('793f9e38-2a4a-4fbb-a9df-fc1796f81d7c','止齋和七五兄次淵明止酒詩韻','薛季宣','宋','宋诗','song-poetry','','[]','知止良獨艱，吾兄獨安止。',120,'全唐诗/poet.song.154000.json','["知止良獨艱，吾兄獨安止。", "不止郊園外，只止塵埃裏。", "脩爲止至善，孝愛止爲子。", "眷言兄止之，得止以爲喜。", "至止內泓澄，非心止弗起。", "止靜有餘歡，止中得妙理。", "勿謂止爲難，止躬徒正己。", "止乎吾未見，致知知止矣。", "兄乎止孰似，兄止無端涘。", "艮止視兼山，止斯千萬祀。"]'),
('26a9fac1-aafb-43e2-9140-e235f83e7f60','重陽無菊','薛季宣','宋','宋诗','song-poetry','','[]','二九節重陽，高風振羣木。',96,'全唐诗/poet.song.154000.json','["二九節重陽，高風振羣木。", "彼菊東籬下，金英粲清馥。", "中有黄裳美，雅稱清人服。", "歲旱靡百草，芽蘗渠能育。", "冷淡登高會，悵望矧可復。", "空酌茱萸酒，帽墮慵舉目。", "愧乏淵明流，誠爲淵明縮。", "借使淵明在，淵明更悽蹙。"]'),
('c0d40672-8c68-4070-99f6-dd0f2f0c2158','九月猶煖梅桂有華','薛季宣','宋','宋诗','song-poetry','','[]','兩雄不並時，丹芍彼春芳。',84,'全唐诗/poet.song.154000.json','["兩雄不並時，丹芍彼春芳。", "同仁乃一視，梅桂華秋暘。", "梅固冰玉姿，桂不時世裝。", "永言異會遇，相從多異香。", "瑣屑辟寒金，磊落明夜光。", "仙人姑射山，墨允期首陽。", "神交際道義，語默何曾常。"]'),
('65342b7f-146b-4d4b-ab9a-cf4542a089ab','患盜','薛季宣','宋','宋诗','song-poetry','','[]','盜賞自孤卿，布亡由令尹。',108,'全唐诗/poet.song.154000.json','["盜賞自孤卿，布亡由令尹。", "政刃可同形，殺人在同殞。", "吾非古之徒，處世良不盡。", "仁義一蘧廬，身心兩矛盾。", "坐使邑中民，嗷嗷困饑窘。", "劫質與穿窬，公行載歸稛。", "道路視秦越，對此獨何忍。", "刑德歎誰施，茫洋空內愍。", "仲尼有佳對，爲發一笑辴。"]'),
('50819b1a-5676-4f0a-851d-e98d6a259a11','又和元可二篇  其一','薛季宣','宋','宋诗','song-poetry','','[]','陽春倡者誰，欲和心已闌。',180,'全唐诗/poet.song.154000.json','["陽春倡者誰，欲和心已闌。", "故鄉渺千里，念之一辛酸。", "人生足離合，豈在共盤餐。", "胡然兒女情，苛留太無端。", "焉得不繫舟，使我懷抱寬。", "信美非吾家，會且即所安。", "後園桃李秋，蕪徑草木繁。", "酒來輒竟醉，歌强難爲歡。", "風雨打寒食，枯河盡瀰漫。", "故乏猜嫌累，誰能整其冠。", "惟當適意爾，曷貴呂極官。", "晉賢泣楚囚，衛女賦竹竿。", "願君憫羈思，所友路何曼。", "歸哉昔在陳，孔聖乏體胖。", "幸非艱棘徒，亦復謝欒欒。"]'),
('5bc5ae5f-39a5-45e6-91e7-2a11b934438c','又和元可二篇  其二','薛季宣','宋','宋诗','song-poetry','','[]','春風動鄉情，燈火語夜闌。',180,'全唐诗/poet.song.154000.json','["春風動鄉情，燈火語夜闌。", "遥聞流星遞，鈴響接悲酸。", "愁人念世事，臨食或忘餐。", "我有無價珠，可以息爭端。", "致君昭代隆，坐使北顧寬。", "何當內修治，邇服遠自安。", "呢呢兒女子，青蠅語喧繁。", "長懷不盡憂，可若一笑歡。", "有酒且强醉，莫等白露漫。", "汾陽脫兜鍪，高祖溺儒冠。", "此意詎未央，抱關樂卑官。", "匡牀足酣眠，紅日出三竿。", "睠言東甌道，來歸路曼曼。", "非行徒爾爲，寂默體用胖。", "天地一大家，中庭樹欒欒。"]'),
('ccaeda96-1512-42c3-a656-a99bb115c4ce','得符速走之官','薛季宣','宋','宋诗','song-poetry','','[]','我本樂閑人，自得安閑志。',288,'全唐诗/poet.song.154000.json','["我本樂閑人，自得安閑志。", "鄙性習疏散，誰識榮華意。", "朅來復舊廬，喜獲平生志。", "稼穡任佃夫，家室歸中饋。", "中外若非我，卒歲無他事。", "飽飯讀詩書，瞢騰時困睡。", "嘲啁燕雀懽，鴻鵠心應異。", "三皇竟何物，況復今官寺。", "寒餒譟妻孥，先春輸典質。", "茲乃不可常，爲貧求祿仕。", "版籍一書名，野情那得遂。", "官來促我裝，去作塵埃吏。", "無復有消摇，真爲口腹累。", "把板從此行，短褐隨棄寘。", "素餐良不堪，邑有民人寄。", "衆心險山川，道微非所暨。", "上恐負朝家，終念家聲墜。", "吾民政焦嗷，爲此不能寐。", "格物可爲邦，舊說今難試。", "泥古誠腐儒，惟此知爲治。", "仁義舍不爲，又敢圖與利。", "上官如我容，刑章得就易。", "庶以遂其生，將久蘇疲瘁。", "此意尚茫然，思之或狂悖。"]'),
('81c06c79-e36f-40f2-a7c2-556cd1c99652','谿𪀸','薛季宣','宋','宋诗','song-poetry','','[]','谿𪀸何翩翩，鎮日煙波裏。',84,'全唐诗/poet.song.154000.json','["谿𪀸何翩翩，鎮日煙波裏。", "將奈網羅何，幽閑從此始。", "一爲美人玩，毛羽慵復理。", "江湖浩蕩意，憔悴蹄涔水。", "昔是滄溟遊，今是樊笯底。", "文章豈是貴，步武難無已。", "丈夫感茲念，心逐冥鴻起。"]'),
('2b398903-7802-4ba4-a5f0-7065cc65ca45','社後即事','薛季宣','宋','宋诗','song-poetry','','[]','東君識歸意，社雨零齋沐。',48,'全唐诗/poet.song.154000.json','["東君識歸意，社雨零齋沐。", "柳眼向人青，草芽隨地綠。", "體輕來燕疾，聲合鳴蛙矗。", "桃李靜無言，艷麗驚郎目。"]'),
('6a7e856c-2a04-41b9-8edd-f16d19280c97','西山野步','薛季宣','宋','宋诗','song-poetry','','[]','雨夏作晴天，浮雲带溶洩。',144,'全唐诗/poet.song.154000.json','["雨夏作晴天，浮雲带溶洩。", "西山旦驅馬，踏破蒼崖翠。", "寒泉漲新綠，决决鳴環佩。", "上有吳郊畤，九曲羊腸細。", "築閣聽松風，縹渺江無際。", "野僧喜客來，一見心已醉。", "竹萌薦盤餐，玉切琅玕碎。", "吟哦壁間詩，恍與古人對。", "時發一笑粲，韶聞殆忘味。", "清遊淡何營，不知夕將至。", "岸巾步箬谷，欲往叵自遂。", "酌此菩薩泉，爲澣濯惡世。"]'),
('a89020e1-852d-42b9-a3d6-07c0e2f549fa','陳思王','薛季宣','宋','宋诗','song-poetry','','[]','喬松産崇岳，託迹太高亢。',96,'全唐诗/poet.song.154000.json','["喬松産崇岳，託迹太高亢。", "飄摇風雪場，踡局蛟龍狀。", "干霄竟何事，勁節良獨壯。", "下有楸桐秀，遠入煙霞望。", "天意固有在，人情亦云妄。", "苦乏柔苗蔭，直傲清霜量。", "居然嗟彼其，坐使出其上。", "至哉文身子，三以天下讓。"]'),
('f547858a-5697-4710-ab6c-252df1f761c2','步抵東坡登舟返石門','薛季宣','宋','宋诗','song-poetry','','[]','爲到西陽城，侘傺東坡上。',132,'全唐诗/poet.song.154000.json','["爲到西陽城，侘傺東坡上。", "舊址就荒蕪，山川寫心匠。", "四見聳高寒，周遭畫屏障。", "萬象儼朝昏，出沒煙霞狀。", "玄覽浩無涯，不覺滄溟漲。", "吾行半南州，此遊誠大壯。", "寸陰良可惜，無奈歸船舫。", "隤然快哉亭，昔夢今知妄。", "吳都一回橈，杯飲漥樽浪。", "石門隠漁舍，行復殊亭創。", "扣竭兩端倪，便可齊得喪。"]'),
('20ebfac1-4237-43d3-b09d-f2599ea51c23','邊事方急有中使至雨中出郊候之','薛季宣','宋','宋诗','song-poetry','','[]','霧雨閣天愁，胡笳閙人耳。',96,'全唐诗/poet.song.154000.json','["霧雨閣天愁，胡笳閙人耳。", "不見霍票姚，只見黄塵起。", "蔣城何岧嶢，橫流混淮水。", "教戰鬨市人，旋柵荒殘壘。", "甲道軒脩竹，亭觀羅弓矢。", "長城萬里壞，衣带江誰恃。", "櫜鞬道左立，一介來行使。", "束带迎督郵，淵明尚深恥。"]'),
('25c63ef9-62ff-4c2f-9e58-fc47f3faff2b','春陰會聞懸瓠不守','薛季宣','宋','宋诗','song-poetry','','[]','飄風吹百花，仰不見天幕。',96,'全唐诗/poet.song.154000.json','["飄風吹百花，仰不見天幕。", "浮雲何慘慘，去我止一握。", "園樹暗無色，紅芳旋凋落。", "摘索晚來雨，如絲度城郭。", "愁人故多情，對此乃非樂。", "羽書絳囊馳，傷春重沈著。", "方鎬若涇陽，龍吟怨清角。", "歸飛內提提，紇真問生雀。"]'),
('bed9d5c0-226b-4463-86b6-1267693d5ee4','雪蛆','薛季宣','宋','宋诗','song-poetry','','[]','冷冷雪中蛆，皎皎夏之日。',84,'全唐诗/poet.song.154000.json','["冷冷雪中蛆，皎皎夏之日。", "藉彼凌厲地，生此柔脆質。", "冰山共攸遠，玉筯無定匹。", "安識時有暑，但保歲云慄。", "中和歎何居，已熱信所必。", "火鼠可澤浣，朝菌寧晚出。", "伯翳爲更名，山經注遺逸。"]'),
('f66951ee-e7e4-42ff-864e-66ece851fb31','新作殊亭','薛季宣','宋','宋诗','song-poetry','','[]','虎將夏中時，旋復怡亭址。',120,'全唐诗/poet.song.154000.json','["虎將夏中時，旋復怡亭址。", "茅茨覆采椽，樸拙亦可喜。", "建斗五移杓，殊亭更釋子。", "規摹雖少華，不陋復不侈。", "元碑碎俗令，遺集裒空紙。", "縱步此山椒，金聲猶屬耳。", "舊亭苦弗稱，新亭直殊美。", "書文兩奇絕，蹤蹟存布指。", "古人久不見，今人尚殊此。", "能知古今意，元始本無始。"]'),
('d4e63642-d666-45e2-808c-240dc1aeb8f4','又讀陶靖節詩即次前韻傚其體  其一','薛季宣','宋','宋诗','song-poetry','','[]','濁酒自傾盡，陶然忘古今。',48,'全唐诗/poet.song.154000.json','["濁酒自傾盡，陶然忘古今。", "橫琴寄逸響，聊以寫我心。", "矯矯兩白鵠，盤旋下曾林。", "此情誰與傳，無弦有遺音。"]'),
('eda0a213-55f4-4937-a804-7254ae77c34f','又讀陶靖節詩即次前韻傚其體  其二','薛季宣','宋','宋诗','song-poetry','','[]','萬籟夕已息，寧知身是今。',48,'全唐诗/poet.song.154000.json','["萬籟夕已息，寧知身是今。", "浮雲翳青空，油然起無心。", "寄傲北窗下，驟雨落疏林。", "遊子爲三歎，寥寥希大音。"]'),
('f0d9e24c-ec2e-43b0-b65b-bf68d33088d1','開渠','薛季宣','宋','宋诗','song-poetry','','[]','開渠引簷溜，涓涓遶茅楹。',84,'全唐诗/poet.song.154000.json','["開渠引簷溜，涓涓遶茅楹。", "政爾江河流，鏘如環佩聲。", "澄瀾漾淪漪，曲甃隨淺清。", "上有翔飛蚋，無殊化摶鵬。", "廣狹詎易量，大小終强名。", "何從汎天潢，同歸在寰瀛。", "吾慚論齊物，揚波歎平生。"]'),
('172e3394-76b4-4764-92dc-3c59938b0825','瓜期代者不至','薛季宣','宋','宋诗','song-poetry','','[]','禽飛有倦時，木落還逢春。',48,'全唐诗/poet.song.154000.json','["禽飛有倦時，木落還逢春。", "薄遊名利場，厭見陌路塵。", "指日得終更，□情難重陳。", "如此代者何，不至愁吾人。"]'),
('88fd6895-6610-40a4-83c2-d940b7c291f7','代者介至','薛季宣','宋','宋诗','song-poetry','','[]','縣道簡書密，束身急于繩。',156,'全唐诗/poet.song.154000.json','["縣道簡書密，束身急于繩。", "況復多難時，匈奴亟憑陵。", "憂危內外競，凜若憑春冰。", "鞭笞苦不痛，何卹寡與矜。", "初心豈得在，反身但兢兢。", "安得事大好，官籍知有承。", "屈指計來月，瓜期閏云增。", "彼乃未易到，吾行重難能。", "百里半九十，終更訒階升。", "社雨晚來急，春天霧夢夢。", "清淮萬胡馬，咫尺方沸騰。", "朞年念天遠，歸飛恨無䎖。", "慇懃謂典吏，用之筆緘縢。"]'),
('419492f8-550a-42de-ace5-9875dff3a002','袁山春望','薛季宣','宋','宋诗','song-poetry','','[]','密雨作春社，袁山暫登臨。',132,'全唐诗/poet.song.154000.json','["密雨作春社，袁山暫登臨。", "迎人多野花，對鏡諧道心。", "于以今日態，而開去年林。", "平沙沒浩蕩，漲水相浮沈。", "草綠湖萬頃，峰青天一尋。", "無情雲自閑，此理吾難任。", "故壘雉明玉，寒溪疊重岑。", "朅來聽流泉，可用資鳴琴。", "新霽石磴滑，崩波馬蹄肣。", "不知日已暮，迂回樹生陰。", "歸路尚修阻，時哉羨靈禽。"]'),
('c53564f2-fac1-4253-92bd-6060061d3baf','重陽馬上看菊','薛季宣','宋','宋诗','song-poetry','','[]','秋菊粲真色，落若千金巵。',84,'全唐诗/poet.song.154000.json','["秋菊粲真色，落若千金巵。", "對此好時序，馨香散幽奇。", "爛漫在伊昔，邂逅不可期。", "吾來倦逢迎，玄黄馬常馳。", "二子復何事，相從意熙熙。", "奔走塵埃間，一見蹙我眉。", "嚮之念佳賞，慙顔朵人頤。"]'),
('28cf7b15-d056-4c01-937e-8f55c6f7d4d8','浮槎','薛季宣','宋','宋诗','song-poetry','','[]','浮槎爾喬木，來從何處村。',132,'全唐诗/poet.song.154000.json','["浮槎爾喬木，來從何處村。", "託迹久非地，湍水撞其根。", "一辭古岩頭，去去隨潺湲。", "上有飛鷺翔，下有白浪翻。", "浪激信反覆，鷺去無回騫。", "十浮將九沈，任彼回風掀。", "飄泊未云已，驚落見者魂。", "今憑逝川波，故憑川上原。", "原中復何有，草木故自蕃。", "洄流潰前汀，薄命乃獨存。", "人生盡如此，株木奚足論。"]'),
('c30bfd1e-6bcf-4b7b-abbf-56b4a40a731e','雪','薛季宣','宋','宋诗','song-poetry','','[]','太素欲還淳，熙然萬物春。',120,'全唐诗/poet.song.154000.json','["太素欲還淳，熙然萬物春。", "封條花爛漫，飛絮柳紛繽。", "玉殿神光發，金樓火色新。", "簷高天漢接，地遠蜀江瀕。", "西塞雲填谷，南湖浪拍漘。", "吠厖欣掉尾，饑鳥困依人。", "躡屣蹤存齒，翻車堊到輪。", "窗開羅岫失，檻倚鑿池堙。", "鑪炭情偏愜，冰壺意亦親。", "郢歌休待和，大化席紛紛。"]'),
('850f5e4b-4e8e-4786-bd83-0c3a2c690293','桃花','薛季宣','宋','宋诗','song-poetry','','[]','桃花如美人，靜有嬌春態。',84,'全唐诗/poet.song.154000.json','["桃花如美人，靜有嬌春態。", "醉眼奈愁何，多情破新睡。", "裝成開笑靨，天裊腰支細。", "不語傍斜陽，鵠立塵寰外。", "煙遠鎖眉顰，東風羞娬媚。", "倏然歎零落，灼灼無窮意。", "會訪武陵源，一飲流霞味。"]'),
('1c9ced91-4252-4f16-aafe-a9b07c078e22','春陰三首  其一','薛季宣','宋','宋诗','song-poetry','','[]','春陰一何甚，愁結窗外花。',204,'全唐诗/poet.song.154000.json','["春陰一何甚，愁結窗外花。", "細雨打疏竹，娟娟草新芽。", "眷此忽中慘，吾生浩無涯。", "閑讀几上書，可歎復可嗟。", "時流諒難追，世路亦已賒。", "折腰墨綬卑，坐有憂患加。", "官柳粲新綠，黄鸝語淫哇。", "把盞但心醉，天外日已斜。", "魄月沈半壁，歸飛噪啼鴉。", "仰頭望虛碧，冥冥密雲遮。", "風塵政昏暗，逃形乏浮槎。", "顧影還自笑，狂遊蕩無家。", "弩頭强應世，鈍若倒拔蛇。", "先人營舊廬，清池傍蒹葭。", "芳時繡文錦，翻濤散晴霞。", "霽色故自好，風霾益云嘉。", "何當舍此去，忘情傲丹葩。"]'),
('cab51857-6919-40ba-b228-63a0dbe72662','春陰三首  其二','薛季宣','宋','宋诗','song-poetry','','[]','逼社窘陰雨，園花就凋零。',144,'全唐诗/poet.song.154000.json','["逼社窘陰雨，園花就凋零。", "翩翩蝶翅重，好鳥無一鳴。", "山頭霧露白，簷前砌苔青。", "旁瞻隔遠到，內與愁思并。", "縣小文書省，氍茵匝莎庭。", "舉頭歎世事，坐有百感生。", "芳林墮玉蕊，垂楊結珠纓。", "傷春復已半，忽忽難爲情。", "朅來發書簀，悼往心自冥。", "袖手一凝竚，意逐飛鳶行。", "中原政紊亂，悲角揚哀聲。", "有酒不解飲，何以解我酲。"]'),
('bfd7efb7-6c98-4234-9331-10daeb141fed','春陰三首  其三','薛季宣','宋','宋诗','song-poetry','','[]','社雨打春色，催落枝上花。',96,'全唐诗/poet.song.154000.json','["社雨打春色，催落枝上花。", "天風振疏篁，離披亦云嘉。", "爲此念疇昔，官曹掇餐霞。", "幕蒼遠夢夢，寰中感生涯。", "落花故有時，摻摻筍當芽。", "芳菲日已老，吾遊路何賒。", "宇宙一悽慘，桑榆未還家。", "詩情不自禁，荒園鼓新蛙。"]'),
('1fede287-e49d-4404-87d2-45f82c5b4c66','讀靖節詩','薛季宣','宋','宋诗','song-poetry','','[]','淵明鳴素琴，無弦有遺音。',60,'全唐诗/poet.song.154000.json','["淵明鳴素琴，無弦有遺音。", "善聽非子騫，寥然賞知心。", "聲滿天地間，清越窮幽深。", "游魚漾澄瀾，宿鳥投故林。", "忘肉爲聞韶，羲皇到于今。"]'),
('cf0b492c-f271-45ec-9754-5fa54c6f2a8d','跋東坡詩案','薛季宣','宋','宋诗','song-poetry','','[]','南方有佳木，遠在漲海涯。',120,'全唐诗/poet.song.154000.json','["南方有佳木，遠在漲海涯。", "沈水産其節，雞舌生其肌。", "結根松柏場，龍腦實離離。", "蜑獠豈知貴，斧斤斬欒枝。", "椓爲糠粃槽，將食犬與狶。", "條枚惡鬈曲，芟除棄江湄。", "滄流蕩回波，不與朽壤期。", "年代知幾閲，愈久乃見奇。", "根株到餘瀝，復恐分寸遺。", "終焉盛芬烈，蘭蓀謝芳姿。"]'),
('428a9448-8652-4225-9428-9fc100fa2deb','還返釋言  其一','薛季宣','宋','宋诗','song-poetry','','[]','先天有真數，八卦因皆九。',48,'全唐诗/poet.song.154000.json','["先天有真數，八卦因皆九。", "升降周六虛，利見龍無首。", "後天奉天時，不在先天後。", "得一定存三，玄中急須守。"]'),
('6b4b98c2-ef03-442a-9761-f93c99317d51','還返釋言  其二','薛季宣','宋','宋诗','song-poetry','','[]','道人與我言，熬水可丹成。',48,'全唐诗/poet.song.154000.json','["道人與我言，熬水可丹成。", "陰陽忖節度，金玉爭精明。", "問之誰因爾，惟言火力停。", "毫釐謬以消，造物亦何情。"]'),
('f32d5e88-4eb3-459d-b6fe-3c6c258ec071','還返釋言  其三','薛季宣','宋','宋诗','song-poetry','','[]','揉木以爲輪，寘之溪之干。',48,'全唐诗/poet.song.154000.json','["揉木以爲輪，寘之溪之干。", "微流蕩輪輻，銀濤立飛翻。", "三田接餘潤，九穀歸其根。", "灌溉有如此，愆陽何足論。"]'),
('ed45b948-e5b0-4355-ae86-a508bfa4aacc','還返釋言  其四','薛季宣','宋','宋诗','song-poetry','','[]','接竹引巖泉，遠在寒谷幽。',48,'全唐诗/poet.song.154000.json','["接竹引巖泉，遠在寒谷幽。", "然炬火其端，高飛北山頭。", "可以活三軍，梅林意悠悠。", "倒置未爲戾，見之復何求。"]'),
('93e168aa-f908-4369-b652-0ef33a768034','還返釋言  其五','薛季宣','宋','宋诗','song-poetry','','[]','陶甓與鎔金，火出資堅久。',48,'全唐诗/poet.song.154000.json','["陶甓與鎔金，火出資堅久。", "炭木已焚如，萬祀長不朽。", "功成在鑪竈，鑪竈憑何有。", "不見古軒轅，鍊寶荆山首。"]'),
('da618c92-fae6-4b3f-b3af-1b1ea444a8c2','還返釋言  其六','薛季宣','宋','宋诗','song-poetry','','[]','嘗聞曾子書，金火中外明。',48,'全唐诗/poet.song.154000.json','["嘗聞曾子書，金火中外明。", "圓方遞含施，二景參黄庭。", "天端月虧盈，宛在日之情。", "誰何液渾金，坩鍋置煎烹。"]'),
('888452fd-d4b5-451b-90a1-8eab8423fa15','還返釋言  其七','薛季宣','宋','宋诗','song-poetry','','[]','律管實葭灰，氣至颯以升。',48,'全唐诗/poet.song.154000.json','["律管實葭灰，氣至颯以升。", "日至冪寒泉，水花結輕冰。", "應候固應然，違天亦何能。", "時哉復時哉，尺璧定自輕。"]'),
('f15ef38f-839a-4889-a92c-03388f9f8620','還返釋言  其八','薛季宣','宋','宋诗','song-poetry','','[]','襄陽庫露真，木器塗髹漆。',48,'全唐诗/poet.song.154000.json','["襄陽庫露真，木器塗髹漆。", "髹漆厚以堅，札去移凡質。", "蕃戎豈不詐，信是真山出。", "所以蛇化龍，頭角非曩日。"]'),
('523d3592-6e9d-443b-ac81-098c1eb5c6a3','還返釋言  其九','薛季宣','宋','宋诗','song-poetry','','[]','苟晞有逸牛，往返日千里。',48,'全唐诗/poet.song.154000.json','["苟晞有逸牛，往返日千里。", "烹之剖其脊，比竹雙筋起。", "强力有由然，物性都如此。", "本立而道生，人身有真理。"]'),
('442c1ce8-6152-4048-a136-517ead0cdabb','還返釋言  其一○','薛季宣','宋','宋诗','song-poetry','','[]','蚨血可還錢，書符能已瘧。',48,'全唐诗/poet.song.154000.json','["蚨血可還錢，書符能已瘧。", "感召有如斯，還丹非外作。", "得意以忘言，象數求還錯。", "無爲四時行，天遊有真樂。"]'),
('a0394193-0290-4c4f-b706-5677735f8bbc','樊口候參政暮歸','薛季宣','宋','宋诗','song-poetry','','[]','摇兀孤舟東復西，飆從赤鼻下樊溪。',64,'全唐诗/poet.song.154000.json','["摇兀孤舟東復西，飆從赤鼻下樊溪。", "驚鱗斜日銀刀亂，飛鵠滄波羽扇低。", "江漲清泠舞洄洑，岸頹浩蕩汩塵泥。", "黄昏盪槳窊樽上，笑指天閨認沐鷖。"]'),
('51f1a4ff-cc6e-4083-8c89-608b695e705c','聞中司還旆清旦踰樊嶺候之不遇自黄子磯乘舟而歸','薛季宣','宋','宋诗','song-poetry','','[]','萬松晨度馬蹄疾，五水春來湖草長。',64,'全唐诗/poet.song.154000.json','["萬松晨度馬蹄疾，五水春來湖草長。", "官柳弄煙天已曙，山花無人風自香。", "濤痕石磧記江路，檜楫蘭舟摇夕陽。", "送我不如歸去也，啼規夾岸切愁腸。"]'),
('91d94639-b3f9-44d6-9fd8-6eaf19f2acc5','夜憶吳江','薛季宣','宋','宋诗','song-poetry','','[]','虹梁新霽倚東隅，還憶松江枕太虛。',64,'全唐诗/poet.song.154000.json','["虹梁新霽倚東隅，還憶松江枕太虛。", "味比蓴羹下鹽豉，賢爲菰菜憶鱸魚。", "清風帆幔輸歸客，落日蒹葭稱晚漁。", "會带笭箵鎮浮浪，扁舟斜掛一籧篨。"]'),
('3dbd0216-43f3-4013-90bc-1cb1439378b1','過樊山','薛季宣','宋','宋诗','song-poetry','','[]','誰將春信過中江，草木無情取次芳。',64,'全唐诗/poet.song.154000.json','["誰將春信過中江，草木無情取次芳。", "裝罷美人梅破額，愁成行客柳牽腸。", "江灘鑿鑿添新漲，沙塞茫茫反夕陽。", "款段趷梯樊嶺道，幾多畦町雜蒼黄。"]'),
('73a35323-5b60-4434-95e2-18db10ceb1f1','樊山春望','薛季宣','宋','宋诗','song-poetry','','[]','飛出仙人壺外天，壺中日月故依然。',64,'全唐诗/poet.song.154000.json','["飛出仙人壺外天，壺中日月故依然。", "虛明百雉龍鱗動，空翠千巒翡羽鮮。", "咫尺畫圖藏世界，侵尋錦繡簇山川。", "歸來身入寒谿路，恍若瑶林一夢還。"]'),
('68d56322-eaa2-4106-9e14-69758e2a2257','濟江逆田開府過西陽俞氏家林','薛季宣','宋','宋诗','song-poetry','','[]','輕舟時復到齊安，一過俞家一黯顔。',64,'全唐诗/poet.song.154000.json','["輕舟時復到齊安，一過俞家一黯顔。", "江打頹牆開野徑，篁生故壘上家山。", "蕭騷城郭塵埃外，縹渺煙霞雲水間。", "便好繫船終日卧，官曹不許片時閒。"]'),
('125c266c-ef7b-4dd3-8063-f3eb2ed354cd','聞吳王城中軍戍嚴鼓','薛季宣','宋','宋诗','song-poetry','','[]','年時芳草碧蒙戎，聒耳新聞甲夜風。',64,'全唐诗/poet.song.154000.json','["年時芳草碧蒙戎，聒耳新聞甲夜風。", "軍吏誤應非進鼓，天王錫忍廢彤弓。", "剛言苻詔難傾晉，不信文王可伐崇。", "擊柝杜關無箇事，釣臺江月靜朦朧。"]'),
('44f706e5-c53e-4b62-b11c-07082809b0ea','宿大城寺與寺僧行鄀子故城于壁壘間得銅矢鏃土中螺殻往往不壞僧言初作此寺發殿基下有古磚渠宮城中得銅矛矢鏃百數南城中土窖積灰埋鵝首骨猶具自甕城北望有鄀王墓僧云其傍墟塚甚多王墓常有巫者發之未開被蜂毒死巫家于懷袖間得蜂乃黄金所化','薛季宣','宋','宋诗','song-poetry','','[]','二千逆數到春秋，戰國興亡一轉眸。',64,'全唐诗/poet.song.154000.json','["二千逆數到春秋，戰國興亡一轉眸。", "壘壁詎銷埋蚌殻，劫灰寧燼斬鵝頭。", "墳緣開發金成范，殿爲焚修瓦出溝。", "哨矢燋銅傷我意，古來爭戰幾曾休。"]'),
('7060c91b-7333-44ac-8295-9791e017bbed','祈晴車中望安樂宮故址','薛季宣','宋','宋诗','song-poetry','','[]','罷休祈雨又祈晴，天道難知德好生。',64,'全唐诗/poet.song.154000.json','["罷休祈雨又祈晴，天道難知德好生。", "鐘鼓鏗鏘西佛寺，草茅荒穢古王城。", "溫輿即就涼輿便，陰氣潛消煖氣盈。", "棲鳳未堪雲尚密，可人日脚尚微明。"]'),
('3507fcd6-ce0e-46a2-b5dd-adf529333d85','寒食甚雨中泛東舍谿偶晴遊張公石室三首  其一','薛季宣','宋','宋诗','song-poetry','','[]','籧篨煙靄入浮槎，罨畫谿干阿果家。',64,'全唐诗/poet.song.154000.json','["籧篨煙靄入浮槎，罨畫谿干阿果家。", "浩蕩天風飛羽蓋，繽紛法雨落曇華。", "阪懸飲澗猿連臂，魄褫投牢虎落牙。", "豈是仙翁未神聖，笑談爲我放靈鴉。"]'),
('69e242a3-71b9-493f-87f8-649afe7558d2','寒食甚雨中泛東舍谿偶晴遊張公石室三首  其二','薛季宣','宋','宋诗','song-poetry','','[]','天遊無事月中槎，物外仙靈別是家。',64,'全唐诗/poet.song.154000.json','["天遊無事月中槎，物外仙靈別是家。", "老蝠有方精不化，白馿絕迹眩生華。", "竈餘丹藥清毛骨，澗吐清泉厲齒牙。", "回首周郎斬蛟處，晚雲當面舞神鴉。"]'),
('d2c24a06-dc15-4dca-8254-8458e6087f20','寒食甚雨中泛東舍谿偶晴遊張公石室三首  其三','薛季宣','宋','宋诗','song-poetry','','[]','天河重泛客星槎，便好成都訪卜家。',64,'全唐诗/poet.song.154000.json','["天河重泛客星槎，便好成都訪卜家。", "渭水未成浮竹葉，武陵猶記落桃華。", "傳聞鐵騎充牛口，暗想樓船破虎牙。", "濁酒一杯山水綠，棹歌三疊百啼鴉。"]'),
('4aaf13b6-1721-4bf4-b644-7aefa07f2c06','周將軍廟觀岳侯石像二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','萬死何知獄吏尊，威名蓋代古難存。',64,'全唐诗/poet.song.154000.json','["萬死何知獄吏尊，威名蓋代古難存。", "二桃豈爲功高賜，一舸不容身退論。", "幾爲飲江思道濟，繆因圖像削王敦。", "沈碑千古蛟川恨，留與無窮客斷魂。"]'),
('18fe4820-d126-4808-a582-f9b1febe0ad9','周將軍廟觀岳侯石像二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','軍聲良苦聽南風，說禮敦詩也不容。',64,'全唐诗/poet.song.154000.json','["軍聲良苦聽南風，說禮敦詩也不容。", "鬭螘達聰良是病，戰蝸流血可同宗。", "親疏間入聯鑣話，真假言從躡足封。", "趣詔河陽長已矣，隆中悲切起人龍。"]'),
('41e8fb2c-35ce-4331-80c6-6665287d4cbc','雨後','薛季宣','宋','宋诗','song-poetry','','[]','攪人無頼是東風，埽盡春菲一雨中。',64,'全唐诗/poet.song.154000.json','["攪人無頼是東風，埽盡春菲一雨中。", "窗外遠山裝暗綠，眼前佳卉夢新紅。", "梅生樂圃枝如綴，草合誠臺路叵通。", "芍藥牡丹知漸老，折來瓶水翫芳叢。"]'),
('b4e65767-44d0-4999-943f-96098a302064','連日自退谷路抵袁口','薛季宣','宋','宋诗','song-poetry','','[]','晚煙暝雨不勝愁，改日仍爲退谷遊。',64,'全唐诗/poet.song.154000.json','["晚煙暝雨不勝愁，改日仍爲退谷遊。", "司事守田如有意，催歸脫袴感行休。", "連營谷里旌旗暮，細草杯湖荷芰秋。", "果下馬拖泥水去，石頭路滑且夷猶。"]'),
('40a4657b-358c-47e1-ba7b-46782b47b025','雨後憶龍翔寺','薛季宣','宋','宋诗','song-poetry','','[]','好溪東赴海門秋，中有禪居湧碧流。',64,'全唐诗/poet.song.154000.json','["好溪東赴海門秋，中有禪居湧碧流。", "潮信往來雙別嶼，世緣生滅幾浮漚。", "菱歌面面來漁鼓，燈火層層到客舟。", "何事瓜期外留滯，短窗斜雨不堪愁。"]'),
('626141ab-45e0-40cf-83e6-8a9521ba43d7','春遊懷古','薛季宣','宋','宋诗','song-poetry','','[]','登臨一度一傷神，功業蹉跎萬物新。',64,'全唐诗/poet.song.154000.json','["登臨一度一傷神，功業蹉跎萬物新。", "飛鳥遠歸雲外嶺，賞花頻對眼前人。", "茸茸雨脚南郊暮，種種茅鍼太極春。", "鼓掌祇供漁父笑，朅來生水拍江漘。"]'),
('3852b975-f12c-41ff-af3e-b73fba567bb7','寒食遣興','薛季宣','宋','宋诗','song-poetry','','[]','介子龍蛇亦大靈，禁煙猶復雨零零。',64,'全唐诗/poet.song.154000.json','["介子龍蛇亦大靈，禁煙猶復雨零零。", "時風未辦作寒食，春事無過醉醁醽。", "取士語乾三禮穴，延賓爲屈五經瓶。", "明年此日家山路，滄漠從君看水萍。"]'),
('077ec059-cfa7-410c-9b71-cf599b47032f','縣舍酴醿始有開意會走遷居簿廳','薛季宣','宋','宋诗','song-poetry','','[]','芳叢纍纍結珠璣，雨後芬香鬰麝臍。',64,'全唐诗/poet.song.154000.json','["芳叢纍纍結珠璣，雨後芬香鬰麝臍。", "半醉半醒春晝永，載行載笑洞仙迷。", "青蛇眼見遊飛霧，綠綬生愁解佩觿。", "舉袂與君爲此別，幸傳薰德絳囊携。"]'),
('5c0d1930-6c6a-4d25-8b51-d4745a3207f5','落梅','薛季宣','宋','宋诗','song-poetry','','[]','東風一夕報春來，管領羣芳次第開。',64,'全唐诗/poet.song.154000.json','["東風一夕報春來，管領羣芳次第開。", "出岫白雲如有意，照人明月幾難回。", "縞衣聊復歸三島，綠醑無辭舉百杯。", "真味不須談鼎實，等閒誰識鏁梁材。"]'),
('00209f58-6242-43a6-938b-5b047592ed12','折枝水仙','薛季宣','宋','宋诗','song-poetry','','[]','西子苧蘿谿浣紗，李白捉月千丈波。',64,'全唐诗/poet.song.154000.json','["西子苧蘿谿浣紗，李白捉月千丈波。", "風流東迆去不盡，玉釧猶傳金叵羅。", "芰荷蒲荇爭清泚，微香密與和風起。", "可將齋潔祀王明，爲言酌獻持杯水。"]'),
('78306618-4f5f-463c-a41f-0c7067f65268','月下酴醿','薛季宣','宋','宋诗','song-poetry','','[]','噴人清馥偏閒庭，心醉銀釭對醁醽。',64,'全唐诗/poet.song.154000.json','["噴人清馥偏閒庭，心醉銀釭對醁醽。", "高髻月娥呈素面，孤雲天蓋拂明星。", "腰支天裊愁縈緒，玉佩招摇尚典刑。", "著意政須延永夜，新條明日定飄零。"]'),
('983620ec-ba64-4d87-8515-65dad84f1584','和許簿牡丹二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','天與花王化日舒，可堪買酒共提壺。',64,'全唐诗/poet.song.154000.json','["天與花王化日舒，可堪買酒共提壺。", "荒涼洛苑芳菲甚，落寞揚州氣味殊。", "傾國幾迷狂舞蜨，還錢不得迅飛鳬。", "清愁懷抱多春感，一葦懸知此意無。"]'),
('15f2cb75-8962-4b06-9de2-fd2b55d50472','和許簿牡丹二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','清江不解蹋長蘆，悶向花前問玉壺。',64,'全唐诗/poet.song.154000.json','["清江不解蹋長蘆，悶向花前問玉壺。", "秀色可餐誰是伴，濃裝獨立自應殊。", "醉傾鏡外歸鍾酒，飛盡人間幾血鳬。", "多占春風稱第一，檀心知有謝來無。"]'),
('3f14c610-a909-4399-9040-03b256c928f6','復和仲蟠二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','開緘豁豁皺眉舒，一首新詩酒一壺。',64,'全唐诗/poet.song.154000.json','["開緘豁豁皺眉舒，一首新詩酒一壺。", "寒食禁煙春已半，佳人傾國態懸殊。", "園荒不減遊羣鹿，才盡應悲短續鳬。", "有墨牡丹君種否，鄉邦能借一畦無。"]'),
('7687eb21-cbc1-45e4-9361-5d3d984eb6c1','復和仲蟠二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','一見春紅意已舒，何須幻化入懸壺。',64,'全唐诗/poet.song.154000.json','["一見春紅意已舒，何須幻化入懸壺。", "含芳鎮日香千和，作態臨風色萬殊。", "曲檻乍開金縷鳳，清池斜照玉爲鳬。", "洛陽擬問門園在，王后如今解接無。"]'),
('62259980-25f1-4d72-9a05-df558919d83a','思鄉奉和','薛季宣','宋','宋诗','song-poetry','','[]','杯室開門傍石泉，平生活計枕書眠。',64,'全唐诗/poet.song.154000.json','["杯室開門傍石泉，平生活計枕書眠。", "但知身世非人界，不信方家說洞天。", "陋巷分甘顔子樂，一瓢所得許由賢。", "年來把板塵埃去，笑殺商山四皓仙。"]'),
('1d990bb8-c519-4c1a-b5d3-0ba6d30a3484','和錢都官','薛季宣','宋','宋诗','song-poetry','','[]','道學從初小況雄，文光萬丈吐長虹。',64,'全唐诗/poet.song.154000.json','["道學從初小況雄，文光萬丈吐長虹。", "凌霜壯節生來勁，噴玉清詩老更工。", "攀檻定須回日御，叫閽端復悟天聰。", "願公赤舄安狼疐，豳國何曾有變風。"]'),
('023a7a45-54e4-4ca6-8c59-34d06ea376ee','和元直','薛季宣','宋','宋诗','song-poetry','','[]','疇昔相要學婁空，蹉跎行即歎龍鍾。',64,'全唐诗/poet.song.154000.json','["疇昔相要學婁空，蹉跎行即歎龍鍾。", "三千牘欠東方奏，十萬兵無小范胸。", "大愧入關歌一箭，終期出塞傳三烽。", "蓬萊有願占雲氣，又羨江山筆墨供。"]'),
('1ee5421f-62e7-4db0-9734-6b8b085649b9','和元可贈別','薛季宣','宋','宋诗','song-poetry','','[]','惟憐蹤蹟負平生，愧予秋空萬里清。',64,'全唐诗/poet.song.154000.json','["惟憐蹤蹟負平生，愧予秋空萬里清。", "體道信能忘聚散，論交曾復俟將迎。", "愁多人物輸前輩，恨有天公也世情。", "陽羨買田雖舊約，虞歌喜起欲誰賡。"]'),
('00fc8766-2097-4fab-9ae0-162dc6c1d17a','王朴','薛季宣','宋','宋诗','song-poetry','','[]','海宇煎熬沸鼎時，先生靜付一支頤。',64,'全唐诗/poet.song.154000.json','["海宇煎熬沸鼎時，先生靜付一支頤。", "單辭隠几三仁在，大略平邊百世知。", "到了勳庸成底事，由來用捨出先幾。", "長槍不用毛錐子，應使毛錐自用爲。"]'),
('3a145cdb-120f-49c3-902d-4fdbc5c49839','酬朱張二秀才皆次其首章韻二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','殃民政虐恐風傳，鎮日窮愁蟬腹然。',64,'全唐诗/poet.song.154000.json','["殃民政虐恐風傳，鎮日窮愁蟬腹然。", "化物未能參物格，高談無當若談天。", "雅歌清唱俱流徵，善聽多慙可絕弦。", "何事攔腰撞君價，絕塵奔逸正吾前。"]'),
('f08b6c6e-44e1-4d53-b96b-b9b931e18f38','酬朱張二秀才皆次其首章韻二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','萬緣政爾未能佳，繪句彫鎪直謾誇。',64,'全唐诗/poet.song.154000.json','["萬緣政爾未能佳，繪句彫鎪直謾誇。", "客裏懸知君有謂，宦遊當念我何奢。", "幾時西塞歌飛鷺，指日東籬采菊花。", "五斗折腰良自苦，奈今無粟飯胡麻。"]'),
('b238a896-4b53-45b2-b379-dce3671b38f0','觀法帖','薛季宣','宋','宋诗','song-poetry','','[]','字學從前小藝林，誰論終古可傳心。',64,'全唐诗/poet.song.154000.json','["字學從前小藝林，誰論終古可傳心。", "毛錐刻劃龍蛇動，筆陣縱橫劍戟森。", "須省六書兼八法，由來一字值千金。", "世人不解張顛聖，剛把碑文鎮日臨。"]'),
('4824f68f-6e5f-48e3-8916-3b2a933ac6b3','夜聞桂香','薛季宣','宋','宋诗','song-poetry','','[]','秋香烈烈鎖房櫳，龍麝腥羶不易同。',64,'全唐诗/poet.song.154000.json','["秋香烈烈鎖房櫳，龍麝腥羶不易同。", "清素月中留夜魄，芬芳林下有家風。", "記惟密雪開梅萼，憶過疏籬采菊叢。", "獨有平泉舊詩句，浪誇金粟竟非工。"]'),
('36ea211b-b7e5-43e7-ae54-ee7abdfa2453','蓼花','薛季宣','宋','宋诗','song-poetry','','[]','不矜秀色傲春風，笑倚斜陽露氣濃。',64,'全唐诗/poet.song.154000.json','["不矜秀色傲春風，笑倚斜陽露氣濃。", "秋草淒涼風索索，江天寂靜水溶溶。", "岸移晴綺飄仙袂，葉起丹霞照玉容。", "可奈少香香似可，爲傳滋味入醺醲。"]'),
('c2b9e0e8-0b75-43db-ade6-fd2bbc1f2835','社日','薛季宣','宋','宋诗','song-poetry','','[]','年去年來春復秋，田豐土穀浪言酬。',64,'全唐诗/poet.song.154000.json','["年去年來春復秋，田豐土穀浪言酬。", "敗家謔善崔文紀，宰社均無曲逆侯。", "燈燭靈壇三告祀，燕鴻邊塞兩淹留。", "不須飲福傾樽酒，聾過今生方始休。"]'),
('59cc7726-2ed0-469c-be28-fd8563b57012','至樊口三首  其一','薛季宣','宋','宋诗','song-poetry','','[]','一霎重爲退谷遊，扁舟一葉浪如舟。',32,'全唐诗/poet.song.154000.json','["一霎重爲退谷遊，扁舟一葉浪如舟。", "人生百歲渾如許，借問都來幾白頭。"]'),
('5f57bb7c-21cb-4271-9927-c2d1c0ee279e','至樊口三首  其二','薛季宣','宋','宋诗','song-poetry','','[]','小回中入大回中，激水那堪括面風。',32,'全唐诗/poet.song.154000.json','["小回中入大回中，激水那堪括面風。", "退谷未堙聱叟笑，釣臺寧是不英雄。"]'),
('1eb2d8e2-df46-4028-89f8-f74103f7026d','至樊口三首  其三','薛季宣','宋','宋诗','song-poetry','','[]','長安當日碎樊山，聞說孫郎鑿峴還。',32,'全唐诗/poet.song.154000.json','["長安當日碎樊山，聞說孫郎鑿峴還。", "舴艋架虛掀舞甚，可堪破舶問前灣。"]'),
