('7fda9382-7a42-4fd8-a2ca-d35a92a53851','歸計二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','置錐無地亦無錐，幸可歸來特地疑。',32,'全唐诗/poet.song.154000.json','["置錐無地亦無錐，幸可歸來特地疑。", "船子月輪貧未破，羅浮焉用石頭爲。"]'),
('6ebe9a3f-7550-4485-8557-c07ab68387c9','青田同七五兄作四首  其一','薛季宣','宋','宋诗','song-poetry','','[]','爲聞雙鶴訪青田，便有孤雲竟目前。',32,'全唐诗/poet.song.154000.json','["爲聞雙鶴訪青田，便有孤雲竟目前。", "灘水自鳴山自綠，短篷斜挂得酣眠。"]'),
('479325d8-7f0e-4d5a-be35-410a07339397','青田同七五兄作四首  其二','薛季宣','宋','宋诗','song-poetry','','[]','鳥雲送雨過前山，白鳥將雛向遠灣。',32,'全唐诗/poet.song.154000.json','["鳥雲送雨過前山，白鳥將雛向遠灣。", "獨立溪亭無箇事，湍流瀧石鎮潺潺。"]'),
('e20ba571-6c8d-4d5d-bf46-146f999ce179','青田同七五兄作四首  其三','薛季宣','宋','宋诗','song-poetry','','[]','浩歌欵乃客銷魂，一抹煙林暝遠村。',32,'全唐诗/poet.song.154000.json','["浩歌欵乃客銷魂，一抹煙林暝遠村。", "花爲忘憂人一笑，不知風雨作黄昏。"]'),
('1add2f77-4b79-4fb6-b502-161ead802135','青田同七五兄作四首  其四','薛季宣','宋','宋诗','song-poetry','','[]','谿翁夜傍清溪立，千尺絲綸一紅粒。',32,'全唐诗/poet.song.154000.json','["谿翁夜傍清溪立，千尺絲綸一紅粒。", "天空月白不見人，無聲露滴蘋蓑溼。"]'),
('1a80830c-0470-48e1-abfa-3af2be7bf93f','追和寶山晝睡','薛季宣','宋','宋诗','song-poetry','','[]','浮生化國總輕塵，已自忘真那得真。',32,'全唐诗/poet.song.154000.json','["浮生化國總輕塵，已自忘真那得真。", "無物從教儘空洞，可須容著許多人。"]'),
('1e995386-b6f2-461f-a8f5-02d1afccca71','戲作贈別效東坡體次其韻','薛季宣','宋','宋诗','song-poetry','','[]','茹菜羹時嘗苦憶，摴蒱無路塞行期。',32,'全唐诗/poet.song.154000.json','["茹菜羹時嘗苦憶，摴蒱無路塞行期。", "難逢莫恨絲長斷，金鎖開緘自有時。"]'),
('feb19c43-5cee-4816-9f03-8d342662ab70','雨中鶴唳','薛季宣','宋','宋诗','song-poetry','','[]','十萬虛屯野次兵，不逢苻詔壽陽城。',32,'全唐诗/poet.song.154000.json','["十萬虛屯野次兵，不逢苻詔壽陽城。", "愁雲慘淡雨來急，鳴鶴一聲天未晴。"]'),
('749e831a-2cd2-448c-a649-d51bf40279c9','啄木','薛季宣','宋','宋诗','song-poetry','','[]','蝎譖區區切考求，饑腸一飽又何尤。',32,'全唐诗/poet.song.154000.json','["蝎譖區區切考求，饑腸一飽又何尤。", "要能去蠹無遺種，寥落空林死便休。"]'),
('2fec1e76-1b58-4853-b49e-9eb2b1c7d7ed','鶑','薛季宣','宋','宋诗','song-poetry','','[]','綿蠻巧語慶青春，金線低垂柳色新。',32,'全唐诗/poet.song.154000.json','["綿蠻巧語慶青春，金線低垂柳色新。", "定自知時厭流蕩，歸來空谷混泥塵。"]'),
('5fc23192-fffc-481f-bd59-0477e3aa1348','讀鬼詩擬作二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','坐對悲風嘯晚山，征鴻不記幾回還。',32,'全唐诗/poet.song.154000.json','["坐對悲風嘯晚山，征鴻不記幾回還。", "青銅蝕破菱花面，慵掠烏雲綰髻鬟。"]'),
('7a9b9e6c-2951-43f5-be1b-93fd2fc7b68b','讀鬼詩擬作二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','至樂紛華苦未真，至遊無朕亦無身。',32,'全唐诗/poet.song.154000.json','["至樂紛華苦未真，至遊無朕亦無身。", "細看浮世多塵坌，如我得歸能幾人。"]'),
('68949dd2-1962-43a7-b6af-c4cdd0478c94','李斯  其一','薛季宣','宋','宋诗','song-poetry','','[]','獵盡山東六暴强，脩明律令起秦皇。',32,'全唐诗/poet.song.154000.json','["獵盡山東六暴强，脩明律令起秦皇。", "還思稅駕知無地，逐兔應當爾許忙。"]'),
('adeac418-36bc-477b-8bdd-4e26703b34b8','李斯  其二','薛季宣','宋','宋诗','song-poetry','','[]','詩書灰燼便秦文，便得秦王却誤身。',32,'全唐诗/poet.song.154000.json','["詩書灰燼便秦文，便得秦王却誤身。", "斯具五刑秦再世，六經還有表章人。"]'),
('09db7adf-0a76-466e-9b4b-d2912fb538ed','李斯  其三','薛季宣','宋','宋诗','song-poetry','','[]','剛從孫卿學帝王，爲羞貧賤速危亡。',32,'全唐诗/poet.song.154000.json','["剛從孫卿學帝王，爲羞貧賤速危亡。", "威嚴無復人居上，自處應慙厠鼠方。"]'),
('18072ce1-a21a-4403-80cd-75d677fe0e62','燕太子','薛季宣','宋','宋诗','song-poetry','','[]','意氣寧知錯感人，姬丹祕計謾危親。',32,'全唐诗/poet.song.154000.json','["意氣寧知錯感人，姬丹祕計謾危親。", "亡燕拜送於期首，政使荆卿趣帝秦。"]'),
('e856c002-6be0-42d8-9b03-e04d403ebd0c','雨後憶龍翔寺  其一','薛季宣','宋','宋诗','song-poetry','','[]','二峰高峙夾禪扃，長落潮音逐磬聲。',32,'全唐诗/poet.song.154000.json','["二峰高峙夾禪扃，長落潮音逐磬聲。", "老僧睡起絕無事，不管波濤四面生。"]'),
('93870dee-47ce-47b7-8155-9d5475999c82','雨後憶龍翔寺  其二','薛季宣','宋','宋诗','song-poetry','','[]','窣堵東西岌兩峰，王宮今日梵王宮。',32,'全唐诗/poet.song.154000.json','["窣堵東西岌兩峰，王宮今日梵王宮。", "潮船八面來勍敵，都入禪師燕坐中。"]'),
('7388048a-3559-407e-a2bd-13ce4b134bc6','秋意','薛季宣','宋','宋诗','song-poetry','','[]','月娥素魄溢嬋娟，金吹淒涼冷淡天。',32,'全唐诗/poet.song.154000.json','["月娥素魄溢嬋娟，金吹淒涼冷淡天。", "野水暝煙楓葉暮，黄花紅蓼獨嫣然。"]'),
('522690c1-09e1-4163-b102-ae7421244ae5','聞蟬  其一','薛季宣','宋','宋诗','song-poetry','','[]','自闢筠鄉五畝陰，蟬聲無處不相尋。',32,'全唐诗/poet.song.154000.json','["自闢筠鄉五畝陰，蟬聲無處不相尋。", "炎天喚起秋蕭索，便擬乘風遶鄧林。"]'),
('d90bd801-c6e6-4d3b-b6a4-8198d8edc00a','聞蟬  其二','薛季宣','宋','宋诗','song-poetry','','[]','新蟬無數咽琅玕，引惹涼生六月寒。',32,'全唐诗/poet.song.154000.json','["新蟬無數咽琅玕，引惹涼生六月寒。", "已自東山譽高潔，未須丹翅擬笙鸞。"]'),
('43634fc2-3902-46a6-b54d-f8b515d8ae47','村居秋暮','薛季宣','宋','宋诗','song-poetry','','[]','風迴偃水縠紋平，林末它山筆架橫。',32,'全唐诗/poet.song.154000.json','["風迴偃水縠紋平，林末它山筆架橫。", "場圃未閒黄葉下，鵓鳩啼雨忽啼晴。"]'),
('b65a561b-6119-4233-8d9d-b83f3cc3d9c4','睡香','薛季宣','宋','宋诗','song-poetry','','[]','君子奪朱有惡，祖師噩夢尋香。',28,'全唐诗/poet.song.154000.json','["君子奪朱有惡，祖師噩夢尋香。", "莫問兩重公案，且須一曲霓裳。"]'),
('cd57d553-dc2a-4782-b8fc-93361c86b363','摴蒱','薛季宣','宋','宋诗','song-poetry','','[]','一局閒尋五木經，橛梟盧白意冥冥。',32,'全唐诗/poet.song.154000.json','["一局閒尋五木經，橛梟盧白意冥冥。", "未能後擲如前擲，將奈長亭又短亭。"]'),
('affa3557-7845-41b9-b68c-909d308aa0da','公叔次開窗詩漫答','薛季宣','宋','宋诗','song-poetry','','[]','不同夷甫坐談空，爛醉鳧鷖滅沒中。',32,'全唐诗/poet.song.154000.json','["不同夷甫坐談空，爛醉鳧鷖滅沒中。", "聞說詩豪君是否，好磨長劍倚崆峒。"]'),
('03a36d66-fc15-459e-ab18-90ad09d21601','幽蘭次十八兄韻六言四首  其一','薛季宣','宋','宋诗','song-poetry','','[]','宛在一人空谷，居然九畹深林。',28,'全唐诗/poet.song.154000.json','["宛在一人空谷，居然九畹深林。", "襟袖不盈披拂，車轍無蹤可尋。"]'),
('bf32fcc4-1e17-4433-ab62-078b3aab2b00','幽蘭次十八兄韻六言四首  其二','薛季宣','宋','宋诗','song-poetry','','[]','有美中郎芝砌，言采淵明菊叢。',28,'全唐诗/poet.song.154000.json','["有美中郎芝砌，言采淵明菊叢。", "會取箇中香氣，蕭然林下家風。"]'),
('fb51cf98-ce7d-44b8-9fa1-7bca9b3c9019','幽蘭次十八兄韻六言四首  其三','薛季宣','宋','宋诗','song-poetry','','[]','舞奏八風薌澤，頌聲焱氏遺音。',28,'全唐诗/poet.song.154000.json','["舞奏八風薌澤，頌聲焱氏遺音。", "允也不夷不惠，悠哉非古非今。"]'),
('a8077ddb-8cc9-4dfc-ae0c-cc4fc2fe9fac','幽蘭次十八兄韻六言四首  其四','薛季宣','宋','宋诗','song-poetry','','[]','超出世間凡品，叵聞鼻觀餘香。',28,'全唐诗/poet.song.154000.json','["超出世間凡品，叵聞鼻觀餘香。", "春入有花不艷，院小無人自芳。"]'),
('1b97e7fa-0114-4582-9c79-848040441c60','詔書屯田湖北相土西鄉屬暑雨中旬轉入洪道時雨初霽谿山葱泚如在縉雲荆坑道中子規之聲相聞屬道','薛季宣','宋','宋诗','song-poetry','','[]','沐雨驅車涉敗橋，平原渺渺漲江潮。',64,'全唐诗/poet.song.154000.json','["沐雨驅車涉敗橋，平原渺渺漲江潮。", "華容葭葦憑誰燎，赤壁艨艟徒自燒。", "一路規啼情悄悄，九皋鶴唳思摇摇。", "道東直指松門去，酷似故鄉歸路遥。"]'),
('dc1cc380-94c2-47e5-854a-c7926d1103e9','書顔子傳後','薛季宣','宋','宋诗','song-poetry','','[]','幾庶都緣有若無，寧論芻狗矧蘧廬。',64,'全唐诗/poet.song.154000.json','["幾庶都緣有若無，寧論芻狗矧蘧廬。", "要須非復周公夢，而亦何爲子夏書。", "行葦至仁均草木，中孚大信洽豚魚。", "窮神至命知奚事，不遠周流意六虛。"]'),
('18418e8e-2224-4853-9aaf-2e7933f4f40b','六月三夜夢觀某人詩什其書一章四絕蓋絕筆也走讀竟太一真人來告語青猿手裏得長書靜聞丹竈風中雨之句夢而默記之寤矣作詩導意','薛季宣','宋','宋诗','song-poetry','','[]','多謝真人警夢書，青猿馴擾尚趦趄。',64,'全唐诗/poet.song.154000.json','["多謝真人警夢書，青猿馴擾尚趦趄。", "任從爐鼎喧風雨，爭奈神明復古初。", "君樂鍊形咀丹火，我甘飲水灌園蔬。", "惟當敬佩終焉意，子欲無言致匪虛。"]'),
('396599e4-7cf1-4e0b-8c0a-f9afb9b67883','讀伊川易傳','薛季宣','宋','宋诗','song-poetry','','[]','太極非名豈自然，由知闢闔見坤乾。',64,'全唐诗/poet.song.154000.json','["太極非名豈自然，由知闢闔見坤乾。", "先天詎必違中古，上古應須得後天。", "至密退藏那有迹，惟幾成務尚容研。", "從教變易能從道，不似神龍得性全。"]'),
('721e5407-9c4e-4ee1-aea6-08f29d27f5e7','樊口見鄭崇陽不遇','薛季宣','宋','宋诗','song-poetry','','[]','經時兀兀坐筠鄉，命駕崎嶇傍夕陽。',64,'全唐诗/poet.song.154000.json','["經時兀兀坐筠鄉，命駕崎嶇傍夕陽。", "島嶼西陵開罨畫，湖山東鄂洗新裝。", "路侵細草迷繁綠，風落閒花憶舊香。", "却上渡船歸去也，不逢安道故無妨。"]'),
('5e5d59f4-d46a-49d8-add6-5eaa2c0d8a8d','誠臺晚意','薛季宣','宋','宋诗','song-poetry','','[]','麥夏西山日脚斜，峰雲千里盡丹霞。',64,'全唐诗/poet.song.154000.json','["麥夏西山日脚斜，峰雲千里盡丹霞。", "晴嵐榱桷水春漲，芳草園林路晚花。", "遠近子規啼怨抑，高低乳燕語淫哇。", "官身歸是何年社，信美誠臺不似家。"]'),
('aa7c58c0-e2fa-410b-8894-391aee4618a2','晨赴寒谿寺乾龍節道場所','薛季宣','宋','宋诗','song-poetry','','[]','曉入招提旋即還，去何忙遽到非閒。',64,'全唐诗/poet.song.154000.json','["曉入招提旋即還，去何忙遽到非閒。", "寒谿日出射煙霧，退谷路荒埋草菅。", "林盡遠峰晴歷歷，叢深流水暗潺潺。", "歸途鐘鼓依稀似，將謂禪居別有山。"]'),
('3f853754-8146-4e63-a6aa-93f0ef2edcf4','新晴','薛季宣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','起人舒慘作陰晴，九十春光祇雨零。',64,'全唐诗/poet.song.154000.json','["起人舒慘作陰晴，九十春光祇雨零。", "宿草未萌波漠漠，落花歸盡葉青青。", "風生遠嶠銜明月，霧瀲長江吐漲汀。", "天意乍回心自廣，片時雲路覺無形。"]'),
('8e9a71ea-bac6-440c-9c34-da38f71b06a2','勝亭雪望','薛季宣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','上元雲路玉塵飛，應是虯驂罷會歸。',64,'全唐诗/poet.song.154000.json','["上元雲路玉塵飛，應是虯驂罷會歸。", "望合郊原人世變，映浮城郭夜燈微。", "連天忘却黄岡縣，際水平將赤壁磯。", "滾滾長江耐澄撓，浪回鷗鳥一驚翬。"]'),
('110d818a-b2d3-471e-a8c7-063728ce311c','和賈簿','薛季宣','宋','宋诗','song-poetry','','[]','澄江風定也清寒，咫尺渾疑醉夢間。',64,'全唐诗/poet.song.154000.json','["澄江風定也清寒，咫尺渾疑醉夢間。", "雪滿後湖真是浪，雲平西塞且無山。", "輕鷗弄水情無限，遠雁書空時自還。", "靜極要當隨衆樂，歸來燈火閙朱顔。"]'),
('f2f7d1c6-d1a3-475c-880a-2d6a7bbf1e43','和賈簿勝亭雪眺','薛季宣','宋','宋诗','song-poetry','','[]','携壺命侶燕江干，雪起頹垣甃玉欄。',64,'全唐诗/poet.song.154000.json','["携壺命侶燕江干，雪起頹垣甃玉欄。", "減水湖中還素浪，明雲天際失青山。", "無端大火寒無艷，不奈生柴苦不乾。", "斷岸蘆洲見殘月，一鉤忤視却前灣。"]'),
('732e480e-88f6-4018-a302-9f4e1c645adb','艮止亭即事','薛季宣','宋','宋诗','song-poetry','','[]','艮止危亭欲暮春，湖山江外翠眉顰。',64,'全唐诗/poet.song.154000.json','["艮止危亭欲暮春，湖山江外翠眉顰。", "鳥啼夕月清歌扇，花發荒原閙舞裀。", "吳老洞迷青草暗，陶公宅古綠蘿新。", "懷歸何日成歸計，不忿端居作主人。"]'),
('a639e1e6-4452-435f-a7e3-ec122d843d8f','泊船','薛季宣','宋','宋诗','song-poetry','','[]','泊船在處即吾家，鮮得熸烹爨有槎。',64,'全唐诗/poet.song.154000.json','["泊船在處即吾家，鮮得熸烹爨有槎。", "弄景日移煙岸柳，流香風度野薇花。", "霞翻錦段浮江渚，水落濤紋隠岸沙。", "塊坐朅來無一事，夜深遠燒起殷霞。"]'),
('7422e721-29b6-40dd-9ebc-51bb69647fdc','從孫元式假定本韓文','薛季宣','宋','宋诗','song-poetry','','[]','楊墨衰周亦既微，仙曇變夏用戎夷。',64,'全唐诗/poet.song.154000.json','["楊墨衰周亦既微，仙曇變夏用戎夷。", "回瀾豈直萬人敵，斷簡傳將百世師。", "脫落間亡烏鰂墨，蠹殘寧免白魚辭。", "校讎歆向君無愧，聊以新詩當一瓻。"]'),
('360dda37-5580-4a9c-9533-eb9971c5bc03','校畢歸之','薛季宣','宋','宋诗','song-poetry','','[]','倒墨扶周復古文，清輝萬丈醇乎醇。',64,'全唐诗/poet.song.154000.json','["倒墨扶周復古文，清輝萬丈醇乎醇。", "七篇奧義遠相繼，六代潛光今又新。", "字假通才識魚魯，車慙寡學改金銀。", "異書喜得君無靳，此道中興知有人。"]'),
('74092148-9e93-40fb-97ad-aeb2d22bb2cd','勸農出郊','薛季宣','宋','宋诗','song-poetry','','[]','漫驅戎馬說農郊，不見田疇見白茅。',64,'全唐诗/poet.song.154000.json','["漫驅戎馬說農郊，不見田疇見白茅。", "洪道曉晴明水底，羊瀾春漲長林梢。", "紅翻大澤霞方散，青人空原草漸苞。", "迎畯示民民自勸，可須杯酒薦烹炮。"]'),
('814636a9-34da-44bb-be0a-0249dc32c4ef','九日龍山之集','薛季宣','宋','宋诗','song-poetry','','[]','年年九日登高會，九日登高年歲閒。',64,'全唐诗/poet.song.154000.json','["年年九日登高會，九日登高年歲閒。", "黄菊茱萸應故泛，茱萸黄菊故應攀。", "今人不在古人後，往意可如茲意閒。", "風帽落簷誰得見，龍山還是昔龍山。"]'),
('c987c34b-c22c-40cb-a2e4-4dbec961f649','冒雨渡江弔喪彭氏造雪堂夜歸  其一','薛季宣','宋','宋诗','song-poetry','','[]','衝風櫛雨亂西江，弔死裴回問雪堂。',64,'全唐诗/poet.song.154000.json','["衝風櫛雨亂西江，弔死裴回問雪堂。", "叢枳界無春草主，小橋蹤在古碑荒。", "人存有政名空大，世遠回思恨始長。", "旋棹晚雲何限事，可堪瑞慶柳成行。"]'),
('1bd6e736-16e5-4354-9417-359bf6981040','冒雨渡江弔喪彭氏造雪堂夜歸  其二','薛季宣','宋','宋诗','song-poetry','','[]','月波樓下草芊芊，浪拍三江起暝煙。',64,'全唐诗/poet.song.154000.json','["月波樓下草芊芊，浪拍三江起暝煙。", "願見古人人又去，欲詢往事事無傳。", "漥樽明滅漁家火，樊口依稀估客船。", "妻子迎門應怪笑，問君何謂苦愁煎。"]'),
('1d04d105-868d-4c8f-8356-7597797cc636','酴醿花','薛季宣','宋','宋诗','song-poetry','','[]','東鄰處子太優柔，醉倚闌干十二樓。',64,'全唐诗/poet.song.154000.json','["東鄰處子太優柔，醉倚闌干十二樓。", "清白有家傳醖藉，醇醲無味飲風流。", "带摇翠幄蒼蛟動，佩解虹梁綠蟻浮。", "嘉木自香香到骨，困人非酒欲誰酬。"]'),
('af806a0b-54de-40cf-a1d0-bd8943cd1b1f','牡丹','薛季宣','宋','宋诗','song-poetry','','[]','三春首出衆芳菲，笑倚東風蹙翠眉。',64,'全唐诗/poet.song.155000.json','["三春首出衆芳菲，笑倚東風蹙翠眉。", "洛浦未翔要玉佩，湯泉新浴曳袿衣。", "無雙可奈傾城恨，第一何堪代命爲。", "桑柘不花花乍可，清霜誰是不空枝。"]'),
('62b69bd6-3d60-4ef3-b7b5-3c292dcbcac7','巖桂','薛季宣','宋','宋诗','song-poetry','','[]','羣芳未許論芳馨，獨自秋天卧月明。',64,'全唐诗/poet.song.155000.json','["羣芳未許論芳馨，獨自秋天卧月明。", "頼有幽香洞淵奧，寧將雅趣博輕盈。", "德純不顯娥皇怨，道大無聞叔度清。", "好向深巖伴黄石，可知誰與桂花名。"]'),
('f8a81143-dbd1-4558-bf6b-a3e7af8a13c3','天閨','薛季宣','宋','宋诗','song-poetry','','[]','扁舟一葉轉寒溪，返照西陽日下西。',32,'全唐诗/poet.song.155000.json','["扁舟一葉轉寒溪，返照西陽日下西。", "旬浹不來江水漲，驚瀾幾欲上天閨。"]'),
('d21ca4e6-8a88-4aba-b688-eed89f653600','武昌懷古','薛季宣','宋','宋诗','song-poetry','','[]','漠漠煙村一古城，郊壇離殿草茅生。',32,'全唐诗/poet.song.155000.json','["漠漠煙村一古城，郊壇離殿草茅生。", "青山不解知興替，銷黯開顔爲雨晴。"]'),
('06386bd9-0c86-4fc2-87f1-9d64c34df745','筠鄉入夏野花方拆','薛季宣','宋','宋诗','song-poetry','','[]','牆匝叢叢繡舞裀，一般顔面各精神。',32,'全唐诗/poet.song.155000.json','["牆匝叢叢繡舞裀，一般顔面各精神。", "筠鄉不爲東君去，野草閒花滿路春。"]'),
('4e0efbfc-8114-4400-8155-5ebd22a08ab4','艮止亭晚意','薛季宣','宋','宋诗','song-poetry','','[]','山影殊亭日轉西，牆頭歷歷片帆移。',32,'全唐诗/poet.song.155000.json','["山影殊亭日轉西，牆頭歷歷片帆移。", "何人喚我頻歸去，側耳疏篁怨子規。"]'),
('e9bc19ed-ecc3-496f-8513-ad65aebdd835','艮止亭阻雨旬日  其一','薛季宣','宋','宋诗','song-poetry','','[]','山亭無路少徘徊，跬步狂瀾漲九垓。',32,'全唐诗/poet.song.155000.json','["山亭無路少徘徊，跬步狂瀾漲九垓。", "不是蜃樓浮海外，也應弱水限蓬萊。"]'),
('9c34d78b-00ff-4c91-b060-1bd2639e126b','艮止亭阻雨旬日  其二','薛季宣','宋','宋诗','song-poetry','','[]','艮止休工未落成，做人限隔雨零零。',32,'全唐诗/poet.song.155000.json','["艮止休工未落成，做人限隔雨零零。", "眼前好景到不得，便是霄中望極星。"]'),
('a26fb4cd-55a0-408e-be40-e6dcba39d00c','晚渡東坡  其一','薛季宣','宋','宋诗','song-poetry','','[]','赤鼻磯頭橫曙煙，吳王城下浪連天。',32,'全唐诗/poet.song.155000.json','["赤鼻磯頭橫曙煙，吳王城下浪連天。", "聞道東坡妙天下，爾來靡日不盤旋。"]'),
('85ad8549-5325-42b7-be7d-5022e2f64e9f','晚渡東坡  其二','薛季宣','宋','宋诗','song-poetry','','[]','浮生萬事盡塵埃，瑞慶堂今榜快哉。',32,'全唐诗/poet.song.155000.json','["浮生萬事盡塵埃，瑞慶堂今榜快哉。", "惟有東坡舊煙柳，道人猶解指莓苔。"]'),
('32328d5d-abc0-4bf8-b1a7-041b0752dd05','行戍西山','薛季宣','宋','宋诗','song-poetry','','[]','帝驅貙虎舊江州，旅卜僧坊計少休。',32,'全唐诗/poet.song.155000.json','["帝驅貙虎舊江州，旅卜僧坊計少休。", "避暑有宮留不暇，遊山算却是山遊。"]'),
('17051827-38ce-4863-b870-ffebdfe69406','讀蕭銑傳','薛季宣','宋','宋诗','song-poetry','','[]','可怪梁朝幾帝王，丘墟萬里變農桑。',32,'全唐诗/poet.song.155000.json','["可怪梁朝幾帝王，丘墟萬里變農桑。", "修文偃武如何故，町疃江陵盡鹿場。"]'),
('ea1f1b8c-ad7c-417a-b1be-f067db9ec590','塊坐','薛季宣','宋','宋诗','song-poetry','','[]','萬緒絲棼汩太和，終朝所得竟無何。',32,'全唐诗/poet.song.155000.json','["萬緒絲棼汩太和，終朝所得竟無何。", "放心收却且危坐，始覺忘機有味多。"]'),
('81dab247-3271-42f6-b019-5f77233f5910','讀皇極經世書','薛季宣','宋','宋诗','song-poetry','','[]','大易誠知自畫前，後天不識異先天。',32,'全唐诗/poet.song.155000.json','["大易誠知自畫前，後天不識異先天。", "工夫用盡還無事，巧歷勞推不盡年。"]'),
('f2c6b62a-1516-46bb-8b15-d6ac9cf5dec7','讀荆軻傳','薛季宣','宋','宋诗','song-poetry','','[]','妙算嘗聞勝五侯，輕生終不是良謀。',32,'全唐诗/poet.song.155000.json','["妙算嘗聞勝五侯，輕生終不是良謀。", "秦王未許論生劫，畢事還同擦虎頭。"]'),
('f59c80f4-af32-48e1-86f8-6f32923274da','讀劉叉集','薛季宣','宋','宋诗','song-poetry','','[]','湯文不作幾經春，叉也賢乎隠澤民。',32,'全唐诗/poet.song.155000.json','["湯文不作幾經春，叉也賢乎隠澤民。", "古劍胸中儘磨淬，寧如覺道樂耕莘。"]'),
('fd268901-9ce2-469c-9277-3d9078ce08ee','伯文人盆池開芙蓉十二','薛季宣','宋','宋诗','song-poetry','','[]','聞合天符下玉麟，祝融湓浦肆時巡。',32,'全唐诗/poet.song.155000.json','["聞合天符下玉麟，祝融湓浦肆時巡。", "西山詎必須陵井，又得餐霞十二人。"]'),
('c45a6767-e6cf-43a9-8eb1-a9c593ad156f','讀近時樂府  其一','薛季宣','宋','宋诗','song-poetry','','[]','天寶龜茲貴尚年，哇淫靡靡到今傳。',32,'全唐诗/poet.song.155000.json','["天寶龜茲貴尚年，哇淫靡靡到今傳。", "尋思溱洧桑中調，幾許不如周頌篇。"]'),
('9fcab6ff-fc14-4144-a5da-1a642ab57611','讀近時樂府  其二','薛季宣','宋','宋诗','song-poetry','','[]','樂好株離幾百年，知昏漢日暗湖天。',32,'全唐诗/poet.song.155000.json','["樂好株離幾百年，知昏漢日暗湖天。", "周東幸有其戎歎，却在伊川被髮前。"]'),
('33054478-e7aa-406b-9638-ed2b8c9f569b','春遊','薛季宣','宋','宋诗','song-poetry','','[]','桃紅李白輝相曜，車馬交關遞流照。',32,'全唐诗/poet.song.155000.json','["桃紅李白輝相曜，車馬交關遞流照。", "牆頭半露是秋千，不見美人聞語笑。"]'),
('f2eef5cb-5c38-4c3b-a800-9ca8bbb3c6e5','即事','薛季宣','宋','宋诗','song-poetry','','[]','芰荷薿薿抽蘋藻，風細幽香襲懷抱。',32,'全唐诗/poet.song.155000.json','["芰荷薿薿抽蘋藻，風細幽香襲懷抱。", "庭竹琅然振玉音，葉落委階墉不埽。"]'),
('f0f05f26-c6bd-45f3-8f5d-11b21635b175','殘花','薛季宣','宋','宋诗','song-poetry','','[]','小院銀瓶花落枝，驪山驚起睡楊妃。',32,'全唐诗/poet.song.155000.json','["小院銀瓶花落枝，驪山驚起睡楊妃。", "銷魂淚滴燕支雨，留得霓裳舊舞衣。"]'),
('abdce80d-8fcd-4ba9-b67d-9101a74460f5','瓶花盡落而梨花瀟灑如故','薛季宣','宋','宋诗','song-poetry','','[]','天帝南遊匹馬還，紅雲作陣雨闌干。',32,'全唐诗/poet.song.155000.json','["天帝南遊匹馬還，紅雲作陣雨闌干。", "駐顔下嚥如冰雪，一粒清涼得賜丹。"]'),
('7cad8620-a9f1-4698-9313-640c38dfe2bf','寒食雨','薛季宣','宋','宋诗','song-poetry','','[]','言歸社鴈已家鄉，紫燕呢喃識舊梁。',32,'全唐诗/poet.song.155000.json','["言歸社鴈已家鄉，紫燕呢喃識舊梁。", "甚雨疾風寒食夜，旅人情緒一思量。"]'),
('d7969a7c-b34d-4608-92ed-6670a90cfe8d','江村聞笛','薛季宣','宋','宋诗','song-poetry','','[]','江村風色秋江渺，林薄無人閙幽鳥。',32,'全唐诗/poet.song.155000.json','["江村風色秋江渺，林薄無人閙幽鳥。", "長笛一聲金吹寒，知有漁舟釣紅蓼。"]'),
('c193cf5a-a291-4004-8ff9-c3f664ca3143','遠景圖  其一','薛季宣','宋','宋诗','song-poetry','','[]','蘆花飛鴈煙村靜，一點青山波萬頃。',32,'全唐诗/poet.song.155000.json','["蘆花飛鴈煙村靜，一點青山波萬頃。", "人在孤舟喚不譍，兒言客寫瀟湘景。"]'),
('81568651-a0a8-46b7-b836-e1ad185dfaa3','遠景圖  其二','薛季宣','宋','宋诗','song-poetry','','[]','慘澹平煙波浩渺，隠月餘光飛白鳥。',32,'全唐诗/poet.song.155000.json','["慘澹平煙波浩渺，隠月餘光飛白鳥。", "依稀一舸是漁舟，獨釣寒江天未曉。"]'),
('152ba123-a770-492f-a8aa-3de20b04bf89','野望','薛季宣','宋','宋诗','song-poetry','','[]','水晶簟冷鋪寒玉，翠帟高張染螺綠。',32,'全唐诗/poet.song.155000.json','["水晶簟冷鋪寒玉，翠帟高張染螺綠。", "陣雲鳥鷺點棋枰，一葉清旗動江曲。"]'),
('a03ed716-98b4-401e-91bd-a09c9a24df48','衰柳','薛季宣','宋','宋诗','song-poetry','','[]','秋草池塘夾黄纈，莫煙淡淡蒙新月。',32,'全唐诗/poet.song.155000.json','["秋草池塘夾黄纈，莫煙淡淡蒙新月。", "擬將攀取贈行人，脫葉枯條不堪折。"]'),
('13c53106-0f2b-4c73-a4b9-6988626ae9ae','嘲欲借予雜稿者  其一','薛季宣','宋','宋诗','song-poetry','','[]','神文道本可言形，退也能藏用即行。',32,'全唐诗/poet.song.155000.json','["神文道本可言形，退也能藏用即行。", "要得任牽馿狗在，無端何似借書生。"]'),
('70d51446-6536-4600-aa1c-07a587745c30','嘲欲借予雜稿者  其二','薛季宣','宋','宋诗','song-poetry','','[]','郎君到底亦何知，奪卷書生真數奇。',32,'全唐诗/poet.song.155000.json','["郎君到底亦何知，奪卷書生真數奇。", "惡語故應多艾氣，殘藤無用寫來詩。"]'),
('adf7dd23-fd4a-4f30-baf2-c4355e04b0b2','送張漕還停舟樊港訪退谷','薛季宣','宋','宋诗','song-poetry','','[]','送客過樊谿，停橈退谷口。',144,'全唐诗/poet.song.155000.json','["送客過樊谿，停橈退谷口。", "不見元次山，靜立躊躇久。", "巉巖兩石峰，猶疑入戶牖。", "杯湖正宜泛，堙塞僅盈肘。", "糞壤瘞杯樽，勿復堪賭酒。", "扁舟泛然者，長歌挈敝笱。", "浩無風塵意，將恐是聱叟。", "自知干進客，對面弗敢扣。", "從之人甚遠，慙顔爲之厚。", "武昌非昔人，望絕不得友。", "它時賦歸歟，湖谷定吾受。", "此心介如石，自誓向樊母。"]'),
('525dcacf-a08f-4ad2-ae3f-2f61a72f7dba','登怡亭故址','薛季宣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','江濱篆貞石，渾謂有神畫。',48,'全唐诗/poet.song.155000.json','["江濱篆貞石，渾謂有神畫。", "閒作故亭遊，心知古人迹。", "竹疏徑微通，天遠荒自闢。", "長江浩無涯，滄溟贏咫尺。"]'),
('659c94b0-b119-4b71-877f-dce71f362b08','行戍西山徒步抵寒溪寺','薛季宣','宋','宋诗','song-poetry','','[]','杖履竹林遊，陟降西山道。',60,'全唐诗/poet.song.155000.json','["杖履竹林遊，陟降西山道。", "匆匆不是閒，倍覺寒溪好。", "潭魚戲憑虛，注水喧幽草。", "埋荒古人迹，樹伐庭如埽。", "桴鼓又相聞，我心爲之懆。"]'),
('afedc43c-354e-4759-be1c-765b14a7e36e','感事','薛季宣','宋','宋诗','song-poetry','','[]','潼華覆哥舒，陳濤僨次律。',48,'全唐诗/poet.song.155000.json','["潼華覆哥舒，陳濤僨次律。", "頼有李豬兒，發憤扶唐室。", "長城賢已遠，惟嶽峻方崇。", "借問南朝事，江流第一功。"]'),
('0b1a0017-5751-4c50-aa05-8ed506ccb34e','陪劉提點遊西山','薛季宣','宋','宋诗','song-poetry','','[]','我家西山下，早晚空翠滴。',96,'全唐诗/poet.song.155000.json','["我家西山下，早晚空翠滴。", "漫仕鄂王城，西山悵難覓。", "不知寒溪上，好景天意錫。", "舉趾異川陸，千里共岑寂。", "丘園動歸念，魂夢時歷歷。", "東吳賽粵甌，信美心愈慼。", "古見似人喜，鄉閈今有覿。", "且作西山遊，笑顔忻自赧。"]'),
('fdc9e66e-9027-4c34-885e-7196a994f330','送中司抵巴口','薛季宣','宋','宋诗','song-poetry','','[]','將迎苦不易，浮湛良亦難。',120,'全唐诗/poet.song.155000.json','["將迎苦不易，浮湛良亦難。", "櫜鞬候使客，無時弄江灘。", "上磧下南浦，風雲怒濤間。", "一葉舞軒昂，五水戲觀瀾。", "朝湖暮淮西，此遊今等閒。", "看盡楚山碧，信宿相與還。", "晴巒挂天衣，水石鳴佩環。", "輕舠簑笠翁，勿與人事關。", "相彼塵外意，心清緒爲闌。", "何時買扁舟，從公看孱顔。"]'),
('b28ce0da-9b22-44ab-a65e-669bda827849','病起','薛季宣','宋','宋诗','song-poetry','','[]','蒸鬰斷梅天，薰風故微細。',48,'全唐诗/poet.song.155000.json','["蒸鬰斷梅天，薰風故微細。", "夢春驚已度，避暑如何計。", "樹老山一色，蛙喧草無藝。", "病興意愕然，到眼多蕪穢。"]'),
('ae11ab02-604a-4c2e-b125-71483333246a','晚雨朝霽林端煜然望之皆寶珠也戲作四十字','薛季宣','宋','宋诗','song-poetry','','[]','晚雨在林麓，朝來弄晴曦。',48,'全唐诗/poet.song.155000.json','["晚雨在林麓，朝來弄晴曦。", "瀾翻漾明月，粲爛生摩尼。", "撒殿固無事，雨天亦何爲。", "少須風景麗，去去將安之。"]'),
('4ab4a2ea-0f02-49c3-81f1-b135d81dcf6f','賞雪','薛季宣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','晃朗長江北，天地都無色。',48,'全唐诗/poet.song.155000.json','["晃朗長江北，天地都無色。", "扁舟撐短篷，一鳥歸飛亟。", "遮莫凍凌兢，如人酒量增。", "鼇山不是照，天地一明燈。"]'),
('1a966103-72f5-4453-913c-78c05a62f2f7','二十五日雪','薛季宣','宋','宋诗','song-poetry','','[]','裘褐透膚寒，𩙖剌春將半。',96,'全唐诗/poet.song.155000.json','["裘褐透膚寒，𩙖剌春將半。", "雪作絮花飛，衮衮攙零亂。", "天地合清明，虛極浮江岸。", "鳥窮棲樹端，走狗欣挑攛。", "埋路已旬浹，四野都瀰漫。", "郊行峭無迹，惟有神光燦。", "茅檐過尺摧，爐火生無炭。", "凍死未能詩，達人方大觀。"]'),
('545b2f7b-e9b8-4f73-af9e-b9a8bb30d78d','和賈簿雪','薛季宣','宋','宋诗','song-poetry','','[]','早起怪吾廬，去天才一尺。',192,'全唐诗/poet.song.155000.json','["早起怪吾廬，去天才一尺。", "始疑大朴還，掩盡幾陳迹。", "比屋皆可封，列土班圭璧。", "照我爛輕明，却似初出日。", "仰頭不可見，恐是老鴉食。", "擬倩玉川子，叫閽聞帝席。", "穹壤合爲容，事乃非人力。", "心膽爲之寒，且退然枯荻。", "曲身今已直，促織休唧唧。", "此意可告客，苦乏鄭莊驛。", "履霜至堅冰，何當介如石。", "鵓鴣有逐婦，相從如娣姪。", "饑蹲苦樹顛，到夜無入室。", "自蠟登山屐，借問何所適。", "我亦無所適，皜皜期太乙。", "庶見太昊氏，鷁視剖我臆。"]'),
('1eff7a39-93a7-4ab3-a67d-33c81c26a605','黄楊生拳石間王彥材以爲贈且賦之走命曰孤山貞榦次韻以酬','薛季宣','宋','宋诗','song-poetry','','[]','孤山有貞榦，不比尋常木。',84,'全唐诗/poet.song.155000.json','["孤山有貞榦，不比尋常木。", "蟠根怪石巔，亭亭自生育。", "百物進相高，位閏知蹙縮。", "散葉傲風霜，樛木外林樕。", "琴桐嶧之陽，逍遥兩俱足。", "夸父徒我庭，如仁示其目。", "股掌翫何言，遂可移風俗。"]'),
('2f5fe47c-a626-4453-a249-f8b04dcefe5e','夜深','薛季宣','宋','宋诗','song-poetry','','[]','爲問夜何其，明滅燈將半。',72,'全唐诗/poet.song.155000.json','["爲問夜何其，明滅燈將半。", "雨雪濺聲繁，霆電流光爛。", "初筵向闌珊，遊子紛繚亂。", "誠知宴樂娛，不怕泥塗漶。", "齋居靜無他，天德全弗畔。", "吟徹借筇頭，假山餘一爟。"]'),
('26b00610-13ce-4e6c-9339-4562b71fef31','偶書','薛季宣','宋','宋诗','song-poetry','','[]','天公不好事，月夜雲埋月。',48,'全唐诗/poet.song.155000.json','["天公不好事，月夜雲埋月。", "遊人且勿遊，辜負良時節。", "霖霪漲塗淖，雷電騰飛雪。", "蓮花燈可憐，對明不同滅。"]'),
('ae91548e-464f-484c-9d54-442832d3f2be','中秋對月戲呈覓舉諸兄','薛季宣','宋','宋诗','song-poetry','','[]','君不見決明混沌江之湄，含胎吸月懷清輝。',150,'全唐诗/poet.song.155000.json','["君不見決明混沌江之湄，含胎吸月懷清輝。", "圓浄唾將珠與璣，又不見明視中原雲月靜。", "跳擲回旋顧形影，生兒往往皆毛穎。", "由來逐物未忘機，勞生吞吐知惟時。", "觀美爲人奚以爲，獨坐金風塵慮省。", "皓月斜河星耿耿，草頭漙露侵膚冷。", "平生不解飲和歌，無人對月醉顔酡。", "月朗清秋奈月何，睡思朅來剛引領。", "林岫參差弄光景，不知月已沈西嶺。"]'),
('ec469b40-892e-4a18-9cd4-0aa3f741843d','開窗','薛季宣','宋','宋诗','song-poetry','','[]','溽暑欲成雨，密雲猶在郊。',72,'全唐诗/poet.song.155000.json','["溽暑欲成雨，密雲猶在郊。", "開窗挹涼飆，遠山見林梢。", "木葉已成陰，野鳥鳴啁啁。", "鏡靜碧池湛，清冷無混淆。", "會意紛萬途，錢荷貫叢茭。", "寂坐一堂上，默默神明交。"]'),
('8ad4f8a8-88f6-4ad9-8cca-d4e78d711728','子規恨','薛季宣','宋','宋诗','song-poetry','','[]','風篠扣吾扉，有人來我語。',204,'全唐诗/poet.song.155000.json','["風篠扣吾扉，有人來我語。", "語好不須多，都不如歸去。", "開門我見客，客子今何許。", "竹下得流虹，人言爲杜宇。", "杜宇昔王蜀，不自安當宁。", "相歸密淫遊，微行時踽踽。", "蛟龍失水困，哀怨成飛羽。", "規名釋爾雅，茲事則然否。", "揚雄蜀本紀，望帝亦賢主。", "仙去正啼規，去思傳往古。", "不妄信斯言，王去非輕舉。", "蒼天悲此民，故使規聲苦。", "脫屣感斯意，八極歸容與。", "到今惟一人，後躅追無侶。", "所以百世下，直指不得數。", "聲盡繼以血，空教瀝肝腑。", "其然豈其然，臣事君看取。"]'),
('ed343b86-f482-4789-bf35-9f12200cd742','聞齊安雜詠板成從沈守求印蒙以爲贈','薛季宣','宋','宋诗','song-poetry','','[]','軑縣西南弦子國，使君昭代文章伯。',256,'全唐诗/poet.song.155000.json','["軑縣西南弦子國，使君昭代文章伯。", "氣吞雲夢納東坡，心在江湖輕赤壁。", "月波蕩漾春山色，崢嶸洲草芊芊碧。", "政平訟簡暇居多，杖屨逍遥神自適。", "到眼風光看如畫，罨畫溪干舊遊者。", "高亭矗立畫不如，坐歗雲屏自天寫。", "使君好客非春申，一夔已足無餘人。", "哦詩五百盡清警，立使江山景物新。", "江山景物古來有，前賢相與天長久。", "近來百草漸埋沒，頼有此詩爲一剖。", "使君好善人如己，鋟板巾箱波遠邇。", "良知何獨此麻城，天下行聞爲商起。", "我拘官禁儃杭葦，跂望亭高衣带水。", "高唐想像賦神遊，遊客言詩詩信美。", "空書從學穆清風，得見異書人見同。", "解嘲不用潘邠老，祇在先生指顧中。"]'),
('7fade9ad-1e43-4d2b-8f72-023d7f67fa18','永嘉行','薛季宣','宋','宋诗','song-poetry','','[]','夷甫清談平子醉，晉俗浮虛喪節義。',224,'全唐诗/poet.song.155000.json','["夷甫清談平子醉，晉俗浮虛喪節義。", "不閑胡虜哭桑林，九伯五侯無一至。", "洛陽宮中胡馬嘶，晉家天子行酒卮。", "驅出如羊晉卿士，婦辱面前爭敢知。", "胡兒居坐漢官立，不許紛紜但含泣。", "刃加頸上始覺憂，追悔前時又何及。", "胡塵坌起昏中土，人死如麻骼如阜。", "草萊萬里無舍煙，氈帳羊裘自來去。", "烏旗霧合胡笳咽，無援邊城腸斷絕。", "瑯琊匹馬竟浮江，棄寘存心堅片鐵。", "天驕一坐昭陽殿，九鼎遷移如轉電。", "禁聲不得悲楚囚，白版金陵謾龍變。", "數奇督運淳于伯，誅斬無名血流逆。", "若思不識是何人，却是帥師臨祖逖。"]'),
('f4437e1c-31bf-474d-9191-f04f60467ac0','雪中送客寒溪堂','薛季宣','宋','宋诗','song-poetry','','[]','前年送客寒溪堂，桃李璀璨寒生光。',131,'全唐诗/poet.song.155000.json','["前年送客寒溪堂，桃李璀璨寒生光。", "今年送客寒溪道，滿望六花形欲槁。", "前歲今年時不同，同爲送客寒光中。", "寒光山積都相似，誰信冬春長有此。", "廣寒宮殿不勝寒，世界瓊瑶無乃是。", "如何名此作寒溪，炎天風色鎮淒淒。", "不緣送客不易到，送客情懷將何爲。", "君不見瑶池高宴非不奇，穆王猶自賦吾歸。"]'),
('b2cbddfb-cf35-4e02-a81f-0a7ba69bedee','可憐','薛季宣','宋','宋诗','song-poetry','','[]','可憐甌越湖山主，厭向黄紬聽衙鼓。',64,'全唐诗/poet.song.155000.json','["可憐甌越湖山主，厭向黄紬聽衙鼓。", "鬭鴨能言名自呼，子規歸去啼聲苦。", "傷情羈鴈怯離羣，適意馴貓哺相乳。", "端是三年貧客官，方春定得離南浦。"]'),
('ffb5231c-d35c-43d7-902d-b580ad9e0bb4','假山次葉師文韻','薛季宣','宋','宋诗','song-poetry','','[]','大隠城居無世喧，疑星塵外非人間。',128,'全唐诗/poet.song.155000.json','["大隠城居無世喧，疑星塵外非人間。", "武都聊試五丁力，一笑天公爲解顔。", "翠蘿散作麻姑髻，枕漱從宜長飯毳。", "青山元自野人物，版築徒然飾東第。", "無論千假須一真，坐對北山南起雲。", "一丘一壑丈夫事，安在窮遊探古文。", "平生樂處天其假，還視王公猶土苴。", "它時買山歸敝廬，定須作屐隨高下。"]'),
('5d5cb850-7b11-420f-a955-d653a4043de8','蘆花','薛季宣','宋','宋诗','song-poetry','','[]','秋風摘索鋪寒雪，敗葉枯條互明滅。',64,'全唐诗/poet.song.155000.json','["秋風摘索鋪寒雪，敗葉枯條互明滅。", "淡蕩閒塘摇夕陽，橫斜斷岸凌高節。", "無言咄咄日書空，執禮拳拳意綿蕝。", "望極氍毹鋪糾結，漁歌何處聲淒切。"]'),
('fc2373dd-60d1-4f09-bdd2-b81436809452','柳絮','薛季宣','宋','宋诗','song-poetry','','[]','駘蕩風光將欲暮，柔條繫日縈霏霧。',152,'全唐诗/poet.song.155000.json','["駘蕩風光將欲暮，柔條繫日縈霏霧。", "寂歷閒庭芳草路，眉開青眼多情度。", "脈脈依依愁不茹，欲翔未定邅容與。", "體輕委蛻韶華去，飄泊晴天離又聚。", "高低上下當何住，捲春匪蹴毬先赴。", "小院深沈鋪月素，卿雲蟬逐凌波步。", "撲樕追隨無定處，冰霜峭覺回寒沍。", "梁王有客能辭賦，蒼凉雪苑知誰訴。", "浮玉神山攻寶璐，屑屑虛花奈憑據。", "還思道藴驚人語。"]'),
('3d8e4de5-045f-43b3-9741-73a2fc5ef13e','香棠','薛季宣','宋','宋诗','song-poetry','','[]','世間元有無窮恨，海外棠花宮錦爛。',152,'全唐诗/poet.song.155000.json','["世間元有無窮恨，海外棠花宮錦爛。", "燒炙東風春未半，濃裝獨立情繚亂。", "博山鑪冷沈煙斷，記語洛妃池側畔。", "袿衣透溼飄香汗，舞罷霓裳高燭看。", "吳苑散花灘彼岸，亦有當初舊遊觀。", "棠梨古逕霞光燦，薔薇露冷衣新盥。", "袖卷燕支紅入腕，噴人蘭芷芳都貫。", "天然種性珍奇玩，嶺海誠知煎可爨。", "擬擷柔柯燃熾炭，裛取緗巾永傳翫。", "它年留得重公案。"]'),
('6f7b1f30-b949-4527-a73e-e0e367a4ebab','元日','薛季宣','宋','宋诗','song-poetry','','[]','星回斗直寅，夏臘變王春。',72,'全唐诗/poet.song.155000.json','["星回斗直寅，夏臘變王春。", "否泰反成卦，乾坤老逼人。", "元正長日月，大化少逡巡。", "世事初無始，天時自一新。", "祇愁梅片片，不見草欣欣。", "善頌聞椒酒，蒼天拱北辰。"]'),
('26d4bac1-bb76-4eee-b896-443257ef3dc8','孔子','薛季宣','宋','宋诗','song-poetry','','[]','蕩蕩東家丘，百世人叵識。',72,'全唐诗/poet.song.155000.json','["蕩蕩東家丘，百世人叵識。", "出類只誇辭，太極無合德。", "堯舜未可過，遠賢真貨殖。", "我欲究遺編，言非是奇特。", "從之如有立，卓爾既吾力。", "大哉贊乾元，一語覓不得。"]'),
('7072f336-26fc-4f5f-bfa7-11c6c0d82f42','比年士風銳進求薦章者殆如辨獄擠排詆訐無所不至客有勸予干當路者二首  其一','薛季宣','宋','宋诗','song-poetry','','[]','見疾多朝士，爭名卒未休。',24,'全唐诗/poet.song.155000.json','["見疾多朝士，爭名卒未休。", "急流須退勇，焉可又隨流。"]'),
('acb49553-42cb-4557-ab5c-1b2c4aec6f37','比年士風銳進求薦章者殆如辨獄擠排詆訐無所不至客有勸予干當路者二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','靜退方真樂，趨時未遽非。',24,'全唐诗/poet.song.155000.json','["靜退方真樂，趨時未遽非。", "不知全道者，進退兩忘機。"]'),
('8ccf76a2-5bf2-407e-8ff8-4b9912ff18b6','痁疾中元式示詩走筆次韻','薛季宣','宋','宋诗','song-poetry','','[]','鄙人病在床，政苦風寒侵。',96,'全唐诗/poet.song.155000.json','["鄙人病在床，政苦風寒侵。", "之子步池上，攀條哦柳陰。", "擲我珠玉辭，瘧鬼毛髮森。", "豁爾脫沈疴，翛然洗煩襟。", "何當漾輕舠，相與從茂林。", "清興諒不淺，此情殊未禁。", "强歌下里曲，賡和白雪音。", "請問覺軒詩，何如梁父吟。"]'),
('701ca69a-cb91-4768-9212-8cc7cffa90c5','江夢孫二首  其一','薛季宣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','聿修去天長，却泛宮亭水。',96,'全唐诗/poet.song.155000.json','["聿修去天長，却泛宮亭水。", "百世友淵明，放意匡廬趾。", "爲愛千金軀，不自知臧否。", "非關走庭下，腰折慙小子。", "少學愴難行，富貴丘所恥。", "一爲田園念，歸思輕脫屣。", "斗大印黄金，各各從所美。", "二士志俱得，何其尚留此。"]'),
('ec1f308c-b764-44e9-ab68-8278f95f3499','江夢孫二首  其二','薛季宣','宋','宋诗','song-poetry','','[]','聿修去天長，元亮歸彭澤。',72,'全唐诗/poet.song.155000.json','["聿修去天長，元亮歸彭澤。", "把版豈難能，趨庭且非昔。", "古之盡心者，樂以所求獲。", "云已廢明民，寧當究安宅。", "大輿輻可脫，無當巵何益。", "君子之所爲，百世空陳迹。"]'),
('719b0a28-7871-4a46-8fed-5743a127acb5','巴口相地作大軍倉','薛季宣','宋','宋诗','song-poetry','','[]','南浦縱蘭橈，打頭清旦風。',48,'全唐诗/poet.song.155000.json','["南浦縱蘭橈，打頭清旦風。", "鳥飛圖障遠，人皺縠紋中。", "銜尾過千柁，頩顔無萬叢。", "端愁少槃瓠，生子亦羣戎。"]'),
('60d6e1b9-b448-4e51-9c52-cf13853740ea','送韓國器登舟至石門視漥樽逮暮乃返','薛季宣','宋','宋诗','song-poetry','','[]','縱步石門下，江山主意勤。',96,'全唐诗/poet.song.155000.json','["縱步石門下，江山主意勤。", "漥樽酌玄酒，未飲吾已醺。", "淵明得聱叟，萬古真同羣。", "杯湖有明齊，退谷今蕕薰。", "我行到殊亭，西日沈就曛。", "陽冰著真蹟，祇恐生玄雲。", "回眸望西塞，慘澹波無垠。", "洄泛樂之子，行舟言采芹。"]'),
('5b7380bb-5611-47e9-beb6-6161108e073d','我客','薛季宣','宋','宋诗','song-poetry','','[]','昔我客荆梁，從事清蕖幕。',144,'全唐诗/poet.song.155000.json','["昔我客荆梁，從事清蕖幕。", "太倉蠹紅腐，吹竽濫東郭。", "去作徒勞吏，青衫走樊鄂。", "撫字亦何心，催科厭笞掠。", "借問差少愧，而今不如昨。", "天遊內于于，紛至攘六鑿。", "鑄此一錯字，爲費幾魏博。", "閑居幸從容，琴書有真樂。", "胡然令閑忙，遠謝乘軒鶴。", "人生百年中，藏舟固非壑。", "顧已習迷途，如蠶自纏縛。", "作詩懺當來，聊以慰寥落。"]'),
('6dd3528d-ac63-4448-8bbd-06fb50e6745e','欲晴又雨終夕震電','薛季宣','宋','宋诗','song-poetry','','[]','日昃望雲氣，西郊將欲開。',84,'全唐诗/poet.song.155000.json','["日昃望雲氣，西郊將欲開。", "丹霞漾晴暉，清風有時來。", "歸坐北窗下，驚霆殷轟豗。", "流電掣飛雨，疾徐鼓巖雷。", "宛轉頹屋頭，終宵響徘徊。", "早起到城市，橫流繞沿洄。", "伊誰補漏天，吾州與蘆灰。"]'),
('e0cd6cbb-846c-4338-b4c7-d6460a192b1c','跋分定錄','薛季宣','宋','宋诗','song-poetry','','[]','人生紅樹花，一謝乃其分。',72,'全唐诗/poet.song.155000.json','["人生紅樹花，一謝乃其分。", "春風儘摇蕩，剛恨分庭糞。", "先賢尚龍豢，缺月何灰暈。", "譬如陌上塵，要是非關運。", "何丘示無朕，子路窮斯慍。", "此理未容言，呼兒課天問。"]'),
('6a230fd7-af60-47c2-bd1b-e18c165a27d4','鄂城篇','薛季宣','宋','宋诗','song-poetry','','[]','袁山野火春風吹，驚飆萬馬爭奔馳。',163,'全唐诗/poet.song.155000.json','["袁山野火春風吹，驚飆萬馬爭奔馳。", "烏龜阪頭蕃草木，化作灰燼張天飛。", "武昌佐史皆好古，煮茗聯鑣訪城府。", "狂生此意復不淺，好事大家何爾汝。", "鄂王城闕煙蒼蒼，鄂王宮殿波茫茫。", "今古都盧一餉頃，不見古人虛引領。", "亳殷豐鎬已丘墟，蠻荆興替將焉如。", "死生建業信徒語，石盆古渡猶多魚。", "古人已去安足齒，近事紛紜尚如此。", "君不見淮淝去歲是豐年，如今千里無舍煙。"]'),
('192eb809-e3bd-4aba-a011-bb0a5821451a','謝王尉見贈龍溪集','薛季宣','宋','宋诗','song-poetry','','[]','稔聞韻鄉名，不識韻鄉面。',144,'全唐诗/poet.song.155000.json','["稔聞韻鄉名，不識韻鄉面。", "班班隠豹文，窺管時一見。", "譬彼闥婆城，尋逐滄流漩。", "聞韶在齊國，九奏何當變。", "王侯韻鄉人，少長居鄉縣。", "韻鄉指迷塗，貽我書一卷。", "森如入武庫，寶璧紛交薦。", "羣玉屣登臨，赫日吹風霰。", "家雞將野鶩，後素詩何絢。", "長安行即到，豈在臨淵羨。", "千金端不如，變色先生饌。", "從可狎江鷗，六籍居貫穿。"]'),
('69a77ed3-387f-47d6-b50d-76a6db9bcfc1','二同舍賦鄂城篇見和文高格古端不可及而仙尉王文措辭侈甚可以參諸臺符羽檄間復次元韻戲酬','薛季宣','宋','宋诗','song-poetry','','[]','生春煖律誰能吹，寸心萬里何當馳。',163,'全唐诗/poet.song.155000.json','["生春煖律誰能吹，寸心萬里何當馳。", "威加海內念方國，也思猛士歌雲飛。", "狂遊不識今與古，闉闍便作潭潭府。", "試憑野叟問吳婆，賜不如回吾與汝。", "高高無事幕穹蒼，湖天無雲湖水茫。", "吳楚爭桑如有頃，東鄂幾人全首領。", "古時封國今爲墟，此心觀古應焚如。", "歸歟衲被蓋頭卧，何妨沸鼎遊如魚。", "舌柔長在强于齒，人間萬事渾如此。", "君不見老聃彭祖俱長年，火化仙乘□□煙。"]'),
('02070021-e7a6-462b-9779-a7cacd79b740','次韻李浩然喜晴','薛季宣','宋','宋诗','song-poetry','','[]','我愧子康之治密，其雨其雨而出日。',208,'全唐诗/poet.song.155000.json','["我愧子康之治密，其雨其雨而出日。", "靡神不宗始霶霈，將爲有年吾事畢。", "豈其霢霂澍霖霪，霮䨴又爲心首疾。", "視將圭璧走羣望，祈社禜門勤屈膝。", "誠知惡積怒神天，流毒匪緣寒自慄。", "甫田千畝垂有秋，刈穫敗之方秀實。", "橫流場圃澆洋洋，茁茁禾頭多耳出。", "仰天何怨俯何尤，退省過愆知自失。", "牢愁僕僕事吁嗟，風雨敢辭頻沐櫛。", "忱誠雖至蟣蝨微，舒慘蒼穹焉可必。", "都緣民困不聊生，重以凶荒神以卹。", "羲和叱馭黑龍僇，倏忽清明開萬室。", "不知帝力固全真，謂我貪天寧直筆。"]'),
('670ae6c3-7163-4ef6-a824-c5e8f169f515','河豚','薛季宣','宋','宋诗','song-poetry','','[]','豈其食魚河之魴，河豚自羨江吳鄉。',256,'全唐诗/poet.song.155000.json','["豈其食魚河之魴，河豚自羨江吳鄉。", "瞋蛙豕腹被文豹，刖如無趾黥而王。", "我生甌東到閩方，規魚貫見梅花裝。", "梅青不肯候春雪，荻芽靜笑垂飛楊。", "古來多魚吳武昌，薄遊三月新初嘗。", "西施乳嫩可奴酪，馬肝得酒尤珍良。", "無愁縷縷結中腸，豐美肥腯如切肪。", "外皮甘滑裏皮厚，令人忘却美烏郎。", "舉之東海來三江，會聞清濁期滄浪。", "白龍未免豫且困，膨脝唯唯浮魚梁。", "氣衝毬鞠何彭彭，地遠都無橄欖香。", "不知深入恣遊泳，極情性命徒爲戕。", "腊毒厚味能人亡，何須西子齊文姜。", "甚美由來必甚惡，直它一死言爲長。", "鮰魚俗物休相妨，良藥相傳海上方。", "蘆根槐子豈足貴，生鳳之腦黄龍湯。"]'),
('7473a61f-b682-42c6-88c1-73f7607596fc','東坡在齊安賦海棠詩爲天下絕唱年來絕無此種許仲蟠取之武昌作詩寄示','薛季宣','宋','宋诗','song-poetry','','[]','武昌三月春草生，攙紅鬭白皆羣英。',224,'全唐诗/poet.song.155000.json','["武昌三月春草生，攙紅鬭白皆羣英。", "就中一種信奇絕，芳菲壓盡吳王城。", "侈非丹芍明非玉，艷陽天日擎高燭。", "從教深淺色相形，不以冰清爲不俗。", "文王自昔基靈囿，綠綬朱裳燕朋友。", "醺醲心醉鄂裳裳，痛飲醇醪不關酒。", "流烏一下新王舟，颭從火御乘丹丘。", "傳得飛霞在海外，千齡只自生炎洲。", "靈砂不到姮娥竊，幾時赤鳳來丹穴。", "趙壘新張漢幟時，闉闍滿望猩猩血。", "少陵昔漫稱詩豪，忘言跨鯉輸琴高。", "剛被東山興妖女，竹菰未可稱蟠桃。", "靈根不分生赤壁，遠在水南呈赫奕。", "朱鳥憑將寄德鄰，告言莫看同巾幗。"]'),
('07ce32e0-1982-436c-8bb7-f408efb5ec96','寒溪送客時李花盛開山谷彌望','薛季宣','宋','宋诗','song-poetry','','[]','寒溪送客荒徑迂，玉華璀璨晨光虛。',112,'全唐诗/poet.song.155000.json','["寒溪送客荒徑迂，玉華璀璨晨光虛。", "仙遊在處見李白，山遠無地尋陶朱。", "雪霜天色際江岸，瓊瑶世界連廷除。", "飄然幾許認姑射，恍若一夢驚華胥。", "寶珪環璧會王路，鐵衣鋒刃交兵車。", "三王純素未云已，百姓渾茫方皞如。", "神清洞古世緣在，梁園祇是空遺書。"]'),
('b26623c1-f559-4e0a-bc9b-d8dd67e3ac4a','蟻䎘','薛季宣','宋','宋诗','song-poetry','','[]','啄䎘玄駒子，當緣一食耳。',139,'全唐诗/poet.song.155000.json','["啄䎘玄駒子，當緣一食耳。", "雪貓與䎘俱咽之，玄駒乃與䎘俱靡。", "古人防未然，精意本如此。", "相教各自慎，豈有失身理。", "䎘子輕此蟻，終焉食于彼。", "蟻亦甘啄䎘，但知䎘之美。", "寧知腊毒生厚味，大小相吞不摇齒。", "蟻微不足食，反以食䎘死。", "不如夏蟲獨飲露，壽不知冬亦良是。", "君不見慕容赫連攘臂起，楚漢存亡竟何似。"]'),
('2f58cb4f-ccfc-405a-966b-6da651c4cf1c','釣臺阻風去得風便','薛季宣','宋','宋诗','song-poetry','','[]','先生非釣名，魚釣清泠水。',288,'全唐诗/poet.song.155000.json','["先生非釣名，魚釣清泠水。", "太空長廓然，浪迹秋光涘。", "人憂我何憂，忘怒亦忘喜。", "建武非漢元，詎有留侯起。", "神明旋地軸，姓字更七里。", "雲臺已埋沒，嚴瀨殊清泚。", "峨峨二釣臺，高插煙霞裏。", "首陽遠相比，萬祀恒不圮。", "我來經舊廬，敢卜瞻遺几。", "東風迴我舟，江步時須艤。", "仰觀嚴象設，敬拜豁煩鄙。", "曾臺暢登臨，無復徒仰止。", "縈迂古道屈，望望扳蘿藟。", "崇基介巖石，特立端不倚。", "削成二山碧，平正章如砥。", "衆山鬰青葱，環合紛碨礧。", "清塵森萬象，觸睫同一視。", "古人不可見，可見安仁美。", "旅情殆忘返，回棹西風駛。", "青蒲挂一席，入望俄城市。", "瞥如周變秦，物物非古始。", "乃知主人意，待我非朱紫。", "送迎因下風，忙遽均倒屣。", "烹茶出清泉，盤饌羅雙鯉。"]'),
('4fbdeea0-e2a1-4b3d-b0da-e775fc69aa43','乙亥歲東遊會稽謁禹陵過馬臻祠下詢所謂鑑湖者則已堙塞爲民田因賦','薛季宣','宋','宋诗','song-poetry','','[]','登會稽，瞰長湖，漪漣萬頃皆平蕪。',353,'全唐诗/poet.song.155000.json','["登會稽，瞰長湖，漪漣萬頃皆平蕪。", "桑田變改唯聞說，豈信古今人事殊。", "往時夏后禹，道川治水勞馳驅。", "四支疲弊跛其足，過門弗視兒呱呱。", "衆流宗海出平陸，滋人巨浸因卑洿。", "百神效職來大計，勤民遠狩崩于嵞。", "名山立郡此焉始，明明功與日月俱。", "馬侯有漢二千石，施仁復古蘇燋枯。", "浚深倍薄拂古鏡，還使墝埆成膏腴。", "陰邪醜正富權戚，居肓如鬼捐其軀。", "大君良吏不復見，茫茫陳迹日就無。", "玻璃湛湛長芳草，蛟龍窟宅生菰蒲。", "前功不錄倚隳棄，誰何聚斂浮穿窬。", "庸情非聖決陂澤，遷移膏潤爲官租。", "昔人舊事已無在，猶有水則{石毚}長途。", "高田燥仰下沮洳，雨晹無歲均沾濡。", "咄哉榮利歸乃室，是邦黔首其何辜。", "反令二主神，淫祀煩此都。", "王陵委積蠹明幣，守祠澆酹傾清酤。", "禳禱兩無已，跳梁飽妖巫。", "享祭緣報誠，嘉猷委泥塗。", "神靈血食已非分，無爲耗黷令人吁。", "復績悵何從，我心徒自㤤。"]'),
('53d9b099-38aa-4bbb-b398-25eb966a21b6','張村','薛季宣','宋','宋诗','song-poetry','','[]','皇羲寂已久，澆俗無還淳。',168,'全唐诗/poet.song.155000.json','["皇羲寂已久，澆俗無還淳。", "如何張村甿，杳杳全其真。", "豈不有妻孥，茅茨甘賤貧。", "豈不憚疲勞，務時勤耔耘。", "脫俗未爲貴，而今焉辟秦。", "青城足躋攀，那染龜城塵。", "枸杞薦盤蔬，殊非關養身。", "安常樂有餘，熙然阜長春。", "奚其壽而康，無知斯體仁。", "靜言逐臭夫，迷途少知津。", "猥云老人村，郊荒絕酸辛。", "筋骨由堅强，誰謂存其神。", "井蛙議滄溟，夫豈窺崖垠。", "作詩賦張村，逝將同野人。"]'),
('93b274d4-4c5f-4a44-bee1-8c53d21aaa85','舟行樊港望竹間石上李花盛開','薛季宣','宋','宋诗','song-poetry','','[]','天下清且奇，無過竹與石。',132,'全唐诗/poet.song.155000.json','["天下清且奇，無過竹與石。", "安得皎然者，素質照人白。", "靜立笑東風，篁岡蟠罅隙。", "望之輕以明，儼似雪初積。", "青草鬭欣欣，不比梅花坼。", "矯首不可到，獨自憑空碧。", "翠帷篠青青，巖崿正虛席。", "我疑辟俗翁，方外友三益。", "又是秦帝宮，傳視相如璧。", "人情不易知，幽致矧可射。", "相從知未能，灰心從此畫。"]'),
('537ea4fc-1b46-4480-bef8-b79f07930bc7','遊韓魏王書堂','薛季宣','宋','宋诗','song-poetry','','[]','蘭生深谷中，香不爲人採。',144,'全唐诗/poet.song.155000.json','["蘭生深谷中，香不爲人採。", "明珠含蚌胎，融曜鎮長在。", "襲來馨滿衣，磨琢未曾璀。", "君子行之常，出處安有改。", "韓王開此居，山立中𡾋嵬。", "窈窕二遊女，易歲昏有待。", "柳下學東門，百世人不逮。", "乃心毋自欺，匪轉焉可怠。", "用之建邦國，所宜烹大鼐。", "我來追後塵，六逸先駑駘。", "美人意桃李，德誼見芳茞。", "瞠若眩吾明，五色騰日彩。"]'),
('35c51760-1046-4c53-ab59-9f364b11b5f6','二女篇','薛季宣','宋','宋诗','song-poetry','','[]','姈娉二美人，幽閒真種性。',156,'全唐诗/poet.song.155000.json','["姈娉二美人，幽閒真種性。", "色秀雪窗梅，衣冠麗修正。", "巖巖韓稚圭，寂寞自清靜。", "虛室埽齋居，展禽當季孟。", "神遊問寒暄，不得窺信行。", "怪力視茫茫，久要交善敬。", "語之非異類，安民公有命。", "蓋聞楚靈均，汩羅陳死證。", "二子終孝慈，雙玉澄江映。", "當初黄鄂人，盪槳追遊泳。", "端午化成俗，龍舸長奔競。", "事神微有道，角黍勞將迎。", "非鬼且非仙，世士憑誰偵。"]'),
('2579cb3e-1d83-4381-839b-4af3bc51edd3','被命行田未半而羽書至造砦者萬別駕其逼方甚繼復有聞','薛季宣','宋','宋诗','song-poetry','','[]','冷火不再然，事成難重言。',192,'全唐诗/poet.song.155000.json','["冷火不再然，事成難重言。", "我苦不憚煩，興言念丘園。", "丘園未得歸，行田縣西原。", "暑雨霑我衣，萊蕪絆我轅。", "熊羆百萬衆，未易輕營屯。", "東征到洪道，折柳臨津門。", "峨峨鳳皇臺，墟吳際荒村。", "南湖湛淪漪，𭲟渺波瀾翻。", "路回溪谷間，子規叫煩冤。", "流血良自悲，誰念望帝魂。", "不羞五斗腰，折支別駕尊。", "松門故鄉類，去路馳且奔。", "羽書如流星，萬室崇屏藩。", "荒凉舊村甿，億兆不一存。", "哀聲聽杜宇，側耳心昏昏。", "山澤久已竭，職死何足論。"]'),
('bc3e622a-6b3d-4e11-b1b3-24a4edfe8378','某爲令無狀不能化服奸盜至加之刑僇仲蟠鄉丈不以爲過又哦詩以寵之是重某之不肖而播其惡于衆也感愧之劇次韻以酬','薛季宣','宋','宋诗','song-poetry','','[]','漢法在彝鼎，三章豈不嚴。',144,'全唐诗/poet.song.155000.json','["漢法在彝鼎，三章豈不嚴。", "姦宄恣暴亂，官刑廢舂鉗。", "未若箕山翁，頑夫偃風廉。", "予慙斯人徒，爲容善謙謙。", "敺民陷之辟，淫刑視齊殲。", "處事禁太速，宜犴非爲淹。", "丹書對婦泣，職死夫何嫌。", "專誅逮垂盡，吾辜倍相兼。", "曾聞鄒魯間，禮義人自恬。", "商君就有道，絳水驚閭閻。", "念此一歎息，歸來賦陶潛。", "南山信崇極，能無刺巖瞻。"]'),
('08be25ba-ac5b-45c5-a019-2590de13a7a4','記遊詩','薛季宣','宋','宋诗','song-poetry','','[]','先生混物化，浩若鶴與猿。',120,'全唐诗/poet.song.155000.json','["先生混物化，浩若鶴與猿。", "詰曲此世間，翛然脫籠樊。", "冥心遂無物，得意亦忘言。", "客至不點茶，猶嗔破苔痕。", "相逢蜀成都，過我故縣村。", "遐觀夢中夢，南膜佛因緣。", "鄭人決真妄，子産不能賢。", "寥哉天地間，誰省物性偏。", "夢覺各有殊，從他見一邊。", "浩歌歸來乎，虛堂好晝眠。"]'),
('eb4d68e5-d17d-49b8-a477-77ee63b77de0','跋蜡虎圖','薛季宣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','歲云暮矣露爲霜，枯條脫葉衰柳黄。',240,'全唐诗/poet.song.155000.json','["歲云暮矣露爲霜，枯條脫葉衰柳黄。", "郊原寂歷無人鄉，獖牙之豕充稻粱，含臕以遊神氣揚。", "有班者虎蹲在旁，低頭妥尾不大忙。", "豕行過之不虎防，虎往搏之搤豕吭。", "豕亡故步聲喚長，虎如抱兒未遽央。", "豕形雖在身命亡，不如安之充虎腸。", "得之紙本君何從，仙人道士形已忘。", "解衣槃礴躶宋王，虎冠虎鞹虎跳踉，百獸望之怖以惶。", "寫鸇鳥雀爲罷翔，匡廬有潔清祠望。", "請君懸之政事堂，坐令帖伏犬與羊。", "君不見大索之祭通八方，盛德百世祠是常。", "又不見螗蜋捕蜩雀捕螗，死生得喪不可償，虎哉寧知蝟𧑐能爾戕。", "是非遠在天一方，君其寶之永世藏。"]'),
('8cd0813f-bea0-4256-82fc-030af763016f','孫元可賦張公石室詩句語險怪辭峰秀拔讀之如神遊洞府而陵果爲之奔屬也非身行此洞不知此詩之工蓋其質似盧仝而文麗多之如又加鞭當千里一瞬其視劉叉馬異得名浪矣詩文與我過當誠無足以當之牽韻勉酬真添薪煮簀之舉','薛季宣','宋','宋诗','song-poetry','','[]','君不見談天衍有言，九州之大惟一州，無論青冀并營幽。',391,'全唐诗/poet.song.155000.json','["君不見談天衍有言，九州之大惟一州，無論青冀并營幽。", "我其放言學鄒子，將子聽之無我尤。", "我騎一紙白馿子，趷梯趷塔走上南山頭。", "萬里以意行，一息不暫留。", "谽谺到空洞，且作秉燭遊。", "呼來混沌老蝙蝠，爾作精怪我則不。", "從教激風怒竅拔木折石，一去旬有五日而後返，但是有戶則可由。", "積蘇累塊雖云巧，達觀只與蟻壤侔。", "我有五雲車，駕以六蒼虯。", "日月行已揭，無人觸虛舟。", "何曾見爾懸旌鳴佩朗裝欲飛動，玉柱校立直以修。", "大撓甲子有窮盡，爾乃祿命難考求。", "皇天大地僅若一雞子，金烏玉兔銜得曉夜作箭浮。", "我不知爾許事，政覺兩耳風飂飂。", "託死不復生，一死可作道者流。", "況乃漢時五斗米師星河耿雙眸，石壇一坐一千歲，坐視生滅水上漚。", "水上漚，且罷休。", "休無休于無作，樂無樂于無憂。", "仙人與世人，壽夭如相酬。", "清清爰靜爰自正，此舉獨步不可儔。", "信是神仙足官府，蜂房戶牖封君侯。", "我偶作此言，不比亦不周。", "爲何孫卿子，謂我阮與劉。", "爲我謝孫子，我才愧爾天一陬。"]'),
('ae2fa2e7-6c8c-4e12-97ed-94a03b41f5bd','春愁詩效玉川子','薛季宣','宋','宋诗','song-poetry','','[]','春陰苦亡頼，巧解窮彫鎪。',363,'全唐诗/poet.song.155000.json','["春陰苦亡頼，巧解窮彫鎪。", "入我方寸間，釀成一百萬斛傷春愁。", "我欲挹此愁，寸田無地安愁芻。", "沃以一石五斗杜康酒，醉心還與愁爲謀。", "愁腸九轉疾車轂，擾擾萬緒何綢繆。", "愁思儻可織，爭奈百結不可紬。", "我與愁作惡，走上千尺高高樓。", "千尺遡雲漢，只見四極愁雲浮。", "都不見銅盤之日，缺月之鉤。", "此心莫與明，愁來壓人頭。", "逃形入冥室，關閉一已牢。", "周遮四壁間，羅幕密以綢。", "愁來無際畔，還能爲我添幽憂。", "我有龍文三尺之長劍，真剛不作繞指柔。", "匣以明月通天虹玉燭銀之寶室，可以陸剸犀象水斷潛伏之蛟虯。", "云昔黄帝軒轅氏，用斬銅頭鐵額橫行天下之蚩尤。", "擬將此劍斬愁斷，昏迷不見愁之喉。", "若士爲我言，子識愁意不。", "愁至不亡以，愁生有來由。", "閑愁不足計，空言學莊周。", "日中之景君莫避，處陰息景景不留。", "疾行嫌足音，不如莫行休。", "因知萬慮爲縈愁之繂，忘懷爲遣累之舟。", "歸來衲被蓋頭坐，從他鼻息鳴齁齁。"]'),
('7580ec1b-36dd-4419-bc1c-10b44877027a','古意','薛季宣','宋','宋诗','song-poetry','','[]','荷芰藕生蓮，每憶心中苦。',24,'全唐诗/poet.song.155000.json','["荷芰藕生蓮，每憶心中苦。", "擬掇斷根苗，絲結千千縷。"]'),
('22c17f51-7693-4852-99fe-a7911cb8019b','侯婦歎三首  其一','薛季宣','宋','宋诗','song-poetry','','[]','侯婦匡坐歎，蕩子新賜冊。',24,'全唐诗/poet.song.155000.json','["侯婦匡坐歎，蕩子新賜冊。", "先自薄恩私，嬪嬙幾巾幗。"]'),
('a5c2b1d3-3696-43bf-bb5b-3ddabe3dfc4a','侯婦歎三首  其二','薛季宣','宋','宋诗','song-poetry','','[]','莫作侯家婦，鳲鳩理清瑟。',24,'全唐诗/poet.song.155000.json','["莫作侯家婦，鳲鳩理清瑟。", "幾許白頭人，同心綰同室。"]'),
('20b251a3-cfad-4fe9-8b73-d0c1f301a6ab','侯婦歎三首  其三','薛季宣','宋','宋诗','song-poetry','','[]','侯婦且勿歎，金玉多滿堂。',24,'全唐诗/poet.song.155000.json','["侯婦且勿歎，金玉多滿堂。", "蛾眉不讓人，當奈薄情郎。"]'),
('33358ccf-ded7-46d8-898c-42d84ddc7ba9','團扇歌三首  其一','薛季宣','宋','宋诗','song-poetry','','[]','田田白團扇，輕綃寫蟬雀。',24,'全唐诗/poet.song.155000.json','["田田白團扇，輕綃寫蟬雀。", "用之却炎暑，生風郎掌握。"]'),
('64edcd58-640d-46b2-81b0-1404f91f142c','團扇歌三首  其二','薛季宣','宋','宋诗','song-poetry','','[]','團扇復團扇，羞郎引遮面。',24,'全唐诗/poet.song.155000.json','["團扇復團扇，羞郎引遮面。", "顧景强躊躇，隙月雲端見。"]'),
('4aaa21bf-10c8-48db-8e4e-490400e7f132','團扇歌三首  其三','薛季宣','宋','宋诗','song-poetry','','[]','團團白紈扇，奉君揮素手。',24,'全唐诗/poet.song.155000.json','["團團白紈扇，奉君揮素手。", "餘凉入長夏，結交貴經久。"]'),
('c0b3f9e3-4c28-4dcb-9535-dba0d7910166','胡無人行','薛季宣','宋','宋诗','song-poetry','','[]','胡無人，非無人。',172,'全唐诗/poet.song.155000.json','["胡無人，非無人。", "銀山蹀躞胡馬羣，甲光射日開金鱗。", "鏃長飛雨旌填雲，轟庭雷鼓聲轔轔。", "柔然之蛇陣囷蝓，傾河鞭石居逡巡。", "浩歌但來輕比鄰，白登豳國公當聞。", "帝羓久作冥漠君，高辛狗食吳將軍。", "胡兒弧矢非周身，控弦雖多將累人。", "狼跳鳥擊虛遊魂，驕矜一息爲微塵。", "梟雛井底蛙彌尊，餘殃積惡天公嗔。", "胡無人，聞不聞。", "衛青去病迹已陳，竇侯乳臭椒房親。", "胡無人，燕然錯落銘王勳。"]'),
('d4735540-848f-4d5a-bd9c-bb4611de5377','木蘭將軍祠','薛季宣','宋','宋诗','song-poetry','','[]','人怯山西種，誰知掌上身。',48,'全唐诗/poet.song.155000.json','["人怯山西種，誰知掌上身。", "豬羊刀霍霍，車馬道轔轔。", "幕府開娘子，旂常紀亂臣。", "夢回清鏡對，千古茜裙新。"]'),
('c35d2472-3e9c-4be3-9b5e-45b5d14d8aaf','車遥遥篇','薛季宣','宋','宋诗','song-poetry','','[]','車遥遥兮路逶迤，思夫君兮君今知。',48,'全唐诗/poet.song.155000.json','["車遥遥兮路逶迤，思夫君兮君今知。", "今安適兮南入楚，願爲聲兮逐君語。", "君不言兮聲不聞，聲何當兮言在君。"]'),
('0a00ccdc-4972-4c49-9c1a-0a2ed96329e2','明妃曲','薛季宣','宋','宋诗','song-poetry','','[]','闕下烏雲暗黑旗，未央高會送將歸。',256,'全唐诗/poet.song.155000.json','["闕下烏雲暗黑旗，未央高會送將歸。", "天子傳觴從官勸，單于今正天驕兒。", "上林關鎖多芳菲，王嬙困睡花葳蕤。", "中人驚起道宣喚，和戎却自拚蛾眉。", "徘徊顧景傷春啼，秀色悞身生不知。", "工師萬死未足謝，丹青始信君難欺。", "冤莫冤兮長別離，盟莫渝兮徒自疑。", "氈車未免下宮殿，記得當年初入時。", "眉山淡掃雙螺垂，擬高門戶生光輝。", "姑姊提携父母送，不教含涕登丹墀。", "赭黄有淚濡龍衣，此身雖是觸事非。", "胡沙萬里少花木，胡中爭看真閼氏。", "言語不通心儘悲，琵琶琢就彈哀思。", "君門萬里不易到，檀槽撥斷商弦絲。", "窮寒絕塞人蹤稀，時有天邊霜雁飛。", "憑誰說與漢卿相，西施莫忘真元龜。"]'),
('746e4d11-6051-4d9a-bab9-b28ce4d0c88a','惜花引','薛季宣','宋','宋诗','song-poetry','','[]','廢圃晨遊，舊觀歷歷。',73,'全唐诗/poet.song.155000.json','["廢圃晨遊，舊觀歷歷。", "三徑已荒蕪，歌酒地，悄悄無人迹。", "爲山傾仄，支柱皆名石。", "桃李無言，爲人岑寂。", "早綠暗紅稀春去也，歎繁華難覓。", "落花如積，誰與東風惜。"]'),
('92615495-0ff1-429c-b7ee-5770f56c438c','楊叛兒','薛季宣','宋','宋诗','song-poetry','','[]','楊婆兒，共戲來。',72,'全唐诗/poet.song.155000.json','["楊婆兒，共戲來。", "白門楊柳正依依，穩稱暝鴉棲。", "博山鑪侈沈烟裊，儂心懽緒繆紛擾。", "語含別意淚空流，未掩宮闈齊閣曉。", "齊閣曉，祇傷悲，婆兒殺儂，那復相思。"]'),
('ed985fe6-25e7-4504-afc8-6ecdc500b9fe','楊白華','薛季宣','宋','宋诗','song-poetry','','[]','楊白華，柳眼自生息。',58,'全唐诗/poet.song.155000.json','["楊白華，柳眼自生息。", "風傳華落大江東，綰毬團絮無多力。", "柳眼落落不可見，淡蕩遊絲空萬億。", "由來宮樹未成陰，踏歌驚斷諠笳篴。"]'),
('2490a4b5-e607-4515-b107-7b046b174d98','秋扇詞','薛季宣','宋','宋诗','song-poetry','','[]','少婦織流黄，織就中秋月。',108,'全唐诗/poet.song.155000.json','["少婦織流黄，織就中秋月。", "上有乘鸞女，肌膚皓冰雪。", "裝成一携手，奉君端暑月。", "感君清涼意，薰風爲君發。", "落葉下驚秋，與君此回訣。", "素質不勝愁，從衡網珠結。", "招摇邈煙露，青鸞影遼絕。", "有物感君懷，騰口知何說。", "分命故應然，不是君心別。"]'),
('172420f6-36bc-4668-bd42-cccc90ed5d26','秋空辭','薛季宣','宋','宋诗','song-poetry','','[]','秋空浄無瑕，耿耿掛明月。',156,'全唐诗/poet.song.155000.json','["秋空浄無瑕，耿耿掛明月。", "有人捉月試騰身，騰身直上黄金闕。", "黄金宮闕高嵯峨，駢頭從目相誰何。", "仙人顧之拍手笑，使我言語能多囉。", "言語多囉還有考，天公何言固無口。", "秦書趙史欺我哉，紫氣充庭是天道。", "通明廣殿凝非雲，日月照曜如環循。", "蝦蟆老鴉恣吞啖，我欲叱之神羊嗔。", "夢中將謂天難知，夢回塵事故依依。", "天大故能成變化，覺夢不勞評是非。"]'),
('017acfee-340f-4ff4-9b4e-ea6b4ae38f11','擬古','薛季宣','宋','宋诗','song-poetry','','[]','春飛紫燕秋飛鴻，雙成阿母長相逢。',80,'全唐诗/poet.song.155000.json','["春飛紫燕秋飛鴻，雙成阿母長相逢。", "誰家窈窕窺綠窗，藕花菡萏清池風。", "璧璫翡翠雙明月，寶釵玉釧衣如雪。", "年可四三當有情，語音嬌軟疑卿卿。", "天公一笑回金電，不似當初不相見。"]'),
('f45cfc7c-6c4e-43a8-8d7d-bc4e5ff1a7a8','相逢狹邪間','薛季宣','宋','宋诗','song-poetry','','[]','敺車逕長坊，長坊劣容綫。',204,'全唐诗/poet.song.155000.json','["敺車逕長坊，長坊劣容綫。", "繚遶狹邪間，相逢記君面。", "君家人共知，共知不難求。", "朱門颺疏柳，虹梁架芳流。", "庭除清且閑，馳道直以修。", "中堂真壯哉，黄戶雙蚩頭。", "亭亭丹桂華，燦爛明人眸。", "主君三男兒，三兒例封侯。", "大兒尹京都，中兒相凝旒。", "小兒奉朝請，籠街進鳴騶。", "三兒俱來歸，青絲控驊騮。", "三兒俱上堂，大人百不憂。", "三兒俱入室，四座沈煙浮。", "蛾眉盡妖艷，三婦不可侔。", "大婦鼓鳴瑟，中婦彈箜篌。", "少婦獨凝眝，酡顔半嬌羞。", "丈夫且躊躇，世有此樂不。"]'),
('67bfc94e-0fb3-42cc-a94d-b119bc0eceeb','怨歌行','薛季宣','宋','宋诗','song-poetry','','[]','男兒多負心，女心良易知。',156,'全唐诗/poet.song.155000.json','["男兒多負心，女心良易知。", "琴音和且諧，何以得淫思。", "文君慕相如，慇懃夜于飛。", "不惜鷫鸘裘，愁成遠山眉。", "茂陵獨何事，爲顰效東施。", "興言念疇昔，卿紅怳如璣。", "彈作白頭吟，深心寫琴詩。", "郎聽弦上聲，妾志終不移。", "清商感人情，兩意亦以非。", "文君獲所願，相如悟沈迷。", "寧能已消渴，琴臺遂同歸。", "妾欲理絲桐，絲桐亮以悲。", "謂言無終極，當非長別離。"]'),
('3cd59bdd-4333-43bc-a9f5-dc6461ac339b','艷歌行','薛季宣','宋','宋诗','song-poetry','','[]','雝雝雲間鴈，南飛北軒翥。',84,'全唐诗/poet.song.155000.json','["雝雝雲間鴈，南飛北軒翥。", "妯娌幾多人，兒夫獨羈旅。", "郎書憑誰寄，妾意憑誰語。", "頼有雙鯉魚，尺素爲懷取。", "歡子今來歸，還羞入朱戶。", "告之莫流宕，天靜星可數。", "星子何昭昭，行不如歸去。"]'),
('646161c6-7d99-471f-83d6-06607a0d2f25','妾薄命','薛季宣','宋','宋诗','song-poetry','','[]','魚生蒲藻中，河水以爲依。',288,'全唐诗/poet.song.155000.json','["魚生蒲藻中，河水以爲依。", "傾河竭其波，魚藻當何歸。", "妾作君家婦，君時尚卑微。", "勤身紝絲纊，夜午不下機。", "憫君書幌勞，寧教食無薇。", "緝緝兒與女，號寒復啼饑。", "憐之小顔色，飣餖攣斑衣。", "君登名利場，妾喜神欲飛。", "今君位通侯，蚩頭建黄扉。", "忍令家人子，舉動生光輝。", "妾昔顔如花，因君損芳菲。", "君去春無迹，潸然淚紅璣。", "自憐承事君，爲他筯頭肥。", "妾命薄如紙，虛牀但歔欷。", "憶昔在家日，憨癡弄庭闈。", "爺娘念嬌子，深心愛其頎。", "人間愁未知，結髮爲君妃。", "姑嫜時在堂，色養親無違。", "慇懃百憔悴，可道才依稀。", "誰言當見君，崇高位巍巍。", "君官知漸穹，人事覺已非。", "非關君二三，妾貌凋寒威。", "恨無長門賦，可以使君磯。", "更長不再眠，入戶多蛜蝛。"]'),
('8f9ddc1e-1e60-4c64-9d8f-1f13e19daded','陌上桑','薛季宣','宋','宋诗','song-poetry','','[]','羅敷秦氏女，皓腕潔如霜。',120,'全唐诗/poet.song.155000.json','["羅敷秦氏女，皓腕潔如霜。", "寶釧瑳明月，領巾疏以長。", "柔桑正沃若，采采官路旁。", "使君從南來，一見神已傷。", "五馬會且止，調之逢國王。", "自名良家婦，狂夫漢中郎。", "閨門甚修整，芝蘭遠芬芳。", "奚爲致此語，不是邯鄲倡。", "去矣勿復顧，風來語流香。", "蕩子踏歸陌，駕言割人腸。"]'),
('62a7cc91-140c-4aba-b809-11b5f3af771f','從軍行','薛季宣','宋','宋诗','song-poetry','','[]','人道從軍樂，我道從軍苦。',168,'全唐诗/poet.song.155000.json','["人道從軍樂，我道從軍苦。", "爲問何所苦，無苦汩沒汝。", "汩沒何可傷，政可虜戎王。", "萬里浪馳逐，征役未遽央。", "太行汝勿登，回復九羊腸。", "黄河汝勿航，波流水湯湯。", "胡然棄平生，欲往無梯梁。", "夫君且淹留，後繼當汝忘。", "長蛇叵復夢，南山强深藏。", "我甲豈不堅，我馬豈不良。", "人生會有死，義死良所傷。", "將軍不汝信，談笑成奔亡。", "誰乎幸際會，虎服而皮羊。", "之子方丈食，何時飽粃糠。"]'),
('97908d75-90df-4458-8cd8-9be3ce154a73','戚戚復戚戚','薛季宣','宋','宋诗','song-poetry','','[]','戚戚復戚戚，如此春意闌。',180,'全唐诗/poet.song.155000.json','["戚戚復戚戚，如此春意闌。", "紅梨褪深暈，青梅結微酸。", "向之一悽慘，饑腸廢朝餐。", "姮娥五圓缺，美人隔雲端。", "衷情叵自禁，陡覺衣带寬。", "芳菲日彫謝，動作不遑安。", "咄哉黄栗留，接翮語何繁。", "小鳥得于飛，而我別所歡。", "夜來風雨惡，中唐水漫漫。", "故鄉貧亦好，楚客日南冠。", "男兒志四方，愧此柳下官。", "安得買山錢，靜處把釣竿。", "高懷未易償，歸有道路曼。", "匡坐作遐想，心體胡自胖。", "行行大刀頭，無生話團欒。"]'),
('a5359f56-6166-4f16-93d1-ec6fd702ed5d','自君之出矣','薛季宣','宋','宋诗','song-poetry','','[]','自君之出矣，珠網弦箜篌。',168,'全唐诗/poet.song.155000.json','["自君之出矣，珠網弦箜篌。", "憔悴損容色，晨朝懶梳頭。", "頭上雙爵釵，脫髮應難留。", "因心持寄君，君還知意不。", "金以表妾心，釵能感君眸。", "長安多美人，陌巷多高樓。", "君如有兩意，持此買名謳。", "妾本侯家女，生平不解愁。", "十九爲君婦，如今幾回秋。", "生兒妾樣長，君方遠行遊。", "妾顔益以悴，君心日悠悠。", "方諸空有淚，圓月難爲鉤。", "死灰不復然，知君亦行休。", "寄言天地間，于以寫我憂。"]'),
('ab6804a5-317b-43bb-842d-641ee6776972','石上可種麻','薛季宣','宋','宋诗','song-poetry','','[]','石上可生麻，麻生豈成畦。',144,'全唐诗/poet.song.155000.json','["石上可生麻，麻生豈成畦。", "嫁婿得蕩子，猶如太常妻。", "我作少年行，長安走新街。", "長安三月春，桃李百花開。", "平康諸女兒，艷麗驚寒梅。", "蛾眉鬭連娟，佳期不須媒。", "投我以木瓜，當歌共傳盃。", "歌聲繫懷抱，知君在空閨。", "期我以立春，清明未云來。", "應作憶秦郎，高樓寄徘徊。", "鸞膠世苦無，斷續何當諧。", "閨中儻相憶，薰風有時回。"]'),
('60206343-d160-4e00-ad13-821b98ccb8b5','春蘭有真意','薛季宣','宋','宋诗','song-poetry','','[]','春蘭有真意，窮居在中谷。',120,'全唐诗/poet.song.155000.json','["春蘭有真意，窮居在中谷。", "端不爲人香，無言自幽獨。", "我家甌浦東，筠扇鎖修竹。", "頎然彼粲者，夭翹散餘馥。", "五年客異縣，對眼囂塵俗。", "百華盡妖艷，信美非吾族。", "延陵蹔遊豫，佳期未云卜。", "同心弗我忘，迎人見青目。", "雖微九畹滋，風動情亦篤。", "當門謂應鋤，吾當爲之哭。"]'),
('b99974af-e108-4640-969d-88c39d925909','七哀','薛季宣','宋','宋诗','song-poetry','','[]','秋風生夕涼，吹我東閣帷。',96,'全唐诗/poet.song.155000.json','["秋風生夕涼，吹我東閣帷。", "中有宕子婦，清歌寄愁思。", "爲問愁何爲，良人長別離。", "銀釭弔隻影，霜雪堅自持。", "君爲黄河流，妾作月桂枝。", "東西各異道，邂逅不可期。", "願爲衣下裳，結束隨君衣。", "君衣何當披，十年守空閨。"]'),
('4f80f612-f75e-41e1-88ba-f72814bbeebb','鈞天曲','薛季宣','宋','宋诗','song-poetry','','[]','清都太皇居，窈在冥冥間。',204,'全唐诗/poet.song.155000.json','["清都太皇居，窈在冥冥間。", "神光貫中極，希微炯非煙。", "紫宸邃以虛，絳闕高于天。", "受職徠百靈，肅雍朝九寰。", "大饗通明殿，張樂玉京山。", "九奏感人心，萬舞形物先。", "谷神靄清唱，黔嬴撫鳴彈。", "緬彼世間音，下里何㛹娟。", "闐闐響雷鼓，蹁躚舉雲鬟。", "彗孛小垂手，日月兩彈丸。", "陽春假優裝，投霓忽高弦。", "壺矢一笑電，歌風發三嘆。", "呼吸成千塵，神仙詎長年。", "峨峨帝王都，積蘇浮九埏。", "簫韶間猗那，鬭蟻蚊雷喧。", "蟲沙與猿鶴，等細不足言。", "遺音寄五柳，海山學成連。"]'),
('207a8520-45c4-4f51-9fd3-a60799e69e6a','欵乃歌','薛季宣','宋','宋诗','song-poetry','','[]','欵乃兮江湘，繚兮繞兮衡之陽。',109,'全唐诗/poet.song.155000.json','["欵乃兮江湘，繚兮繞兮衡之陽。", "龍衣兮黼裳，帝何之兮陟方，我不見兮攪我心腸。", "欵乃兮蒼梧，杳兮渺兮遠隔重湖。", "龍駕兮鸞車，帝何之兮升遐，我不見兮泣涕漣如。", "雲夢兮漪淪，欵兮乃兮岣嶁峋。", "青天兮白雲，帝何之兮上賓，我不見兮慼此下民。"]'),
('f863a901-65df-4b6c-9c24-ba3f32db92be','菊冬榮','薛季宣','宋','宋诗','song-poetry','','[]','時乎時乎，去去如車轂之運行。',345,'全唐诗/poet.song.155000.json','["時乎時乎，去去如車轂之運行。", "瞥然過目無留停，追隨無及不我待。", "東籬菊花無耗，迤邐真到陽冬始敷榮。", "落落離離𪿨礧，蔓衍布丘坂。", "碧爲之葉紫其莖，爭妍騁媚芬芳吐。", "如金如玉之繁英，含霜萬顆好顔色。", "節雖可尚時難并，惟重陽日月二九之嘉會。", "此時抱一符乾貞，年年閭里交相慶。", "賓朋相將相喚，携手登高陵。", "采茱插鬢款終日，揉挪碎蕊滿琖浮醁醽。", "乃今候遲閏冬孟，其如金烏自飛𩆊走𨁈。", "黄華從此後期拆，枉教陶令舒手望穿兩眼睛。", "殊不見甲茁與芽萌，花誠細事足多惜，時良不遇令我傷衷情。", "聖王作應五百歲，文昌歿既三千齡。", "中間賢君苦無輔，唐宗世民周宗榮。", "孔丘無位皆汲汲，到頭畢竟嗟無成。", "應如此花時來不吐穎，過期無用還叢生。", "叢生失時又無用，蹉跎畢世空冥冥。", "于嗟後聖不時作，使人雨淚雰零零。", "不如及花開，香醪但時傾。", "莫教花瘁後，有辜負花名。"]'),
('ad9d5ee8-89e0-41d1-9574-35a49ea30ae8','樓上曲','薛季宣','宋','宋诗','song-poetry','','[]','樓頭月白良夜深，美人睡起搊胡琴。',224,'全唐诗/poet.song.155000.json','["樓頭月白良夜深，美人睡起搊胡琴。", "咿嚘怨抑如誠訴，四弦了不諧琴音。", "推琴憑欄歌一曲，爲聲不成氣不續。", "和愁擁面歸錦帷，曲肱展轉愁相屬。", "床前蛟燭光熒熒，乍明乍滅如參星。", "卷衾起來問高燭，能知妾意還不能。", "燭如不解人深意，如何伴妾長垂淚。", "澄思微物本無情，有懷觸目皆傷志。", "眠來復坐坐復眠，不交兩睫時潸然。", "自惟命薄多離恨，春宵鎮長遲曙天。", "親知問得郎書不，低頭無言墮紅雨。", "遲回捩淚强爲容，不成一語愁還主。", "何人遠自日邊歸，殷勤爲問郎歸期。", "待得郎歸與俱隠，不教被劾緣蛾眉。"]'),
('6cdf59bd-ed31-4280-b6f1-9c32dd19eb24','武陵行','薛季宣','宋','宋诗','song-poetry','','[]','秦君植木咸陽市，秦民血作東流水。',344,'全唐诗/poet.song.155000.json','["秦君植木咸陽市，秦民血作東流水。", "秦風薄惡法秋荼，秦郊行人半無趾。", "祖龍虎視吞六雄，漆城隠隠陵雲起。", "驪山罷休營阿房，匹夫奮臂爲侯王。", "重瞳隆準騁逐鹿，非冬積白何雪霜。", "至人知幾忍徒死，競遵大路逃彼方。", "從茲不復通上國，不知戈鋋不見德。", "耕田鑿井自希夷，安居守分無餘職。", "抱孫養子樂天年，羲皇何遠今其域。", "自從別祖來避秦，無文不記幾世人。", "曹劉典午任强弱，歷年六百何紛紜。", "山中既絕中原路，從更百代猶無聞。", "武陵野人事漁釣，獨遊沅溪忘故道。", "泝流探得桃花源，舍舟洞口窮幽討。", "洞中逸民忻見之，共嗟遺事詢其老。", "爲言上世絕塵由，殺雞命酒爭獻酬。", "具聞閫內戰爭事，始知違俗爲優遊。", "鄙夫何知尚懷土，怱怱須別還中州。", "塵心已萌淳樸散，桃源咫尺仙凡判。", "還求不得曰仙鄉，寧知死生無少閒，相望如隔一世間。", "到今沅山色蒼蒼，流水滔滔花泛泛。"]'),
('1433055f-01f9-4821-9424-156254518502','貴遊行','薛季宣','宋','宋诗','song-poetry','','[]','沙堤大蓋何穹窿，底人佩玉鞍蒙狨。',384,'全唐诗/poet.song.155000.json','["沙堤大蓋何穹窿，底人佩玉鞍蒙狨。", "傔如熊虎馬遊龍，誰何出入咸陽宮。", "笑刀瓠體顔芙蓉，步趨持重爲雍容。", "諸侯爰統掌百工，調元爲職裨九重。", "萬錢一食聲鼓鐘，猶言下筯終無從。", "異時糠噉腸不充，家徒壁立其室蓬。", "抄撮語麗文彫蟲，繪爲綉句欺南宮。", "不分菽麥儔知儂，且無萬卷澆胸中。", "脂韋媕婀陳小忠，竭民膏髓自爲功。", "榻前觸事惟迎逢，肯思責難始爲恭。", "君王謂賢拜三公，門如沸湯賄賂通。", "財侔縣官邑侯封，積金猶欲齊灊崈。", "家有錢爐非範銅，賣官鬻獄揚成風。", "後房的燦燕支紅，皆民女婦來無蹤。", "有憂失得常忡忡，殺賢賊能摧英雄。", "汲將同類塞要衝，害苗之心饒蝗螽。", "忽彎射羿逢蒙弓，怡然自得豁心胸。", "黯如抹漆何赤衷，問人自欺咤匪躬。", "高自標置人盲聾，言立便擬稱儒宗。", "學禪逃俗坐談空，元非友朋相磨礱。", "世間將謂無軻雄，言出波流士與農。", "却矜巧宦官既穹，笑伊魯儒嗟道窮。", "那知達人節青松，眎而土苴及蛆蟲。", "古今異時理道同，姦邪未必皆令終。"]'),
('e31c7718-3928-4e6b-a020-5ccf9567b8c7','夢仙謠','薛季宣','宋','宋诗','song-poetry','','[]','長城役罷驪山起，秦人斷念還居里。',384,'全唐诗/poet.song.155000.json','["長城役罷驪山起，秦人斷念還居里。", "一呼或化爲侯王，避之却是神仙子。", "漢家宮殿生荆棘，桃源千樹長春色。", "花香破鼻桃離離，只在人間人不知。", "夢中有客曾一到，屋舍衣裳殊草草。", "狗彘雞豚還治生，若度流年不知老。", "南華砎壁連天起，人家庭戶多流水。", "紅碧夭桃百種花，不似凡間錦和綺。", "仙人容貌閑且都，居處雖貧樂有餘。", "老子桃紅入雙臉，皤然只有銀爲須。", "仙家女兒多茜衣，桃花宜面葉宜眉。", "離宮茅舍略相似，別有譙麗璇爲題。", "仙君名氏猶屬秦，許由往往陪遊人。", "老人石上問行客，傳今幾世秦之君。", "爲言天下方南北，人鹿千齡經幾得。", "嗟說來時桃始華，桃子而今未成核。", "祖龍往日親曾見，六合連兵事攻戰。", "北城紫塞南陸梁，傾貲未足供輸輓。", "誠知黔首無聊生，側目有誅正視刑。", "剖心不獨商王受，當時論殺諸儒生。", "我本何辜一何幸，避役離鄉共亡命。", "石髓藥苗聊解饑，經年陡覺儕仙聖。", "訊今丞相胡爲者，振古如今同土苴。", "驚起城頭角調哀，頓覺令人小天下。"]'),
('6441c070-22de-40eb-8dbb-551c55f20c1f','谷里章','薛季宣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','上有青山，下有滄洲。',379,'全唐诗/poet.song.155000.json','["上有青山，下有滄洲。", "步有回波，面有紅流。", "吞吐風雲，呼吸觜昴。", "審能處之可銷憂，退谷中人带笭箵。", "山中繚繞茅舍旁，寒泉之流激琅琅。", "雙石西峰我在東，無情鉤加此漫郎，性情荒浪氣志剛。", "東隣之人揮鉤車，胎鰾孤{魚菐}浪屋加。", "鉤綸相投不遑舍，聱齖會懾歸吾家。", "我蓑我笠聊自娛，沒溺愧彼鄰舍漁。", "沙門招提宅谷西，金仙宮殿雲漢齊。", "撞鐘擊磬禮耶毗，子欲詣之持清齋。", "箇中有人坐無爲，饑餐困眠氣答酡。", "撫掌咍然笑呵呵，吾昏將奈此子何。", "漫歌八曲音清泠，風高水寒三歎聲。", "勿哦大洞修黄庭，谷中之樂寔難名。", "長江北來，樊水流東，樊山水曲大回中。", "儵儵之魚泳油洋，鉤舟漁人鼓鳴榔。", "浩歌一闋清滄浪，終焉無求漫相忘。", "大江之東叢石起，谽谺聚石江鳴水。", "小回中間浪不惡，釣臺嵯峨瞰城郭。", "去來客船是中泊，漫成二闋回中曲。", "豪人仲謀當漢衰，建安之際鼎祚移。", "江淮萬里吳帝之，冕旒十二龍卷垂。", "輅車華葢日月旗，荒墟之中不可求。"]'),
('f712da8c-fb42-46e1-80e4-1c4af9e69fdb','東坡','薛季宣','宋','宋诗','song-poetry','','[]','江之廣矣，一葉航斯。',164,'全唐诗/poet.song.155000.json','["江之廣矣，一葉航斯。", "東坡遠矣，企而望斯。", "彼草蒙茸，翳于雪堂。", "决决濫泉，橋亦云亡。", "人知其名，我懷允實。", "崔嵬者山，有環彼室。", "江之廣矣，跋而髣髴。", "悠哉悠哉，如泉流以出。", "我思古人，寥其久矣。", "文如爾矣，我心起矣。", "雪堂之圮矣，曷爲其止矣。", "人之匪矣，若其已矣。", "我之鄰斯，一江之巨。", "我之來斯，忽其如寓。", "有懷北堂，頹如以仆。", "相彼道人，隻眼之云具。"]'),
('93c9a691-8892-4e70-825f-6d2dc1fdc535','淵魚','薛季宣','宋','宋诗','song-poetry','','[]','躍躍淵魚，言泉之涸。',185,'全唐诗/poet.song.155000.json','["躍躍淵魚，言泉之涸。", "有束樊籠，既幽其鶴。", "眷言懷之，翰飛戾天。", "薄言存之，泳于重泉。", "蹙蹙何嗟，靡生靡活。", "胥失其淪，上下靡所。", "察視其淺矣，宛轉于泥。", "就其幽矣，安處于棲。", "匪我之云爲，何適何歸。", "曰有虞衡，莫我肯知，亦莫我肯悲。", "父母何其，嗚呼蒼天，蓋亦勿思。", "尾魚既頳，鶴樊既鳴。", "孰聽其聲，孰視其形。", "豈無高天，翱翔靡路。", "豈無重泉，職職靡寓。", "洋洋者魚，惟淵之實。", "鶴飛于九霄，時豈籠中物。"]'),
('63812777-0224-4bfd-b348-109087dd8e09','誠臺瓦鼓詩','薛季宣','宋','宋诗','song-poetry','','[]','瓦鼓垖垖，寘之誠臺。',263,'全唐诗/poet.song.155000.json','["瓦鼓垖垖，寘之誠臺。", "誠臺有稱，不革不銅。", "不尚其𪔳，自天之性。", "天性如之何，至質無華。", "有稱如之何，埏埴無加。", "誠哉誠哉，其儀孔嘉。", "瓦鼓垖垖，誠臺之上，崇基有塽。", "可據而居，可憑而望，湯其泱漭。", "瓦鼓之垖然，稱臺址之隤然，抱峰崿之嵬然。", "誠哉誠哉，紛會意之颸然。", "瓦鼓垖垖，誠臺之下，筠鄉有楚。", "掃地而居，修竹猗猗。", "垖其反古，五畝之竹兮。", "彼垖者鼓，在彼墺兮。", "在彼墺兮，稱此麓兮。", "誠哉誠哉，會我獨兮。", "瓦鼓垖垖，在彼青林，有象無音。", "稱臺觀之嶔岑，稱筠竹之清陰，樂稱走之誠心。", "豈無胡床，可將可坐。", "豈無鼖鼗，可鳴可播，而垖鼓以無和。", "誠哉誠哉，不加其埵。"]'),
('ef990884-3b55-41a9-8843-85a072f8f128','端午寒溪早出','薛季宣','宋','宋诗','song-poetry','','[]','雲天鴻濛，煙蘿冥密。',90,'全唐诗/poet.song.155000.json','["雲天鴻濛，煙蘿冥密。", "寒溪綫繞，荆江壁出。", "竹徑晨遊，露風飃䫻。", "有懷碩人，遠在清汨。", "不競流芳，睠此誠壹。", "道存語外，泓潭納日。", "形模比櫛，滉如日室。", "萬派瓜分，無往弗徹。", "吾心憒焉，莫可致詰。"]'),
('b26e0938-7311-4a40-9e31-f1ae0ef34854','志事','薛季宣','宋','宋诗','song-poetry','','[]','我生之辰，六月甲戌。',242,'全唐诗/poet.song.155000.json','["我生之辰，六月甲戌。", "師伯清塵，羲和納日。", "粵有氛祲，南自篳門。", "輪囷扶疏，英如白雲。", "高減儲胥，來循軌道。", "面阻清池，岐分繚繞。", "玦如隄立，不即我庭。", "直建千房，視左爲榮。", "載明載滅，載高載卑。", "甲夜籌三，侵尋以微。", "外戶如之何，秋空澄霽。", "庭內如之何，靜無纖曀。", "我門我籞，豈伊異人。", "何吉何凶，祥讖誰詢。", "發書占之，日音受徵。", "公正司辰，廉貞變起。", "時維寬大，斗建移申。", "律中參陽，干庚歲寅。", "庚刑甲祿，三合離鄉。", "王墓加臨，金剛火强。", "白維王氣，金方火死。", "從革之占，庶乎近止。", "我非瞽史，詎易談天。", "禍福由人，無論未然。"]'),
('e34ddedc-4f0c-4e5d-b214-9ced92a150c9','神人暢','薛季宣','宋','宋诗','song-poetry','','[]','莫莫昊天，莫夥烝民，感兮格兮君之仁。',114,'全唐诗/poet.song.155000.json','["莫莫昊天，莫夥烝民，感兮格兮君之仁。", "混茫萬宇，自都于野，余一人爰主。", "于何道兮，暢浹神人。", "于何道兮，神人我與。", "蕩蕩兮帝德，高高兮不極。", "吾不知其名兮，命焉弗得。", "其人則天兮，天乎其仁。", "吾不知其際兮，究焉無適。", "伊神人之交暢兮，其帝之力。"]'),
('67cbc126-333b-49b3-a620-fa844621f08e','思歸操','薛季宣','宋','宋诗','song-poetry','','[]','彼美鳩雛，歸晡嗚嗚。',50,'全唐诗/poet.song.155000.json','["彼美鳩雛，歸晡嗚嗚。", "所哺伊何，曰父母且。", "匪生何父，匪育何母。", "歷山之居，居庸可久。", "念念思歸，不歸何俟。"]'),
('c64ad063-850e-4bfe-ad3a-47d37292319c','舜操','薛季宣','宋','宋诗','song-poetry','','[]','黄屋兮巍巍，人道兮委蛇，念父母兮庭闈。',56,'全唐诗/poet.song.155000.json','["黄屋兮巍巍，人道兮委蛇，念父母兮庭闈。", "三牲日饋兮，夫豈不時也。", "憯不如在野兮，親几履也。", "惟昔樂而勞今兮，吾將已也。"]'),
('f13d0555-95b0-456d-94a7-48745ee42561','南風歌','薛季宣','宋','宋诗','song-poetry','','[]','愾彼夏日，熇熇其暑。',60,'全唐诗/poet.song.155000.json','["愾彼夏日，熇熇其暑。", "毒我下民，辟焉無所。", "愾彼夏夜，鬰蒸其雨。", "民之慍結，莫安其處。", "凱風自南，發于茂林。", "實彼百穀，紓我慍心。"]'),
('604b0551-7cbe-45e2-b2e4-c021405a2a6f','襄陵操','薛季宣','宋','宋诗','song-poetry','','[]','湯湯洚水兮，懷山襄陵。',45,'全唐诗/poet.song.155000.json','["湯湯洚水兮，懷山襄陵。", "浩浩滔天兮，昏墊生靈。", "導之入于海兮，王事有程。", "啟呱弗子兮，匪我忘情。"]'),
('c0771b35-59c2-4d30-9d2d-b6a082f4699e','霹靂引','薛季宣','宋','宋诗','song-poetry','','[]','天地肅兮陽伏藏，以時出兮萬物攸行。',92,'全唐诗/poet.song.155000.json','["天地肅兮陽伏藏，以時出兮萬物攸行。", "聲砰訇兮，蟄蟲咸作。", "蟄蟲不作兮，自底天亡。", "象震出兮惟君王，發號令兮驚四方。", "惽封禺之守臣兮，自爲聾聵。", "死霹靂之下兮，式彼天常。", "噫，余非好殺兮，刑憲有章。"]'),
('5b8ad708-d30f-47c1-8a67-c4bc79323ed5','適薄歌','薛季宣','宋','宋诗','song-poetry','','[]','瞻彼薄兮，俗灝灝兮。',60,'全唐诗/poet.song.155000.json','["瞻彼薄兮，俗灝灝兮。", "父母邦兮，蔑强暴兮。", "瞻彼薄兮，俗洋洋兮。", "父母邦兮，蔑暴强兮。", "茫茫禹迹，紊其經紀。", "適彼薄兮，言歸父母。"]'),
('f0751e6b-295f-4236-afa8-39e6291e6cc8','箕子操','薛季宣','宋','宋诗','song-poetry','','[]','天道渾渾兮不享，繄神器從神兮適彼西隣。',62,'全唐诗/poet.song.155000.json','["天道渾渾兮不享，繄神器從神兮適彼西隣。", "泯社稷之阽危兮君無與守，將正而斃兮誰善其後。", "負罪囚奴兮九疇我保，庶湯孫之復兮載興商道。"]'),
('bba8b614-7dbd-4a39-b56d-f3de2522ee7a','文王操','薛季宣','宋','宋诗','song-poetry','','[]','鳳兮鳳兮，鳥之王兮。',30,'全唐诗/poet.song.155000.json','["鳳兮鳳兮，鳥之王兮。", "覽德輝兮，爲嘉祥兮。", "匪下昌兮，我王明兮。"]'),
('19b732e1-b09e-4581-ad37-cf9d94b3c9db','克商操','薛季宣','宋','宋诗','song-poetry','','[]','天命文考，翦滅大商。',40,'全唐诗/poet.song.155000.json','["天命文考，翦滅大商。", "發將天命，戈矛有光。", "非余武兮，獨夫自亡。", "非余武兮，天啟先王。"]'),
('ec81b032-27cd-4a4e-8fb2-71f4d11fbc7c','采薇歌','薛季宣','宋','宋诗','song-poetry','','[]','陟彼首陽，言采其薇。',82,'全唐诗/poet.song.155000.json','["陟彼首陽，言采其薇。", "可以充腸，可以樂饑。", "采薇采薇，首陽之下。", "可以全身，可以安處。", "采薇采薇，首陽之巔。", "可以適己，可以窮年。", "在彼亦食，在此亦食。", "雖傾天爾力，父子有常職。"]'),
('9894e5b7-63c6-4b23-8e15-0fa5d5d6e368','麥秀歌','薛季宣','宋','宋诗','song-poetry','','[]','麥秀漸漸，殷商宮兮。',90,'全唐诗/poet.song.155000.json','["麥秀漸漸，殷商宮兮。", "肅肅清廟，儼惟墉兮。", "城郭依然，澮畎通兮。", "惻我心摧，悼人亡兮。", "寤彼盛時，阜熙雍兮。", "車蓋幢幢，來朝宗兮。", "自我成湯，德顒顒兮。", "恍如夢驚，留眼中兮。", "今我不見，內猶霿兮。"]'),
('bafe669f-21aa-459f-b187-5e81fb1f22af','神鳳操','薛季宣','宋','宋诗','song-poetry','','[]','大樂和諧兮，神鳳來儀。',25,'全唐诗/poet.song.155000.json','["大樂和諧兮，神鳳來儀。", "彼周公之聖兮，余何德以堪之。"]'),
('516b3453-1830-47b6-9968-f9c58ddb6aa2','丘陵歌','薛季宣','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','陟彼丘陵，岡阜逶迤。',81,'全唐诗/poet.song.155000.json','["陟彼丘陵，岡阜逶迤。", "莫適所窮，曷知所止。", "泰山蒼昂，西國之望。", "人之弗登，道舊云亡。", "顧瞻周道，坦平如砥。", "捷徑斜敧，小人所履。", "亶不由乎，此式遵乎。", "彼大路棘矣，何能久矣。"]'),
('547f95d6-bc35-415a-94ad-076cc2802cf3','梁山歌','薛季宣','宋','宋诗','song-poetry','','[]','雨雪霏霏，梁山之下。',62,'全唐诗/poet.song.155000.json','["雨雪霏霏，梁山之下。", "樸𨔤其凝，皓其郊野。", "凜其寒矣，曷藏曷御。", "親庭孔邈，孰爲溫者。", "台不能此處，歸途無所。", "台不能此處，曷其疾去。"]'),
('9e877594-6c48-4215-82f4-649ef2d4e3b0','歸耕操','薛季宣','宋','宋诗','song-poetry','','[]','我欲仁，違離二親。',166,'全唐诗/poet.song.155000.json','["我欲仁，違離二親。", "自我不見，于今十春。", "心雖不去，情不親。", "聞師教有年，子不曰夫，孝終立身而始事親。", "求仁斯得仁，事斯語足以窮吾年，歸耕乎休。", "歷山之下有良田，參來其誰芸，歸耕乎休。", "以一貫道者，吾夫子之言也。", "去不我留者，年也。", "不可得而再事者，親也。", "歸耕乎休，耒耜足以待豐年也。", "禾黍足以奉吾親也，樂道足以富吾仁也。", "歸耕乎休，如是夫豈食吾貧也。"]'),
('60a2bc9d-7719-4023-b4ee-73b6f70a0c6f','汾亭操','薛季宣','宋','宋诗','song-poetry','','[]','我思周道兮，適彼鎬京。',176,'全唐诗/poet.song.155000.json','["我思周道兮，適彼鎬京。", "遵逵孔直兮，踖踖其行。", "驅車潼華兮，草𦬇罥余。", "軸限河渭兮，濟無津梁。", "日銜山兮天欲夜，愁雲結兮不成雨。", "我心惻兮思故鄉，汾亭寂兮汾之陽。", "陶唐氏之遺風湣兮其若亡，睠吾徒兮狷或狂。", "振還轅兮去京邑，淚涂泥兮道猶澀。", "汾亭上兮有六世之遺書，野有田兮汾有魚，宵續經兮晝狎佃漁。", "闢闕里兮薙萊蕪，倡弦誦兮開羣儒。", "神交周孔兮獨樂有餘，神交周孔兮獨樂有餘。"]'),
('6f0afa2e-d0f0-4183-be6a-80793b341fd5','水仙操','薛季宣','宋','宋诗','song-poetry','','[]','海山中兮四無居人，海之濤兮渺漠而無垠。',79,'全唐诗/poet.song.155000.json','["海山中兮四無居人，海之濤兮渺漠而無垠。", "浮空輿地兮，風雲濫其出沒。", "朝而潮夕而汐兮，浩兔烏之吐吞。", "彼鳥兮鳴飛，彼鹿兮跂跂。", "聊淹留兮歲聿其暮，鼓絲桐兮從夫君而與歸。"]'),
('d2592147-904f-411d-8c18-2b3855e08309','沈舟操','薛季宣','宋','宋诗','song-poetry','','[]','悠悠之川兮汎彼淘河，一江動蕩兮恬風靜而騰波。',102,'全唐诗/poet.song.155000.json','["悠悠之川兮汎彼淘河，一江動蕩兮恬風靜而騰波。", "瀾翻下瀨聲渢渢兮柂師不可以告語，沈舟折首兮天其奈何。", "愚夫婦兮中倉不濡，行褚遷于高岸兮婦沾漬之長吁。", "凡之亡兮，凡存不害。", "渺江波之瀰漫，走于行之不濟也。", "嘻，命矣夫。"]'),
('0b86cbc5-3466-4743-ac13-9050f5b5ebd0','傷劉復之三首  其一','薛季宣','宋','宋诗','song-poetry','','[]','交情不在久，還有白頭新。',48,'全唐诗/poet.song.155000.json','["交情不在久，還有白頭新。", "雨礎知同氣，斤墁喪若人。", "薰焚雖有限，玉折豈無因。", "世事都如此，蒼天何不仁。"]'),
('7e07c22f-277e-4c20-b210-ba081ce95b35','傷劉復之三首  其二','薛季宣','宋','宋诗','song-poetry','','[]','聞憶鱸魚去，嗟君獨見幾。',48,'全唐诗/poet.song.155000.json','["聞憶鱸魚去，嗟君獨見幾。", "若何車軸折，未迨草廬歸。", "殄瘁吾心懼，云亡世德稀。", "南風方不競，民援欲誰依。"]'),
('55ee26fd-4039-45dc-9144-a5949e83891f','傷劉復之三首  其三','薛季宣','宋','宋诗','song-poetry','','[]','世念吾衰久，爲之慟却哀。',48,'全唐诗/poet.song.155000.json','["世念吾衰久，爲之慟却哀。", "知言非語到，見事直心開。", "吾道傷麟出，韶音憶鳳來。", "州鄉桃李地，編戶想悲摧。"]'),
('40f10345-2d19-498b-8953-d122b3d87846','劉復之哀辭','薛季宣','宋','宋诗','song-poetry','','[]','天胡不仁兮，瘼此下民。',236,'全唐诗/poet.song.155000.json','["天胡不仁兮，瘼此下民。", "良苦乏賢兮，賢人名去而仙。", "繄世途之好徑兮，正路榛塞。", "閶闔重重有栗階而進兮，不崇朝而折翼。", "鴟鶚司政兮，蝙蝠之晨。", "猿仁何咎兮，擯自王孫。", "寧是不畏兮，天實爲之。", "皇浩浩之充天兮，豈其已而。", "鴻翱翔而遵逵兮，退飛者再。", "摶扶摇之直上兮，竟翷翩而長逝。", "夫豈人爲兮，呼天不聞。", "人莫不死兮，不亡者存。", "小官之不卑兮，賢聲載路。", "視彭鏗其猶夭兮，後昆有裕。", "楙實雙而一瘁兮，哀哀者母。", "紛孺弱之呱前兮，蒼天太苦。", "生者作德兮，死者有仁。", "嗚呼哀哉，家國無人非余患兮，余悲夫抱志之不伸。"]'),
('9e4495fb-7c9e-432f-a788-8b392829a6be','外舅孫帥挽詩','薛季宣','宋','宋诗','song-poetry','','[]','行誼推前輩，繄公學大成。',264,'全唐诗/poet.song.155000.json','["行誼推前輩，繄公學大成。", "博通行祕府，威德殷長城。", "筆力千均重，詞源三峽傾。", "懷珠飆躍浪，杖策穩登瀛。", "奇節爲繩直，危言襲鳳鳴。", "弦歌風四甸，領袖服諸生。", "任付即山鑄，章分煮海程。", "錢流邦貨重，利半國租贏。", "政抑豪民折，人知公道行。", "繡衣休直指，彤矢賜專征。", "劍戟森營壘，邊陲卧鼓鉦。", "正辭平楚獄，折簡罷蠻兵。", "治水防云固，爲魚患不萌。", "藴含荆玉潤，廉與蜀江清。", "流馬追前躅，輕裘擁後旌。", "鸞聲仍噦噦，蠅矢自營營。", "毋謂鏐金鑠，其如衡石平。", "功名書冊在，冠冕擲瓢輕。", "棠棣輝方韡，瓊瑰夢忽驚。", "人間傅說謝，天上歲星明。", "有美稱遺愛，無窮企令聲。", "淚碑兼陌祭，西蜀又南荆。"]'),
('4444b7a9-cb13-4606-b4ea-3ae5912acecd','故使制置閣學蕭公挽章  其一','薛季宣','宋','宋诗','song-poetry','','[]','萬夫卬止配高山，德望巍峨履道安。',64,'全唐诗/poet.song.155000.json','["萬夫卬止配高山，德望巍峨履道安。", "容貌誾誾服鄉黨，風稜凜凜冠朝端。", "鳳鳴往格君心正，鸇擊曾聞奸膽寒。", "不相宅家長已矣，空教有識涕瀾汍。"]'),
('463ba548-1c55-41a4-8c1d-9c651747f9ae','故使制置閣學蕭公挽章  其二','薛季宣','宋','宋诗','song-poetry','','[]','陝服它時帥五侯，盡心分主顧西憂。',64,'全唐诗/poet.song.155000.json','["陝服它時帥五侯，盡心分主顧西憂。", "爲民發廩成歸節，揖盜開關記釋謀。", "澤施生人追灌口，法垂當世說遨頭。", "華陽舊志今誰續，巷祭餘哀可見收。"]'),
('bc7d311d-9e7b-4558-a49e-d4501b70c5fe','故使制置閣學蕭公挽章  其三','薛季宣','宋','宋诗','song-poetry','','[]','履賜西州事可尋，稅軺無在不棠陰。',64,'全唐诗/poet.song.155000.json','["履賜西州事可尋，稅軺無在不棠陰。", "憶參盛府開巴峽，忍送靈輀入鳳林。", "語上故藏應筆鑑，家傳清尚只龜琴。", "自傷下走青衫少，慟哭無人知此心。"]'),
('d8ce14aa-ccb3-426d-a298-a7630cb0cc92','故使制置閣學蕭公挽章  其四','薛季宣','宋','宋诗','song-poetry','','[]','脫巾自責爲兒非，叱馭辭舟識洞微。',64,'全唐诗/poet.song.155000.json','["脫巾自責爲兒非，叱馭辭舟識洞微。", "不辨盜金緣重義，危言撩虎自知幾。", "惠霑神物能通夢，節感鄉閭憶葬衣。", "今見我公公又往，後生學古欲儔依。"]'),
('72ce321c-c022-4506-ad72-d4255857a20e','高邦貢挽詩','薛季宣','宋','宋诗','song-poetry','','[]','世道久衰息，惟君尚典刑。',48,'全唐诗/poet.song.155000.json','["世道久衰息，惟君尚典刑。", "好詩清臘雪，醇德醉春醽。", "考筴窮三易，傳家守一經。", "高風不可見，誰與勒貞銘。"]'),
('2e150683-2872-4ed2-be74-e6b8f87895ba','張端明挽詩  其一','薛季宣','宋','宋诗','song-poetry','','[]','凋落傷前輩，風流屬老成。',48,'全唐诗/poet.song.155000.json','["凋落傷前輩，風流屬老成。", "和羹方爾用，接淅已吾行。", "卜筮占先志，儀刑式後生。", "贈同開府相，哀誄易佳名。"]'),
('86522bb0-e28f-4a7d-acd2-59a0425ed11a','張端明挽詩  其二','薛季宣','宋','宋诗','song-poetry','','[]','帝功成贊育，天道與爲徒。',48,'全唐诗/poet.song.155000.json','["帝功成贊育，天道與爲徒。", "祖帳霸陵岸，扁舟笠澤湖。", "送鞋非李泌，哭市有郇謨。", "已矣龍輀稅，依然曳尾塗。"]'),
('19235ece-3dbd-478e-826e-9741d641a272','張思豫挽詩','薛季宣','宋','宋诗','song-poetry','','[]','蝗食虛來鳳，牛刀第割雞。',48,'全唐诗/poet.song.155000.json','["蝗食虛來鳳，牛刀第割雞。", "解紛誰俠行，懷惠或嬰啼。", "寤歎傷凋落，虞歌思慘悽。", "鄴侯家傳在，蘭佩可童觿。"]'),
('7e8dc312-d698-4492-a858-4bc8d5e786f6','許深父母挽詩','薛季宣','宋','宋诗','song-poetry','','[]','載德稱賢母，宜家啟令郎。',48,'全唐诗/poet.song.155000.json','["載德稱賢母，宜家啟令郎。", "背萱傷蚤謝，蟾桂籍流芳。", "負米思何報，啼狶教叵忘。", "一篇勝得第，應喜賽錢塘。"]'),
('d721d0fd-decf-49f5-bd47-f673e1b5d7df','陳蕃仲侍郎挽詩','薛季宣','宋','宋诗','song-poetry','','[]','鄉黨名卿有幾人，如公學術兩離倫。',64,'全唐诗/poet.song.155000.json','["鄉黨名卿有幾人，如公學術兩離倫。", "貢金政告忠嘉舊，春草詩傳語句新。", "北虜使華中昨好，西岑野色近來親。", "忍觀封鬣珉岡地，藴我東朝法從臣。"]'),
('a60603ca-efde-4c32-9450-2bb8fdf967b9','孫元式挽詩  其一','薛季宣','宋','宋诗','song-poetry','','[]','世盡宗韓柳，君期振古今。',48,'全唐诗/poet.song.155000.json','["世盡宗韓柳，君期振古今。", "文場聲籍籍，武庫入森森。", "未契千年運，終孤百戰心。", "一官端溷子，遐及贊鳴琴。"]'),
('da5addc4-7f3a-4d2d-9116-0a3214a3ed9d','孫元式挽詩  其二','薛季宣','宋','宋诗','song-poetry','','[]','凜凜東門會，巖巖烈士風。',48,'全唐诗/poet.song.155000.json','["凜凜東門會，巖巖烈士風。", "語高文筆外，歡溢酒杯中。", "契闊從睽隔，綢繆見始終。", "之人而不壽，吾欲問蒼穹。"]'),
('c5b29581-eebe-49b0-ba2b-2e4b01b06d1e','周詹事操挽詩','薛季宣','宋','宋诗','song-poetry','','[]','前輩傷凋落，如君尚典刑。',48,'全唐诗/poet.song.155000.json','["前輩傷凋落，如君尚典刑。", "政聲喧劇郡，直節挺明庭。", "江海理歸棹，乾坤託旅亭。", "相知不相見，如洗淚吾零。"]'),
('b6977ca1-dd70-42ac-83f0-87d8779c3574','周待制淙挽詩','薛季宣','宋','宋诗','song-poetry','','[]','昭代開昌運，名臣取世資。',48,'全唐诗/poet.song.155000.json','["昭代開昌運，名臣取世資。", "權謀乘保障，彈壓治京師。", "方接清風會，俄驚汗漫期。", "此情誰與論，虞殯屬篇詩。"]'),
('d3334d67-b777-45bb-a514-da7a789dc13d','走作復之哀辭將寄諸賓之旋聞賓之下世道中哀痛之劇','薛季宣','宋','宋诗','song-poetry','','[]','虛傳流水遶壺公，興化衣冠轉盼空。',64,'全唐诗/poet.song.155000.json','["虛傳流水遶壺公，興化衣冠轉盼空。", "擬比三君扶漢室，肯同二陸起吳中。", "泗川始訝沈神鼎，劍浦俄驚合化龍。", "齠齔滿前垂白母，此情何處問蒼穹。"]'),
('cb895d80-2e39-46ad-bc93-02c7b83af1da','九奮 啟憤','薛季宣','宋','宋诗','song-poetry','','[]','啟憤兮申冤，訴衷情兮敶矢言。',369,'全唐诗/poet.song.155000.json','["啟憤兮申冤，訴衷情兮敶矢言。", "叫蒼天之無辜兮，指心以爲正。", "將求信于旬始兮，或咎繇之我聽。", "神羊不世有以觸邪兮，其誰宜爲政。", "親莫親于手足兮，而爲之詬病。", "重莫重于君臣兮，而讒言以興。", "余服蘭而佩芷兮，扈江蘺與蕙茝。", "紉留夷而緯楬車兮，以爲束带。", "青雲冠兮遠遊履，心曠漭兮橫四海。", "日月昭其清明兮，孰興雲霧。", "余既有此高潔兮，羌謂余爲卑污。", "鳳皇翔于九霄兮，燕雀與程其度。", "蒼蠅矢之亂白墨兮，人夫何爲乎不悟。", "於穆靈脩之高厚兮，天與地其作配。", "三辰煥其服章兮，揭招摇而爲蓋。", "拂白螭之純素兮，列蒼龍于左輔。", "朱鳥熒煌而先後兮，神龜昌揚而禦侮。", "東南海而西界羌兮，商於崇其北戶。", "愉昭明而震起兮，諶發揮于天下。", "余日望其遵此途兮，放意咸池。", "乘王虯兮俱奮飛，開閶門兮造東父，逍遥遊兮太微。", "何鴟鴞兮名鳳皇，駕金車兮翱翔。", "之桑間兮溱洧之側，樂盤遊兮三旬不息。", "余心隠憂兮，惟靈脩之故也。"]'),
('ca5ca1db-0266-48c9-84b7-20016b565d55','九奮 怨春風','薛季宣','宋','宋诗','song-poetry','','[]','怨春風之不仁兮，既發我羣芳與衆葩。',384,'全唐诗/poet.song.155000.json','["怨春風之不仁兮，既發我羣芳與衆葩。", "羌無遠而不屆兮，爛錦綺之紛華。", "柳青青兮花漫漫，黄鸝擲兮聲度轉。", "香襲衣兮馡馡滿路，又吹殘兮何故。", "匪黔嬴之媢嫉兮，是殘醜類。", "摧傷物之通美兮，且以成其獨異。", "彼丹葩兮適榮樹端，今飄零兮匝地漫漫。", "昔芬馨兮襲人旖旎，今質存兮已魄然而少氣。", "野之草兮，昔芽萌其嫩綠。", "今生砌兮，亦盤盤而錯錯。", "余啟卜于靈氛兮，問其何故。", "靈氛視余以其繇兮，曰皇之常度。", "在天地萬物其盡然兮，夫子何疑。", "暢其理而誠告兮，子其知之。", "曰人生百年猶樹花兮，三春發榮粲其葩兮。", "光彩馨香能幾何兮，壹昔飄風竟辭柯兮。", "彼隨飆兮展轉，或歸根兮或遠。", "或一墜于庭闈兮，或遂沈于坑圊。", "風何知而花何有兮，子之心焉眷眷。", "嗟世態之汩于是非兮，孰通其說。", "西施見斥兮嫫母爲說，毀棄尺璧兮鼠璞見珍，明月沈埋兮魚目爲蠙。", "美自美而惡自惡兮，贋與真其誰分。", "春與秋其代謝兮，子何與而傷春。", "餘不得此之高意兮，懷達人之至言。"]'),
('a0d3f563-f927-4452-ba14-cfdff8c3ba10','九奮 去郢','薛季宣','宋','宋诗','song-poetry','','[]','桂枻兮蘭舟，去景兮悠悠。',291,'全唐诗/poet.song.155000.json','["桂枻兮蘭舟，去景兮悠悠。", "維赤岸兮裴回，睠丹陽兮夷猶。", "中腸鬰結兮神情惝怳，思夫君兮聊淹留。", "浮涔江兮放于沱漢，泛淪漪兮極其汗漫。", "悵始異而終同兮匪它，回波瀾兮顧復之豈遠。", "婉清揚兮採蓮女，要美人兮北渚。", "㨫芳蘅與若英兮備雜菜之芬馨，將日昃之與期兮指潛波而爲盟。", "羲和晻曀其西入兮暮雲合而美人不見，怨芳心兮泣蘪蕪余以衍。", "秋風起兮飆飀蕭索，幽蘭秀兮芙蓉亂落。", "感北江之東注兮泝洄之宛宛，羌順天而不極兮蕩波之有沔。", "鳴鳩雨而逐婦兮言歸以霽，動人情兮弔孤影而零涕。", "去靈脩而自放兮余心不忍，回素首而不見其形兮于斯焉其逾逝。", "亂曰：冶余容兮安閑自喜，蓀窈窕而不我嘉兮何以。", "苟承恩之不在貌兮蒼天謂何，分此生兮已矣。"]'),
('f57c74ef-0313-4a87-85d5-fe00a2c836c7','九奮 東首','薛季宣','宋','宋诗','song-poetry','','[]','愁城結余之方寸兮，羅累千之雉堞。',376,'全唐诗/poet.song.155000.json','["愁城結余之方寸兮，羅累千之雉堞。", "繚其外惟怨水兮，如褰裳之不可涉。", "揖輸般俾攻以械兮，訴余曰罔克。", "礪利刃而斬其關兮，礙重門而莫得。", "登東丘而延佇兮，見滄溟之滉瀁。", "深湛漫兮，受百川之漭漭。", "朝與夕有汐潮兮，冉冉來而西漲。", "江河之波倒流而西傾兮，泝崇丘而以上。", "欻忽洄流兮已往，來孰使之然兮去誰與讓。", "曰夏后之勤勞兮，導川流之歸王。", "執玉帛而朝萬邦兮，淩會稽而會計。", "穆百神之受其職兮，罔或不至。", "瑣防風氏之恃修軀兮，朝宗敢後。", "缺我析兮破齊斧，骨專車兮以徇于天下。", "于越守東藩而奉其祀兮，盛侵淫于中世。", "句踐王兮始大，北爭衡兮吳會。", "棲會稽而幾不免其身兮，惟種蠡之與謀。", "朝嘗膽以苦身兮，將反之于寇讎。", "吳夫差之不仁兮，忍闔廬之餘恨。", "甘蟲蠹心兮，尚不靦乎其面。", "說妖女而築姑蘇兮，咈胥臣之悶悶。", "乘鴟夷而蹈斤溝兮，不及夫椒之親見。", "麋鹿遊于吳宮兮，火災興于探燕。", "羌伯越于中原兮，通舟梁于梁宋。"]'),
('18cd7a59-b69b-4a75-821f-3d20d946d587','九奮 遡江','薛季宣','宋','宋诗','song-poetry','','[]','越夏首兮西泝，張青蒲兮疾去。',328,'全唐诗/poet.song.155000.json','["越夏首兮西泝，張青蒲兮疾去。", "鷁吻低徊兮翱翔風便，回首東冥兮日遠。", "睇蘭洲兮芳杜若，羌吾好兮不得泊。", "聞持鼓兮𩐨𩐨，余心結兮尚何樂。", "西風駛兮江皋，舟迎風兮遡流。", "進將寸兮退尺，凝遠眺兮江水幽幽。", "江風號兮漫天素濤，走魦逼人兮將吞舟。", "余奈何兮倏忽，下有蛟龍兮出沒。", "江豚得意兮若神，肆跳梁兮衝突。", "泊兮恍，烏雲潑墨兮吾上。", "天地變兮不可測，渠泉飛兮無峭壁。", "儃徊余桂棹兮，蘋叢至止。", "曳方竹而相羊兮，㨫芝中沚。", "蘇椒紅兮和羹，搴辛夷兮用餌。", "雜薦兮蓀蘭，載敶兮薜芷。", "風細細兮波停，縱余舸兮于征。", "長歌自放，顧一返兮屏營。", "倡曰：扁舟大江，遡狂風兮。", "下地登天，轉飄蓬兮。", "人之死生，將彼舸之攸同兮。", "停橈待濟，考攸終兮。", "賡曰：逆天理兮，雖大而覆。", "順其然兮，百福攸助。", "叛水性而余求兮，噫其何故。"]'),
('b4cee23c-93dd-4831-882b-2bf58c3e4040','九奮 賦巴丘','薛季宣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','巴丘兮崢嶸，嶔岑兮洞庭。',380,'全唐诗/poet.song.155000.json','["巴丘兮崢嶸，嶔岑兮洞庭。", "秋霖兮閣淚，春草兮愁生。", "巴之蛇兮修之，雲英甲兮火晶。", "戟微手足兮惟行，雲霧飛騰兮匪翼。", "知絀信兮天性，展轉委蛇兮至行。", "朝之遊兮衡岳，莫飯流兮湘曲。", "鹿焱起兮中洲，人之逐兮悠悠。", "紛繚亂兮海波弗靜，逐之顛者相望兮莫得持其腰領。", "鹿冠元兮森槎千角，蛇銜取兮不畏觸。", "歲三遷而解甲兮骼髏具吐，羌有獲兮故無取。", "象巨牙之雙植兮，肥腯頑健。", "肉雞兔虎龍而牛幹兮，得鼠狶爲首面。", "性羊狠而馬行兮，狗猴心而蛇變。", "既備此十二神象兮，害于田其不遠。", "蜿蜒蛇之怒兮，吸無勞乎宛轉。", "雖有此修鼻駢齒兮，寧復餐而以卷。", "不勞咀此齒牙兮，害以蛇除。", "珠顯灼而光明兮，不在短狐之毀譽。", "遊蘭若兮芳洲，卧香蒲兮翔素流。", "芷岡兮戲豫，丹穴兮優游。", "何蜂蟲之陰戾瑣微兮藏形于闇，騎蛇頭而啜之兮墮厥頤而脫頷。", "阜堆骨兮名陵，風悲雨泣兮千齡萬齡。", "象種繁兮蛇既斃，欲吞之兮誰能舍。", "鹿奔兮其復獲，登蛇丘兮涕零零。"]'),
('ec8fe5e5-a627-481f-ba6b-ee62616a22c7','九奮 記夢','薛季宣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','解荃維兮放蘭舸，蹇南越兮洞庭波。',312,'全唐诗/poet.song.155000.json','["解荃維兮放蘭舸，蹇南越兮洞庭波。", "噴浪花兮飛白雪，身何居兮入明月。", "聊凝神兮隠處，夢龍宮兮波之下。", "珍珠庭兮紫貝闕，璆琳宮兮犀甲戶。", "朝龍君兮殿堂，芰荷巾兮蘋藻裳。", "圭琉璃兮荇带，佩美玉兮琅璫。", "龍君遊兮何之，水晶宮兮丹水湄。", "驂蒼虯兮飛廉御，豐隆車兮爲後屬。", "磣磹驅駝其左右兮使風伯爲清路，都離宮兮忘反。", "命羣臣兮燕衎，葅蘩藴兮形鹽。", "列鯨胎兮黿卵，張鈞天兮廣漠野。", "鼓蛇鼖兮雷鼉鼓，鏗浮磬兮□龍鍾。", "歌湘靈兮奇相，舞三行兮清酤。", "戛止兮柷敔，觀其臣之就位兮厥令尹曰瞋。", "鮭總羣蝦而將之兮，胄乃元惟鮑魚。", "緣蛙聲之聒聒兮，位高于五諫。", "鱣魚大而無庸兮，處之冗散。", "鬰鬰余心之惛默兮，周章而蹇産。", "欲敶詞而夢覺兮，嗟言之而已晚。", "怱怱余見斯情物兮，徒臨流而惋歎。"]'),
('e657e9f4-d867-4135-a508-48e132d6616f','九奮 行吟','薛季宣','宋','宋诗','song-poetry','','[]','行吟兮大澤，邈無人兮臨水石。',308,'全唐诗/poet.song.155000.json','["行吟兮大澤，邈無人兮臨水石。", "被髮兮徙倚彷徨，遇隠淪兮嘉客。", "艤漁舟而前致恭兮，問余以名何。", "徒摇爾精兮，燋然爾形。", "曰原楚卿之貴戚兮，三閭次也。", "同王姓而氏惟屈兮，靈均先人之字也。", "世滔淫而混濁兮，我惟潔清。", "彼醉者之紛拏兮，同怒余之獨醒。", "漁父愀然而教之兮，曰聖人之致一。", "不必動而營皇兮，卓時中之變物。", "貴莫貴于和光兮，太潔在情之甚嫉。", "混濁世兮胡不揚波而泥淈，衆皆醉兮尚可餔糟而醨歠。", "不同人而求自異兮，宜一朝之見絀。", "指清流之灝灝兮，余將以逝。", "方浴茝而沐芳兮，振衣冠而卒歲。", "不自塵其皓皓兮，受汶汶而蒙世。", "父行歌而鼓枻兮，舟飄飄然無凝滯。", "歌滄浪之水兮時乎清濁，斯濯纓兮斯濯足。", "望斯人兮摇摇，欲從之兮無由。", "煙雲邈兮不可見，嗟斯人兮已遠。"]'),
('e07cdc0b-cbdf-482b-b6bd-68910a2a7a6c','九奮 沈湘','薛季宣','宋','宋诗','song-poetry','','["\u8861\u5c71"]','觀吾生兮何爲乎今之世，永悲傷兮耿耿夜長而鮮寐。',325,'全唐诗/poet.song.155000.json','["觀吾生兮何爲乎今之世，永悲傷兮耿耿夜長而鮮寐。", "臨清湘兮思逝無舟，倀欲行兮不濟。", "擬飛騰兮假羽翰于黄鵠，鵠已亡兮曾是余之能服。", "將解衣而下遊兮潛川不貫，懼射工之余中兮備蛟龍之芻豢。", "登衡山之嵯峨兮柏松委靡，怨飄風之怒狂兮害于物理。", "猨狖嘯侶兮上獲我冠，荆榛塞路兮下穿我履。", "望蒼梧兮將重華之云愬，巉九疑之不可辯兮又藐然其煙霧。", "殺竹枝而求淚班兮思二妃之榘度，哀靈脩之返無期兮蓀舍茲將安寓。", "首陽河瀆遠而不可適兮，視申子夷齊其有故。", "將從此汨羅之水兮，儻務成之或遇。", "悲女嬃之嬋媛兮，臨流而止余。", "涕滂沱兮，心悲江渚。", "念我獨兮，斯不可以久處。", "心如石而莫轉兮，吾其此介。", "與子別兮余將于邁，褰余衣兮不我止，蹈清泠兮余乃已。", "抱巨石兮懷沙，諶同流兮灝波。", "其窮幽兮眇眇，皇合德兮太皓。"]'),
('e2099ede-cee2-4d02-9d8d-6c768d59be4d','九禽言  其一','薛季宣','宋','宋诗','song-poetry','','[]','不如歸去，巴江春暮。',52,'全唐诗/poet.song.155000.json','["不如歸去，巴江春暮。", "腸斷口無聲，早夜啼紅雨。", "尋思帝蜀時，驪龍魚服不知非。", "相婦未饒姬妾貌，流紅長恨不如歸。"]'),
('99dffcc0-48e6-404d-ae7c-e183517e46b0','九禽言  其二','薛季宣','宋','宋诗','song-poetry','','[]','婆餠焦，胡不歸，熾炭炎炎不識兒。',44,'全唐诗/poet.song.155000.json','["婆餠焦，胡不歸，熾炭炎炎不識兒。", "兒饑不敢取，兒苦長自啼。", "父母生兒忍不字，棄兒父母生何爲。"]'),
('6b8b4e5f-4c7b-41b0-af57-0ed570e1464a','九禽言  其三','薛季宣','宋','宋诗','song-poetry','','[]','脫脚布袴，從教暴露。',54,'全唐诗/poet.song.155000.json','["脫脚布袴，從教暴露。", "已自不能羞，有甚供租賦。", "官家官家聽我語，我本農家困徵取。", "祇今爲鳥心不忘，願王一念農家苦。"]'),
('c0f44ef6-deae-4184-8d05-51c53f1c8d39','九禽言  其四','薛季宣','宋','宋诗','song-poetry','','[]','蠶姑力作，繰絲一百箔。',71,'全唐诗/poet.song.155000.json','["蠶姑力作，繰絲一百箔。", "五月罷蠶繅，炎天勤織絡。", "今年州府急催科，輕綃織成不得著。", "蔽體無褌獨蠶婦，百箔絲蠶枉辛苦。", "貴人不念有寒人，一曲千縑賜倡女。"]'),
('fe0da630-84de-46e3-b3e3-2b0a4423328f','九禽言  其五','薛季宣','宋','宋诗','song-poetry','','[]','新婦抱兒歸，天清曜日暉。',110,'全唐诗/poet.song.155000.json','["新婦抱兒歸，天清曜日暉。", "陰雲凝霧雨，新婦抱兒去。", "窶窶勃姑鳥，此情那可曉。", "有兒有婦不作窠，教去教歸幾時了。", "謝豹謝豹獨何心，挈我裳衣無處尋。", "白露漙兮風勁，紅葉下兮秋深。", "我寒終不辭，皇天故不私。", "請看穴土重泉下，對人靦面何爲者。"]'),
('d9cafc45-0207-47c3-97df-06636ef99449','九禽言  其六','薛季宣','宋','宋诗','song-poetry','','[]','泥滑滑，山岡路。',64,'全唐诗/poet.song.155000.json','["泥滑滑，山岡路。", "一步一躊躇，行前復回顧。", "如膏兮小雨，膠膠兮薄土。", "失足無多來往人，撲落洪崖不堪數。", "戰兢驅馿行不前，苦是昏黄無逆旅。"]'),
('2c846652-8940-4cbd-a25c-49db8cc80cc5','九禽言  其七','薛季宣','宋','宋诗','song-poetry','','[]','行不得也哥哥，途遠山高奈何。',58,'全唐诗/poet.song.155000.json','["行不得也哥哥，途遠山高奈何。", "畏日流金兮長夏，蔭人有樾兮無柯。", "足繭兮撐獰，口渴兮煙生。", "思量有底虧人處，不處高堂長路行。"]'),
('dad6e229-2d54-4bc1-8e5a-ad1908f6b6aa','九禽言  其八','薛季宣','宋','宋诗','song-poetry','','[]','提葫蘆，沽美酒。',44,'全唐诗/poet.song.155000.json','["提葫蘆，沽美酒。", "舞春風，卧花柳。", "且作醉鄉遊，此身非我有。", "與君看取壠頭墳，人在誰知不長久。"]'),
('5471a109-efc6-433d-a645-70f8c9f2ef00','挽薛艮齋','薛季宣','宋','宋诗','song-poetry','','[]','眼看嘉木斧斤摧，竹路凄凉孰不哀。',64,'全唐诗/poet.song.155000.json','["眼看嘉木斧斤摧，竹路凄凉孰不哀。", "高論每聞前席聽，讜言曾欲挽裾回。", "膏銷果見龔生夭，芻奠空悲徐孺來。", "儒效俗傳今若此，蒼蒼福善竟悠哉。"]'),
('f1e2d10d-95f2-4f9e-99e7-8351d47c3c31','句','樓錫','宋','宋诗','song-poetry','','[]','但愛窗間冬日暖，不知門外北風涼。',16,'全唐诗/poet.song.155000.json','["但愛窗間冬日暖，不知門外北風涼。"]'),
('5b22b003-8b66-4930-a776-3a7a9bc86db2','和朱晦菴','劉清之','宋','宋诗','song-poetry','','[]','誰云兩州牧，擇笏望轅門。',24,'全唐诗/poet.song.155000.json','["誰云兩州牧，擇笏望轅門。", "渠亦髭鬚好，公今德義尊。"]'),
('6e1d5382-df68-42b6-854f-f97b2b49d449','洞霄宮','劉清之','宋','宋诗','song-poetry','','[]','青山鎖斷紅塵路，石柱干霄藏洞府。',64,'全唐诗/poet.song.155000.json','["青山鎖斷紅塵路，石柱干霄藏洞府。", "老蛟據窟不可窺，千古流泉替渠舞。", "真墟容我輒躋攀，心曠方知白日閒。", "飛仙一去忽已遠，坐對松梢雲往還。"]'),
('f46b9480-7296-4d07-82b1-c0f4d4b4ca10','遊洪陽洞  其一','劉清之','宋','宋诗','song-poetry','','[]','朝來拔脚塵埃底，共訪人間小有天。',32,'全唐诗/poet.song.155000.json','["朝來拔脚塵埃底，共訪人間小有天。", "喚醒幾年朱墨夢，胸中丘壑故依然。"]'),
('9dc898b6-aeac-4c8c-80ed-664be9044633','遊洪陽洞  其二','劉清之','宋','宋诗','song-poetry','','[]','稚川仙去憶浮丘，携客巖前問舊遊。',32,'全唐诗/poet.song.155000.json','["稚川仙去憶浮丘，携客巖前問舊遊。", "懷古臨風一杯酒，荻花楓葉不勝秋。"]'),
('f969db56-1457-4d65-a0e3-20e4dafa1112','洞庭湖','劉清之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','天孫歲晚會湘靈，倒瀉銀河合洞庭。',64,'全唐诗/poet.song.155000.json','["天孫歲晚會湘靈，倒瀉銀河合洞庭。", "上下天光唯一白，中間山色不多青。", "荆潭萬里收塵滓，宇宙連宵失晦明。", "莫道人間少仙境，詩魂酒魄一時醒。"]'),
('a4b1dbba-995e-4c52-a434-7b929a70d488','句','劉清之','宋','宋诗','song-poetry','','[]','愁非爲宋玉，亦不因莫愁。',12,'全唐诗/poet.song.155000.json','["愁非爲宋玉，亦不因莫愁。"]'),
('9dc77bb7-3baa-486a-bc44-7a8462922d77','古梅','俞亨宗','宋','宋诗','song-poetry','','[]','疏疏瘦蕊含清馥，矯矯虬枝綴碧苔。',32,'全唐诗/poet.song.155000.json','["疏疏瘦蕊含清馥，矯矯虬枝綴碧苔。", "疑是髯龍離雪殿，蒼鱗遥駕玉妃來。"]'),
('ccbcb43e-f909-4d5f-99fa-da59ccb4128c','送王龜齡','何佾','宋','宋诗','song-poetry','','[]','斷橋截鐙亦堪憐，始信林間別有天。',32,'全唐诗/poet.song.155000.json','["斷橋截鐙亦堪憐，始信林間別有天。", "微見兵機第一義，朱轓暫席廣文氈。"]'),
('7f6fb7c3-b6e7-4378-a3e4-16aafebb40a4','句','何佾','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','滕王閣上煙波遠，孺子亭中花竹深。',16,'全唐诗/poet.song.155000.json','["滕王閣上煙波遠，孺子亭中花竹深。"]');
